def ensure_dir(path: Path) -> Path:
    path.mkdir(parents=True, exist_ok=True)
    return path


def read_json(path: Path) -> Any:
    with path.open("r", encoding="utf-8") as f:
        return json.load(f)


def write_json(path: Path, value: Any) -> None:
    ensure_dir(path.parent)
    with path.open("w", encoding="utf-8") as f:
        json.dump(value, f, indent=2, ensure_ascii=False)
        f.write("\n")


def slugify(value: str, fallback: str = "object") -> str:
    slug = re.sub(r"[^a-zA-Z0-9._-]+", "-", str(value).strip().lower())
    slug = slug.strip("-._")
    return (slug or fallback)[:80]


def frame_stem(frame_id: str | int) -> str:
    text = str(frame_id)
    return f"{int(text):06d}" if text.isdigit() else text


def project_manifest_path(project_root: Path) -> Path:
    return project_root / "manifest.json"


def load_manifest(project_root: Path) -> dict[str, Any]:
    path = project_manifest_path(project_root)
    if not path.exists():
        raise FileNotFoundError(f"Project manifest not found: {path}")
    return read_json(path)


def save_manifest(project_root: Path, manifest: dict[str, Any]) -> None:
    write_json(project_manifest_path(project_root), manifest)


def rel_or_abs(path: Path, base: Path) -> str:
    try:
        return str(path.resolve().relative_to(base.resolve()))
    except ValueError:
        return str(path.resolve())


def resolve_project_cli_path(path: Path, project_root: Path) -> Path:
    if path.is_absolute():
        return path.resolve()
    cwd_candidate = path.resolve()
    if path.exists() or path.parent.exists():
        return cwd_candidate
    project_text = str(project_root)
    path_text = str(path)
    if path_text == project_text or path_text.startswith(project_text.rstrip("/") + "/"):
        return cwd_candidate
    return (project_root / path).resolve()


def resolve_project_relative_path(path: Path, project_root: Path) -> Path:
    if path.is_absolute():
        return path.resolve()
    return (project_root / path).resolve()


def resolve_export_record_path(value: str | Path, project_root: Path | None = None) -> Path:
    path = Path(value)
    if path.exists():
        return path
    if project_root is not None:
        project_root = project_root.resolve()
        if not path.is_absolute():
            candidate = project_root / path
            if candidate.exists():
                return candidate
        parts = path.parts
        for index, part in enumerate(parts):
            if part == project_root.name:
                candidate = project_root.joinpath(*parts[index + 1 :])
                if candidate.exists():
                    return candidate
        if "exports" in parts:
            index = parts.index("exports")
            if index + 2 < len(parts) and parts[index + 1] == project_root.name:
                candidate = project_root.joinpath(*parts[index + 2 :])
                if candidate.exists():
                    return candidate
    return path


def resolve_active_mask_root(project_root: Path, manifest: dict[str, Any]) -> Path:
    artifacts = manifest.get("artifacts", {}) if isinstance(manifest.get("artifacts"), dict) else {}
    active = resolve_existing_path(artifacts.get("object_masks_2d"), project_root)
    if active and active.exists():
        return active
    return project_root / manifest["masks"]["mask_2d_dir"]


def copy_or_link(src: Path, dst: Path, mode: str = "copy") -> Path:
    ensure_dir(dst.parent)
    if src.resolve() == dst.resolve():
        return dst
    if dst.exists() or dst.is_symlink():
        dst.unlink()
    if mode == "symlink":
        dst.symlink_to(src.resolve())
    elif mode == "copy":
        shutil.copy2(src, dst)
    else:
        raise ValueError("--mode must be copy or symlink")
    return dst


def import_numpy():
    try:
        import numpy as np  # type: ignore
    except Exception as exc:  # pragma: no cover - depends on environment
        raise RuntimeError("This command requires numpy.") from exc
    return np


def import_cv2():
    try:
        import cv2  # type: ignore
    except Exception as exc:  # pragma: no cover - depends on environment
        raise RuntimeError("This command requires opencv-python (cv2).") from exc
    return cv2


def import_pil_image():
    try:
        from PIL import Image  # type: ignore
    except Exception as exc:  # pragma: no cover - depends on environment
        raise RuntimeError("This command requires Pillow.") from exc
    return Image


def safe_cv2_imwrite(path: Path | str, image: Any, params: list[int] | tuple[int, ...] | None = None) -> bool:
    path = Path(path)
    try:
        cv2 = import_cv2()
        ok = cv2.imwrite(str(path), image, list(params or []))
        if ok:
            return True
    except Exception:
        pass
    try:
        np = import_numpy()
        Image = import_pil_image()
        array = np.asarray(image)
        if array.ndim == 2:
            pil_image = Image.fromarray(array.astype("uint8"), mode="L")
        elif array.ndim == 3 and array.shape[2] == 3:
            pil_image = Image.fromarray(array[:, :, ::-1].astype("uint8"), mode="RGB")
        elif array.ndim == 3 and array.shape[2] == 4:
            pil_image = Image.fromarray(array[:, :, [2, 1, 0, 3]].astype("uint8"), mode="RGBA")
        else:
            raise ValueError(f"Unsupported image shape for fallback write: {array.shape}")
        ensure_dir(path.parent)
        pil_image.save(path)
        return True
    except Exception as exc:
        raise RuntimeError(f"Failed to write image {path}: {exc}") from exc


def init_project(project_root: Path, scene_id: str, video: Path | None = None) -> dict[str, Any]:
    project_root = project_root.resolve()
    scene_id = slugify(scene_id, fallback="scene")
    for subdir in [
        "scene/frames",
        "scene/cameras",
        "scene/reconstruction",
        "masks/2d",
        "masks/3d",
        "objects",
        "simulator_assets",
        "logs",
    ]:
        ensure_dir(project_root / subdir)

    manifest = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "scene_id": scene_id,
        "project_root": str(project_root),
        "inputs": {},
        "scene": {
            "frames_dir": "scene/frames",
            "camera_info": "scene/cameras/camera_info.json",
            "point_cloud": "scene/reconstruction/point_cloud.ply",
            "scene_3dgs": "scene/reconstruction/3dgs",
        },
        "masks": {
            "mask_2d_dir": "masks/2d",
            "mask_3d_dir": "masks/3d",
        },
        "objects_dir": "objects",
        "simulator_assets_dir": "simulator_assets",
        "external_stages": {
            "video_to_3dgs": {
                "status": "not_configured",
                "notes": "Plug in COLMAP/Gaussian Splatting/MASt3R-SLAM here.",
            },
            "segmentation_2d_tracking": {
                "status": "not_configured",
                "notes": "Plug in SAM/DEVA/XMem/Grounded-SAM style masks here.",
            },
            "mesh_generation": {
                "status": "prepared_for_image_blaster",
                "notes": "Use export-image-blaster and mesh-commands.",
            },
        },
        "artifacts": {},
    }
    if video is not None:
        manifest["inputs"]["video"] = str(video.resolve())
    save_manifest(project_root, manifest)
    return manifest


def cmd_init(args: argparse.Namespace) -> int:
    manifest = init_project(args.project_root, args.scene_id, args.video)
    print(json.dumps(manifest, indent=2, ensure_ascii=False))
    return 0


