def high_quality_3dgs_job_summary_from_job(path: Path | None) -> dict[str, Any]:
    job = safe_read_json(path) if path and path.exists() else None
    if not isinstance(job, dict):
        return {
            "job": str(path) if path else "",
            "job_exists": bool(path and path.exists()),
            "input_contract": {},
            "quality_targets": {},
            "acceptance_criteria_count": 0,
            "post_import_validation_count": 0,
        }
    input_contract = job.get("input_contract") if isinstance(job.get("input_contract"), dict) else {}
    quality_targets = job.get("quality_targets") if isinstance(job.get("quality_targets"), dict) else {}
    preview_thresholds = quality_targets.get("preview_thresholds") if isinstance(quality_targets.get("preview_thresholds"), dict) else {}
    environment_contract = job.get("environment_contract") if isinstance(job.get("environment_contract"), dict) else {}
    trainer_backends = job.get("trainer_backends") if isinstance(job.get("trainer_backends"), dict) else {}
    execution_plan = job.get("execution_plan") if isinstance(job.get("execution_plan"), list) else []
    handoff = job.get("handoff") if isinstance(job.get("handoff"), dict) else {}
    run_script = resolve_existing_path(handoff.get("run_script"), Path(str(job.get("project_root") or "."))) if handoff.get("run_script") else None
    return {
        "job": str(path) if path else "",
        "job_exists": True,
        "provider": job.get("provider"),
        "source_path": job.get("source_path"),
        "output_path": job.get("output_path"),
        "canonical_scene_vertex_count": input_contract.get("canonical_scene_vertex_count"),
        "downsampled_work_vertex_count": input_contract.get("downsampled_work_vertex_count"),
        "colmap_points3d_point_count": input_contract.get("colmap_points3d_point_count"),
        "colmap_matches_canonical_point_count": input_contract.get("colmap_matches_canonical_point_count"),
        "colmap_matches_downsampled_point_count": input_contract.get("colmap_matches_downsampled_point_count"),
        "use_full_point_cloud_required": input_contract.get("use_full_point_cloud_required"),
        "downsampled_point_cloud_allowed_for_training_init": input_contract.get("downsampled_point_cloud_allowed_for_training_init"),
        "frame_source": input_contract.get("frame_source") if isinstance(input_contract.get("frame_source"), dict) else {},
        "quality_targets": {
            "preview_thresholds": preview_thresholds,
            "expected_trainer_features": quality_targets.get("expected_trainer_features") or [],
            "replaces": quality_targets.get("replaces"),
        },
        "environment_contract": environment_contract,
        "trainer_backend_count": len(trainer_backends),
        "trainer_backends": sorted(trainer_backends.keys()),
        "has_graphdeco_backend": "graphdeco" in trainer_backends,
        "has_nerfstudio_backend": "nerfstudio_splatfacto" in trainer_backends,
        "has_full_gsplat_backend": "full_gsplat" in trainer_backends,
        "execution_plan_count": len(execution_plan),
        "run_script": str(run_script) if run_script else handoff.get("run_script", ""),
        "run_script_exists": bool(run_script and run_script.exists()),
        "required_outputs_count": len(job.get("required_outputs") if isinstance(job.get("required_outputs"), dict) else {}),
        "acceptance_criteria_count": len(job.get("acceptance_criteria") if isinstance(job.get("acceptance_criteria"), list) else []),
        "post_import_validation_count": len(job.get("post_import_validation") if isinstance(job.get("post_import_validation"), dict) else {}),
    }


def sceneversepp_job_summary_from_job(path: Path | None) -> dict[str, Any]:
    job = safe_read_json(path) if path and path.exists() else None
    if not isinstance(job, dict):
        return {
            "job": str(path) if path else "",
            "job_exists": bool(path and path.exists()),
            "svpp_instance_count": 0,
            "metadata_instance_count": 0,
            "commands_count": 0,
            "script_count": 0,
            "scripts_existing": 0,
            "scripts_executable": 0,
            "acceptance_criteria_count": 0,
            "post_execution_validation_count": 0,
        }

    project_root = Path(str(job.get("project_root") or (path.parent if path else "."))).resolve()

    def resolve_job_path(value: Any) -> Path | None:
        if not value:
            return None
        return resolve_project_cli_path(Path(str(value)), project_root)

    svpp_scene_dir = resolve_job_path(job.get("svpp_scene_dir"))
    svpp_export_path = resolve_job_path(job.get("svpp_export"))
    svpp_export = safe_read_json(svpp_export_path)
    if not isinstance(svpp_export, dict):
        svpp_export = {}
    files = svpp_export.get("files") if isinstance(svpp_export.get("files"), dict) else {}
    metadata_path = resolve_job_path(files.get("metadata")) or (svpp_scene_dir / "metadata.json" if svpp_scene_dir else None)
    camera_info_path = resolve_job_path(files.get("camera_info")) or (svpp_scene_dir / "camera_info.json" if svpp_scene_dir else None)
    data_info_path = resolve_job_path(files.get("data_info")) or (svpp_scene_dir / "data_info.json" if svpp_scene_dir else None)
    mesh_path = resolve_job_path(files.get("mesh")) or (svpp_scene_dir / "mesh.ply" if svpp_scene_dir else None)
    metadata = safe_read_json(metadata_path)
    metadata_entries = metadata if isinstance(metadata, dict) else {}
    instances = svpp_export.get("instances") if isinstance(svpp_export.get("instances"), list) else []

    spatiallm = job.get("spatiallm") if isinstance(job.get("spatiallm"), dict) else {}
    pq3d = job.get("pq3d") if isinstance(job.get("pq3d"), dict) else {}
    commands = job.get("commands") if isinstance(job.get("commands"), dict) else {}
    scripts = job.get("scripts") if isinstance(job.get("scripts"), dict) else {}
    dependency_status = job.get("dependency_status") if isinstance(job.get("dependency_status"), dict) else {}
    script_paths = {str(key): resolve_job_path(value) for key, value in scripts.items()}
    script_status = {
        key: {
            "path": str(value) if value else "",
            "exists": bool(value and value.exists()),
            "executable": bool(value and value.exists() and os.access(value, os.X_OK)),
        }
        for key, value in script_paths.items()
    }
    input_contract = job.get("input_contract") if isinstance(job.get("input_contract"), dict) else {}
    environment_contract = job.get("environment_contract") if isinstance(job.get("environment_contract"), dict) else {}
    execution_plan = job.get("execution_plan") if isinstance(job.get("execution_plan"), list) else []
    required_outputs = job.get("required_outputs") if isinstance(job.get("required_outputs"), dict) else {}
    post_execution_validation = job.get("post_execution_validation") if isinstance(job.get("post_execution_validation"), dict) else {}

    metadata_instance_count = len(metadata_entries)
    instances_with_point_ids = 0
    instances_with_pred_class_id = 0
    for value in metadata_entries.values():
        if not isinstance(value, dict):
            continue
        point_ids = value.get("point_ids")
        if isinstance(point_ids, list) and point_ids:
            instances_with_point_ids += 1
        if value.get("pred_class_id") is not None:
            instances_with_pred_class_id += 1

    return {
        "job": str(path) if path else "",
        "job_exists": True,
        "stage": job.get("stage"),
        "project_root": str(project_root),
        "scene_id": job.get("scene_id"),
        "sceneversepp_root": job.get("sceneversepp_root"),
        "sceneversepp_root_exists": bool(resolve_job_path(job.get("sceneversepp_root")) and resolve_job_path(job.get("sceneversepp_root")).exists()),
        "svpp_scene_dir": str(svpp_scene_dir) if svpp_scene_dir else "",
        "svpp_scene_dir_exists": bool(svpp_scene_dir and svpp_scene_dir.exists()),
        "svpp_export": str(svpp_export_path) if svpp_export_path else "",
        "svpp_export_exists": bool(svpp_export_path and svpp_export_path.exists()),
        "svpp_instance_count": len(instances),
        "metadata": str(metadata_path) if metadata_path else "",
        "metadata_exists": bool(metadata_path and metadata_path.exists()),
        "metadata_instance_count": metadata_instance_count,
        "instances_with_point_ids": instances_with_point_ids,
        "instances_with_pred_class_id": instances_with_pred_class_id,
        "mesh_exists": bool(mesh_path and mesh_path.exists()),
        "camera_info_exists": bool(camera_info_path and camera_info_path.exists()),
        "data_info_exists": bool(data_info_path and data_info_path.exists()),
        "spatiallm_supported_count": len(spatiallm.get("supported_instances") if isinstance(spatiallm.get("supported_instances"), list) else []),
        "spatiallm_skipped_count": len(spatiallm.get("skipped_instances") if isinstance(spatiallm.get("skipped_instances"), list) else []),
        "spatiallm_label_map_exists": bool(resolve_job_path(spatiallm.get("label_map")) and resolve_job_path(spatiallm.get("label_map")).exists()),
        "spatiallm_code_template_exists": bool(resolve_job_path(spatiallm.get("code_template")) and resolve_job_path(spatiallm.get("code_template")).exists()),
        "pq3d_config_exists": bool(resolve_job_path(pq3d.get("config")) and resolve_job_path(pq3d.get("config")).exists()),
        "pq3d_save_root": pq3d.get("save_root", ""),
        "pq3d_segmentator_exists": dependency_status.get("pq3d_segmentator_exists"),
        "pq3d_segmentator_executable": dependency_status.get("pq3d_segmentator_executable"),
        "commands": sorted(commands.keys()),
        "commands_count": len(commands),
        "script_status": script_status,
        "script_count": len(script_status),
        "scripts_existing": len([item for item in script_status.values() if item.get("exists")]),
        "scripts_executable": len([item for item in script_status.values() if item.get("executable")]),
        "dependency_status": dependency_status,
        "dependency_missing": sorted(str(key) for key, value in dependency_status.items() if not value),
        "input_contract": input_contract,
        "environment_contract": environment_contract,
        "execution_plan_count": len(execution_plan),
        "required_outputs_count": len(required_outputs),
        "acceptance_criteria_count": len(job.get("acceptance_criteria") if isinstance(job.get("acceptance_criteria"), list) else []),
        "post_execution_validation_count": len(post_execution_validation),
        "bridge_only": bool(job.get("bridge_only", True)),
        "training_or_inference_executed": bool(job.get("training_or_inference_executed", False)),
    }


def cmd_prepare_high_quality_3dgs_job(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    provider = args.provider
    stage_root = ensure_dir(args.work_dir.resolve() if args.work_dir else project_root / "external" / "high_quality_3dgs")
    source_path = args.source_path.resolve() if args.source_path else stage_root / "colmap_source"
    output_path = args.output_path.resolve() if args.output_path else project_root / "scene" / "reconstruction" / f"3dgs_{slugify(provider)}"
    log_path = project_root / "logs" / f"{slugify(provider)}_3dgs_train.log"
    ensure_dir(log_path.parent)
    args.default_point_cloud = resolve_project_path(manifest["scene"]["point_cloud"], project_root)
    manifest, source_report = prepare_3dgs_colmap_source(project_root, manifest, args, source_path)
    sparse_filter_report = apply_3dgs_sparse_filter(source_path, args)

    command_template = args.command_template or default_3dgs_command_template(provider)
    values = {
        "provider": provider,
        "source_path": str(source_path),
        "output_path": str(output_path),
        "project_root": str(project_root),
        "work_dir": str(stage_root),
        "scene_id": str(manifest.get("scene_id", project_root.name)),
        "log_path": str(log_path),
    }
    command = command_from_template(command_template, values)
    job_spec = high_quality_3dgs_job_spec(
        project_root=project_root,
        manifest=manifest,
        provider=provider,
        source_path=source_path,
        output_path=output_path,
        work_dir=stage_root,
        log_path=log_path,
        sparse_filter_report=sparse_filter_report,
    )
    job = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "high_quality_3dgs_training",
        "provider": provider,
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "source_path": str(source_path),
        "output_path": str(output_path),
        "work_dir": str(stage_root),
        "log_path": str(log_path),
        "camera_model": args.camera_model,
        "command_template": command_template,
        "command": command,
        "source_report": source_report,
        "sparse_point_filter": sparse_filter_report,
        "expected_registration": {
            "command": f"python -m video2mesh.cli import-3dgs-result --project-root {project_root} --path {output_path} --provider {provider} --mode symlink",
            "notes": "After external training finishes, import/register the output and export point-cloud, SuperSplat, semantic, and QA artifacts where possible.",
        },
        **job_spec,
    }
    job_path = stage_root / "high_quality_3dgs_job.json"
    write_json(job_path, job)
    script_path = stage_root / "run_high_quality_3dgs.sh"
    write_high_quality_3dgs_runner(
        script_path,
        provider=provider,
        command=command,
        source_path=source_path,
        output_path=output_path,
        project_root=project_root,
        log_path=log_path,
    )

    manifest.setdefault("artifacts", {})["high_quality_3dgs_job"] = str(job_path)
    manifest.setdefault("external_stages", {})["video_to_3dgs"] = {
        "status": "high_quality_3dgs_job_prepared",
        "notes": "Prepared COLMAP-style source and external high-quality 3DGS trainer command; training not executed.",
        "provider": provider,
        "source_path": str(source_path),
        "output_path": str(output_path),
        "job": str(job_path),
        "script": str(script_path),
    }
    save_manifest(project_root, manifest)

    print(f"Prepared high-quality 3DGS job: {job_path}")
    print(f"Provider: {provider}")
    print(f"Source: {source_path}")
    print(f"Output: {output_path}")
    print(f"Script: {script_path}")
    return 0


def import_torch_and_gsplat():
    try:
        import torch  # type: ignore
        import gsplat  # type: ignore
    except Exception as exc:  # pragma: no cover - depends on environment
        raise RuntimeError("train-gsplat requires torch and gsplat.") from exc
    return torch, gsplat


def write_gsplat_ply(
    path: Path,
    means,
    colors,
    opacities,
    scales,
    quats,
) -> None:
    np = import_numpy()
    means_np = np.asarray(means, dtype=np.float32)
    colors_np = np.clip(np.asarray(colors, dtype=np.float32), 0.0, 1.0)
    opacities_np = np.asarray(opacities, dtype=np.float32).reshape(-1)
    scales_np = np.asarray(scales, dtype=np.float32)
    quats_np = np.asarray(quats, dtype=np.float32)
    ensure_dir(path.parent)
    with path.open("w", encoding="utf-8") as f:
        f.write("ply\n")
        f.write("format ascii 1.0\n")
        f.write(f"element vertex {means_np.shape[0]}\n")
        for name in ["x", "y", "z", "red", "green", "blue", "opacity", "scale_0", "scale_1", "scale_2", "rot_0", "rot_1", "rot_2", "rot_3"]:
            if name in {"red", "green", "blue"}:
                f.write(f"property uchar {name}\n")
            else:
                f.write(f"property float {name}\n")
        f.write("end_header\n")
        rgb = np.clip(np.rint(colors_np * 255.0), 0, 255).astype(np.uint8)
        for point, color, opacity, scale, quat in zip(means_np, rgb, opacities_np, scales_np, quats_np):
            values = [
                f"{float(point[0]):.8f}",
                f"{float(point[1]):.8f}",
                f"{float(point[2]):.8f}",
                str(int(color[0])),
                str(int(color[1])),
                str(int(color[2])),
                f"{float(opacity):.8f}",
                f"{float(scale[0]):.8f}",
                f"{float(scale[1]):.8f}",
                f"{float(scale[2]):.8f}",
                f"{float(quat[0]):.8f}",
                f"{float(quat[1]):.8f}",
                f"{float(quat[2]):.8f}",
                f"{float(quat[3]):.8f}",
            ]
            f.write(" ".join(values) + "\n")


def parse_ply_vertex_header(path: Path) -> dict[str, Any]:
    with path.open("rb") as f:
        header: list[str] = []
        ply_format = None
        vertex_count = None
        properties: list[tuple[str, str]] = []
        current_element = None
        for raw_line in f:
            line = raw_line.decode("ascii", errors="ignore").rstrip("\r\n")
            header.append(line)
            parts = line.strip().split()
            if not parts:
                continue
            if parts[0] == "format" and len(parts) >= 2:
                ply_format = parts[1]
            elif parts[0] == "element" and len(parts) >= 3:
                current_element = parts[1]
                if current_element == "vertex":
                    vertex_count = int(parts[2])
            elif parts[0] == "property" and current_element == "vertex":
                if len(parts) >= 5 and parts[1] == "list":
                    raise RuntimeError(f"Vertex list properties are not supported: {path}")
                if len(parts) >= 3:
                    properties.append((parts[2], parts[1]))
            elif parts[0] == "end_header":
                return {
                    "header": header,
                    "format": ply_format,
                    "vertex_count": vertex_count,
                    "properties": properties,
                    "data_offset": f.tell(),
                }
    raise RuntimeError(f"PLY file has no end_header: {path}")


def parse_ply_header(path: Path) -> dict[str, Any]:
    with path.open("rb") as f:
        header: list[str] = []
        ply_format = None
        elements: list[dict[str, Any]] = []
        current_element: dict[str, Any] | None = None
        for raw_line in f:
            line = raw_line.decode("ascii", errors="ignore").rstrip("\r\n")
            header.append(line)
            parts = line.strip().split()
            if not parts:
                continue
            if parts[0] == "format" and len(parts) >= 2:
                ply_format = parts[1]
            elif parts[0] == "element" and len(parts) >= 3:
                current_element = {"name": parts[1], "count": int(parts[2]), "properties": []}
                elements.append(current_element)
            elif parts[0] == "property" and current_element is not None:
                if len(parts) >= 5 and parts[1] == "list":
                    current_element["properties"].append(
                        {"name": parts[4], "kind": "list", "count_type": parts[2], "value_type": parts[3]}
                    )
                elif len(parts) >= 3:
                    current_element["properties"].append({"name": parts[2], "kind": "scalar", "type": parts[1]})
            elif parts[0] == "end_header":
                return {
                    "header": header,
                    "format": ply_format,
                    "elements": elements,
                    "data_offset": f.tell(),
                }
    raise RuntimeError(f"PLY file has no end_header: {path}")


def ply_struct_format(prop_type: str, byte_order: str) -> str:
    fmt = PLY_STRUCT_FORMATS.get(prop_type)
    if fmt is None:
        raise RuntimeError(f"Unsupported PLY property type {prop_type!r}.")
    return byte_order + fmt


def read_ply_triangle_mesh_light(path: Path) -> dict[str, Any]:
    np = import_numpy()
    header = parse_ply_header(path)
    ply_format = header["format"]
    elements = header["elements"]
    vertex_element = next((element for element in elements if element.get("name") == "vertex"), None)
    face_element = next((element for element in elements if element.get("name") == "face"), None)
    if vertex_element is None:
        raise RuntimeError(f"PLY mesh has no vertex element: {path}")
    if face_element is None:
        raise RuntimeError(f"PLY mesh has no face element: {path}")

    vertex_count = int(vertex_element["count"])
    face_count = int(face_element["count"])
    vertex_props = vertex_element["properties"]
    face_props = face_element["properties"]
    if any(prop.get("kind") != "scalar" for prop in vertex_props):
        raise RuntimeError(f"PLY vertex list properties are not supported: {path}")
    vertex_names = [str(prop["name"]) for prop in vertex_props]
    vertex_types = [str(prop["type"]) for prop in vertex_props]
    if not {"x", "y", "z"}.issubset(set(vertex_names)):
        raise RuntimeError(f"PLY mesh vertices must include x/y/z: {path}")

    if ply_format == "ascii":
        with path.open("rb") as f:
            f.seek(int(header["data_offset"]))
            vertex_rows: list[list[str]] = []
            for _ in range(vertex_count):
                raw_line = f.readline()
                if not raw_line:
                    raise RuntimeError(f"PLY ended before all vertices were read: {path}")
                row = raw_line.decode("ascii", errors="ignore").strip().split()
                if len(row) < len(vertex_props):
                    raise RuntimeError(f"PLY vertex row has too few values: {path}")
                vertex_rows.append(row)
            vertex_data: dict[str, Any] = {}
            for col, (name, prop_type) in enumerate(zip(vertex_names, vertex_types)):
                dtype = PLY_NUMPY_DTYPES.get(prop_type)
                if dtype is None:
                    raise RuntimeError(f"Unsupported PLY vertex property type {prop_type!r}: {path}")
                vertex_data[name] = np.asarray([row[col] for row in vertex_rows], dtype=np.dtype(dtype))

            faces: list[list[int]] = []
            for _ in range(face_count):
                raw_line = f.readline()
                if not raw_line:
                    raise RuntimeError(f"PLY ended before all faces were read: {path}")
                row = raw_line.decode("ascii", errors="ignore").strip().split()
                if not row:
                    continue
                first_consumed = False
                for prop in face_props:
                    if prop.get("kind") == "list":
                        count = int(row[0])
                        values = [int(value) for value in row[1 : 1 + count]]
                        if str(prop.get("name")) in {"vertex_indices", "vertex_index"} and not first_consumed:
                            faces.append(values)
                            first_consumed = True
                        break
                if not first_consumed:
                    raise RuntimeError(f"PLY face element has no vertex_indices list: {path}")
        return {"vertex_count": vertex_count, "face_count": face_count, "vertex_data": vertex_data, "faces": faces}

    if ply_format not in {"binary_little_endian", "binary_big_endian"}:
        raise RuntimeError(f"Unsupported PLY format {ply_format!r}: {path}")

    byte_order = "<" if ply_format == "binary_little_endian" else ">"
    dtype_fields = []
    for name, prop_type in zip(vertex_names, vertex_types):
        dtype_code = PLY_NUMPY_DTYPES.get(prop_type)
        if dtype_code is None:
            raise RuntimeError(f"Unsupported PLY vertex property type {prop_type!r}: {path}")
        dtype_fields.append((name, np.dtype(byte_order + dtype_code)))
    vertex_dtype = np.dtype(dtype_fields)
    vertex_data: dict[str, Any] = {}
    faces: list[list[int]] = []
    with path.open("rb") as f:
        f.seek(int(header["data_offset"]))
        table = np.fromfile(f, dtype=vertex_dtype, count=vertex_count)
        if table.shape[0] != vertex_count:
            raise RuntimeError(f"PLY ended before all binary vertex rows were read: {path}")
        vertex_data = {name: table[name] for name in vertex_names}

        for _ in range(face_count):
            face_indices: list[int] | None = None
            for prop in face_props:
                if prop.get("kind") == "scalar":
                    f.read(struct.calcsize(ply_struct_format(str(prop["type"]), byte_order)))
                    continue
                count_fmt = ply_struct_format(str(prop["count_type"]), byte_order)
                count_raw = f.read(struct.calcsize(count_fmt))
                if len(count_raw) != struct.calcsize(count_fmt):
                    raise RuntimeError(f"PLY ended while reading face list count: {path}")
                count = int(struct.unpack(count_fmt, count_raw)[0])
                value_fmt = ply_struct_format(str(prop["value_type"]), byte_order)
                value_size = struct.calcsize(value_fmt)
                raw_values = f.read(value_size * count)
                if len(raw_values) != value_size * count:
                    raise RuntimeError(f"PLY ended while reading face list values: {path}")
                values = [int(item[0]) for item in struct.iter_unpack(value_fmt, raw_values)]
                if str(prop.get("name")) in {"vertex_indices", "vertex_index"} and face_indices is None:
                    face_indices = values
            if face_indices is None:
                raise RuntimeError(f"PLY face element has no vertex_indices list: {path}")
            faces.append(face_indices)

    return {"vertex_count": vertex_count, "face_count": face_count, "vertex_data": vertex_data, "faces": faces}


def write_ascii_triangle_mesh_ply(
    path: Path,
    vertices,
    colors,
    faces: list[list[int]],
) -> None:
    np = import_numpy()
    vertices_np = np.asarray(vertices, dtype=np.float64)
    if vertices_np.ndim != 2 or vertices_np.shape[1] != 3:
        raise ValueError(f"vertices must be Nx3, got {vertices_np.shape}")
    if colors is None:
        colors_np = np.full((vertices_np.shape[0], 3), 192, dtype=np.uint8)
    else:
        colors_np = np.asarray(colors)
        if colors_np.shape != (vertices_np.shape[0], 3):
            raise ValueError(f"colors must be Nx3, got {colors_np.shape}")
        if colors_np.size and float(np.nanmax(colors_np)) <= 1.0:
            colors_np = np.rint(np.clip(colors_np, 0.0, 1.0) * 255.0)
        colors_np = np.clip(colors_np, 0, 255).astype(np.uint8)
    ensure_dir(path.parent)
    with path.open("w", encoding="utf-8") as f:
        f.write("ply\n")
        f.write("format ascii 1.0\n")
        f.write(f"element vertex {vertices_np.shape[0]}\n")
        f.write("property float x\n")
        f.write("property float y\n")
        f.write("property float z\n")
        f.write("property uchar red\n")
        f.write("property uchar green\n")
        f.write("property uchar blue\n")
        f.write(f"element face {len(faces)}\n")
        f.write("property list uchar int vertex_indices\n")
        f.write("end_header\n")
        for vertex, color in zip(vertices_np, colors_np):
            f.write(
                f"{float(vertex[0]):.8f} {float(vertex[1]):.8f} {float(vertex[2]):.8f} "
                f"{int(color[0])} {int(color[1])} {int(color[2])}\n"
            )
        for face in faces:
            f.write(f"{len(face)} {' '.join(str(int(index)) for index in face)}\n")


def extract_triangle_submesh_from_indices(
    mesh_data: dict[str, Any],
    point_indices: list[int],
    face_mode: str,
    max_faces: int = 0,
) -> dict[str, Any]:
    np = import_numpy()
    vertex_data = mesh_data["vertex_data"]
    faces = mesh_data["faces"]
    vertex_count = int(mesh_data["vertex_count"])
    selected = {int(index) for index in point_indices if 0 <= int(index) < vertex_count}
    if not selected:
        raise ValueError("No valid selected point indices.")
    if face_mode not in {"all", "any"}:
        raise ValueError("face_mode must be all or any")

    selected_faces_source: list[list[int]] = []
    for face in faces:
        if len(face) < 3:
            continue
        if face_mode == "all":
            keep = all(int(index) in selected for index in face)
        else:
            keep = any(int(index) in selected for index in face)
        if not keep:
            continue
        if len(face) == 3:
            selected_faces_source.append([int(face[0]), int(face[1]), int(face[2])])
        else:
            base = int(face[0])
            for tri_index in range(1, len(face) - 1):
                selected_faces_source.append([base, int(face[tri_index]), int(face[tri_index + 1])])
        if max_faces > 0 and len(selected_faces_source) >= max_faces:
            selected_faces_source = selected_faces_source[:max_faces]
            break

    if not selected_faces_source:
        raise ValueError("No mesh faces matched the selected point indices.")
    used_vertices = sorted({index for face in selected_faces_source for index in face})
    remap = {old_index: new_index for new_index, old_index in enumerate(used_vertices)}
    out_faces = [[remap[index] for index in face] for face in selected_faces_source]
    points = np.stack(
        [
            np.asarray(vertex_data["x"])[used_vertices],
            np.asarray(vertex_data["y"])[used_vertices],
            np.asarray(vertex_data["z"])[used_vertices],
        ],
        axis=1,
    ).astype(np.float64)
    names = set(vertex_data)
    if {"red", "green", "blue"}.issubset(names):
        colors = np.stack(
            [
                np.asarray(vertex_data["red"])[used_vertices],
                np.asarray(vertex_data["green"])[used_vertices],
                np.asarray(vertex_data["blue"])[used_vertices],
            ],
            axis=1,
        )
    else:
        colors = None
    return {
        "vertices": points,
        "colors": colors,
        "faces": out_faces,
        "source_face_count": len(selected_faces_source),
        "source_vertex_count": len(used_vertices),
        "selected_point_count": len(selected),
    }


def read_ply_vertex_data(path: Path) -> dict[str, Any]:
    np = import_numpy()
    parsed = parse_ply_vertex_header(path)
    ply_format = parsed["format"]
    vertex_count = parsed["vertex_count"]
    properties: list[tuple[str, str]] = parsed["properties"]
    if vertex_count is None:
        raise RuntimeError(f"PLY file has no element vertex header: {path}")
    if not properties:
        raise RuntimeError(f"PLY file has no vertex properties: {path}")

    data: dict[str, Any] = {}
    if ply_format == "ascii":
        with path.open("rb") as f:
            f.seek(int(parsed["data_offset"]))
            rows = []
            for _ in range(int(vertex_count)):
                raw_line = f.readline()
                if not raw_line:
                    raise RuntimeError(f"PLY ended before all vertex rows were read: {path}")
                values = raw_line.decode("ascii", errors="ignore").strip().split()
                if len(values) < len(properties):
                    raise RuntimeError(f"PLY vertex row has too few values: {path}")
                rows.append(values)
        for index, (name, prop_type) in enumerate(properties):
            dtype = PLY_NUMPY_DTYPES.get(prop_type)
            if dtype is None:
                raise RuntimeError(f"Unsupported PLY property type {prop_type!r}: {path}")
            data[name] = np.asarray([row[index] for row in rows], dtype=np.dtype(dtype))
        return {**parsed, "data": data}

    if ply_format in {"binary_little_endian", "binary_big_endian"}:
        byte_order = "<" if ply_format == "binary_little_endian" else ">"
        dtype_fields = []
        for name, prop_type in properties:
            dtype_code = PLY_NUMPY_DTYPES.get(prop_type)
            if dtype_code is None:
                raise RuntimeError(f"Unsupported PLY property type {prop_type!r}: {path}")
            dtype_fields.append((name, np.dtype(byte_order + dtype_code)))
        dtype = np.dtype(dtype_fields)
        with path.open("rb") as f:
            f.seek(int(parsed["data_offset"]))
            table = np.fromfile(f, dtype=dtype, count=int(vertex_count))
        if table.shape[0] != int(vertex_count):
            raise RuntimeError(f"PLY ended before all binary vertex rows were read: {path}")
        data = {name: table[name] for name, _prop_type in properties}
        return {**parsed, "data": data}

    raise RuntimeError(f"Unsupported PLY format {ply_format!r}: {path}")


def ply_color_channels_to_rgb(data: dict[str, Any], names: set[str]):
    np = import_numpy()
    if {"red", "green", "blue"}.issubset(names):
        rgb = np.stack(
            [
                np.asarray(data["red"], dtype=np.float32),
                np.asarray(data["green"], dtype=np.float32),
                np.asarray(data["blue"], dtype=np.float32),
            ],
            axis=1,
        )
        if rgb.size and float(np.nanmax(rgb)) > 1.5:
            rgb = rgb / 255.0
        return np.clip(rgb, 0.0, 1.0)
    if {"f_dc_0", "f_dc_1", "f_dc_2"}.issubset(names):
        dc = np.stack(
            [
                np.asarray(data["f_dc_0"], dtype=np.float32),
                np.asarray(data["f_dc_1"], dtype=np.float32),
                np.asarray(data["f_dc_2"], dtype=np.float32),
            ],
            axis=1,
        )
        return sh_dc_to_rgb(dc)
    return None


def format_ply_ascii_value(value: Any, prop_type: str) -> str:
    if PLY_NUMPY_DTYPES.get(prop_type, "").startswith(("i", "u")):
        return str(int(value))
    return f"{float(value):.8f}"


def summarize_ascii_ply_int_property(path: Path, property_name: str) -> dict[str, Any]:
    try:
        header = parse_ply_vertex_header(path)
    except Exception:
        return {}
    if header.get("format") != "ascii":
        return {}
    properties = [name for name, _prop_type in header.get("properties", [])]
    if property_name not in properties:
        return {}
    vertex_count = header.get("vertex_count")
    if vertex_count is None:
        return {}
    property_index = properties.index(property_name)
    distribution: dict[str, int] = {}
    positive_count = 0
    positive_value_set: set[int] = set()
    try:
        with path.open("rb") as f:
            f.seek(int(header["data_offset"]))
            for _ in range(int(vertex_count)):
                raw_line = f.readline()
                if not raw_line:
                    break
                parts = raw_line.decode("ascii", errors="ignore").strip().split()
                if len(parts) <= property_index:
                    continue
                try:
                    value = int(float(parts[property_index]))
                except Exception:
                    continue
                distribution[str(value)] = distribution.get(str(value), 0) + 1
                if value > 0:
                    positive_count += 1
                    positive_value_set.add(value)
    except Exception:
        return {}
    return {
        "distribution": distribution,
        "positive_count": positive_count,
        "positive_value_count": len(positive_value_set),
    }


def write_vertex_data_ascii_ply(
    path: Path,
    properties: list[tuple[str, str]],
    data: dict[str, Any],
    extra_properties: list[tuple[str, str, list[Any]]] | None = None,
) -> int:
    ensure_dir(path.parent)
    extras = extra_properties or []
    if not properties and not extras:
        raise ValueError("No PLY properties to write")
    vertex_count = 0
    if properties:
        vertex_count = len(next(iter(data.values())))
    elif extras:
        vertex_count = len(extras[0][2])
    for _name, _prop_type, values in extras:
        if len(values) != vertex_count:
            raise ValueError("Extra PLY property length does not match vertex count")
    with path.open("w", encoding="utf-8") as f:
        f.write("ply\n")
        f.write("format ascii 1.0\n")
        f.write(f"element vertex {vertex_count}\n")
        for name, prop_type in properties:
            f.write(f"property {prop_type} {name}\n")
        for name, prop_type, _values in extras:
            f.write(f"property {prop_type} {name}\n")
        f.write("end_header\n")
        for index in range(vertex_count):
            values = [format_ply_ascii_value(data[name][index], prop_type) for name, prop_type in properties]
            values.extend(format_ply_ascii_value(extra_values[index], prop_type) for _name, prop_type, extra_values in extras)
            f.write(" ".join(values) + "\n")
    return vertex_count


def read_gsplat_ply(path: Path) -> dict[str, Any]:
    np = import_numpy()
    vertex_data = read_ply_vertex_data(path)
    data = vertex_data["data"]
    properties = [name for name, _prop_type in vertex_data["properties"]]
    names = set(properties)
    required_xyz = {"x", "y", "z"}
    if not required_xyz.issubset(names):
        missing = ", ".join(sorted(required_xyz - names))
        raise ValueError(f"Not a renderable gsplat PLY, missing properties: {missing}")
    has_rgb = {"red", "green", "blue"}.issubset(names)
    has_dc = {"f_dc_0", "f_dc_1", "f_dc_2"}.issubset(names)
    colors = ply_color_channels_to_rgb(data, names)
    if colors is None:
        raise ValueError("Not a renderable gsplat PLY, missing red/green/blue or f_dc_0/f_dc_1/f_dc_2 color properties")
    points = np.stack(
        [
            np.asarray(data["x"], dtype=np.float32),
            np.asarray(data["y"], dtype=np.float32),
            np.asarray(data["z"], dtype=np.float32),
        ],
        axis=1,
    )

    opacities_raw = np.asarray(data["opacity"], dtype=np.float32) if "opacity" in names else np.full(points.shape[0], 0.5, dtype=np.float32)
    opacities = 1.0 / (1.0 + np.exp(-opacities_raw)) if has_dc and "opacity" in names else opacities_raw
    scales_raw = np.stack(
        [
            np.asarray(data["scale_0"], dtype=np.float32) if "scale_0" in names else np.full(points.shape[0], 0.02, dtype=np.float32),
            np.asarray(data["scale_1"], dtype=np.float32) if "scale_1" in names else np.full(points.shape[0], 0.02, dtype=np.float32),
            np.asarray(data["scale_2"], dtype=np.float32) if "scale_2" in names else np.full(points.shape[0], 0.02, dtype=np.float32),
        ],
        axis=1,
    )
    scales = np.exp(scales_raw) if has_dc and {"scale_0", "scale_1", "scale_2"}.issubset(names) else scales_raw
    quats = np.stack(
        [
            np.asarray(data["rot_0"], dtype=np.float32) if "rot_0" in names else np.ones(points.shape[0], dtype=np.float32),
            np.asarray(data["rot_1"], dtype=np.float32) if "rot_1" in names else np.zeros(points.shape[0], dtype=np.float32),
            np.asarray(data["rot_2"], dtype=np.float32) if "rot_2" in names else np.zeros(points.shape[0], dtype=np.float32),
            np.asarray(data["rot_3"], dtype=np.float32) if "rot_3" in names else np.zeros(points.shape[0], dtype=np.float32),
        ],
        axis=1,
    )
    normals = None
    if {"nx", "ny", "nz"}.issubset(names):
        normals = np.stack(
            [
                np.asarray(data["nx"], dtype=np.float32),
                np.asarray(data["ny"], dtype=np.float32),
                np.asarray(data["nz"], dtype=np.float32),
            ],
            axis=1,
        )
    f_rest = None
    f_rest_names = [f"f_rest_{idx}" for idx in range(45)]
    if set(f_rest_names).issubset(names):
        f_rest = np.stack([np.asarray(data[name], dtype=np.float32) for name in f_rest_names], axis=1)
    return {
        "means": points,
        "colors": colors,
        "opacities": opacities,
        "scales": scales,
        "quats": quats,
        "normals": normals,
        "f_rest": f_rest,
        "properties": properties,
    }


def read_ascii_ply_property(path: Path, property_name: str) -> list[Any] | None:
    try:
        _header, properties, rows = read_ascii_ply_table(path)
    except Exception:
        return None
    property_to_index = {name: idx for idx, name in enumerate(properties)}
    if property_name not in property_to_index:
        return None
    idx = property_to_index[property_name]
    values = []
    for row in rows:
        raw = row[idx]
        try:
            values.append(int(float(raw)))
        except ValueError:
            values.append(raw)
    return values


def read_ascii_ply_float_property(path: Path, property_name: str) -> list[float] | None:
    try:
        _header, properties, rows = read_ascii_ply_table(path)
    except Exception:
        return None
    property_to_index = {name: idx for idx, name in enumerate(properties)}
    if property_name not in property_to_index:
        return None
    idx = property_to_index[property_name]
    values: list[float] = []
    for row in rows:
        try:
            values.append(float(row[idx]))
        except Exception:
            return None
    return values


def export_viewer_plys(
    source_ply: Path,
    output_dir: Path,
    prefix: str,
    include_labels: bool = False,
) -> dict[str, Any]:
    np = import_numpy()
    data = read_gsplat_ply(source_ply)
    labels = read_ascii_ply_property(source_ply, "object_id") if include_labels else None
    probabilities = read_ascii_ply_float_property(source_ply, "object_probability") if include_labels else None
    display_colors = data["colors"]
    if labels is not None:
        display_colors = semantic_colors_for_labels(np.asarray(labels, dtype=np.int64)) / 255.0
    f_rest = None if labels is not None else data.get("f_rest")
    plain_path = output_dir / f"{prefix}_point_cloud.ply"
    supersplat_path = output_dir / f"{prefix}_supersplat.ply"
    write_point_cloud_ascii_ply(plain_path, data["means"], display_colors)
    write_supersplat_ply(
        supersplat_path,
        data["means"],
        display_colors,
        data["opacities"],
        data["scales"],
        data["quats"],
        labels=labels,
        probabilities=probabilities,
        normals=data.get("normals"),
        f_rest=f_rest,
    )
    label_sidecar = write_supersplat_label_sidecar(supersplat_path, labels, probabilities)
    return {
        "source_ply": str(source_ply),
        "point_cloud_ply": str(plain_path),
        "point_cloud_ply_info": {
            "path": str(plain_path),
            "format": "plain_xyzrgb_ply",
            "includes_object_id": False,
            "includes_object_probability": False,
        },
        "supersplat_ply": str(supersplat_path),
        "supersplat_ply_info": {
            "path": str(supersplat_path),
            "format": "graphdeco_supersplat_ply",
            "encoding": "binary_little_endian",
            "includes_object_id": False,
            "includes_object_probability": False,
            "label_sidecar": str(label_sidecar) if label_sidecar else None,
        },
        "vertex_count": int(data["means"].shape[0]),
        "includes_object_id": bool(labels is not None),
        "includes_object_probability": bool(probabilities is not None),
        "label_sidecar": str(label_sidecar) if label_sidecar else None,
        "notes": (
            "point_cloud_ply is a plain XYZ/RGB PLY for Preview/CloudCompare. "
            "supersplat_ply uses binary GraphDECO/SuperSplat Gaussian fields including f_dc_*, f_rest_*, "
            "opacity, scale_*, and rot_*; semantic object_id/object_probability metadata is stored in "
            "label_sidecar when present."
        ),
    }


def load_frame_tensor(path: Path, width: int, height: int, device: str):
    np = import_numpy()
    torch, _gsplat = import_torch_and_gsplat()
    Image = import_pil_image()
    try:
        with Image.open(path) as pil_image:
            pil_image = pil_image.convert("RGB")
            if pil_image.size != (width, height):
                pil_image = pil_image.resize((width, height), Image.Resampling.LANCZOS)
            image = np.asarray(pil_image, dtype=np.float32) / 255.0
    except Exception as exc:
        raise RuntimeError(f"Failed to read frame image: {path}") from exc
    image = np.ascontiguousarray(image, dtype=np.float32)
    try:
        return torch.from_numpy(image).to(device=device, dtype=torch.float32)
    except TypeError:
        # Some CUDA images have mismatched torch/numpy C-API state after remote
        # package installs; list conversion is slower but robust for QA renders.
        return torch.tensor(image.tolist(), device=device, dtype=torch.float32)


def scaled_intrinsic_for_size(intrinsic: dict[str, Any], width: int | None, height: int | None) -> dict[str, Any]:
    target_width = int(width or intrinsic["w"])
    target_height = int(height or intrinsic["h"])
    source_width = float(intrinsic["w"])
    source_height = float(intrinsic["h"])
    if source_width <= 0 or source_height <= 0:
        raise ValueError("Camera intrinsic width/height must be positive.")
    scale_x = float(target_width) / source_width
    scale_y = float(target_height) / source_height
    scaled = dict(intrinsic)
    scaled["w"] = target_width
    scaled["h"] = target_height
    scaled["fx"] = float(intrinsic["fx"]) * scale_x
    scaled["fy"] = float(intrinsic.get("fy", intrinsic["fx"])) * scale_y
    scaled["cx"] = float(intrinsic["cx"]) * scale_x
    scaled["cy"] = float(intrinsic["cy"]) * scale_y
    return scaled


def camera_tensors_for_frame(camera_info: dict[str, Any], frame_id: str, extrinsic_type: str, device: str, width: int | None = None, height: int | None = None):
    torch, _gsplat = import_torch_and_gsplat()
    intrinsic = scaled_intrinsic_for_size(intrinsic_for_frame(camera_info, frame_id), width, height)
    extrinsic = resolve_extrinsic(camera_info["extrinsic"], frame_id)
    if extrinsic is None:
        raise ValueError(f"Missing camera extrinsic for frame {frame_id}")
    w2c = world_to_camera_matrix(extrinsic, camera_info.get("extrinsic_type") or extrinsic_type)
    viewmat = torch.tensor(w2c, device=device, dtype=torch.float32)
    K = torch.tensor(
        [
            [float(intrinsic["fx"]), 0.0, float(intrinsic["cx"])],
            [0.0, float(intrinsic.get("fy", intrinsic["fx"])), float(intrinsic["cy"])],
            [0.0, 0.0, 1.0],
        ],
        device=device,
        dtype=torch.float32,
    )
    return intrinsic, viewmat, K


def cmd_train_gsplat(args: argparse.Namespace) -> int:
    np = import_numpy()
    torch, gsplat = import_torch_and_gsplat()
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    frames_dir = args.frames_dir or (project_root / manifest["scene"]["frames_dir"])
    camera_info_path = args.camera_info or (project_root / manifest["scene"]["camera_info"])
    point_cloud_path = args.point_cloud or (project_root / manifest["scene"]["point_cloud"])
    output_dir = args.output_dir or (project_root / manifest["scene"]["scene_3dgs"])
    output_dir = output_dir.resolve()
    iteration_dir = ensure_dir(output_dir / "point_cloud" / f"iteration_{int(args.iterations)}")
    log_path = project_root / "logs" / "gsplat_train_log.json"

    frames = list_frame_images(frames_dir)
    if args.max_frames and args.max_frames > 0:
        frames = frames[: args.max_frames]
    camera_info = load_camera_info(camera_info_path)
    points, colors = read_point_cloud(point_cloud_path)
    if points.shape[0] == 0:
        raise RuntimeError(f"No points found in point cloud: {point_cloud_path}")
    max_points = int(args.max_points or 0)
    if max_points > 0 and points.shape[0] > max_points:
        rng = np.random.default_rng(args.seed)
        choice = np.sort(rng.choice(points.shape[0], size=max_points, replace=False))
        points = points[choice]
        colors = colors[choice] if colors is not None else None

    device = args.device
    if device == "auto":
        device = "cuda" if torch.cuda.is_available() else "cpu"
    if device == "cuda" and not torch.cuda.is_available():
        raise RuntimeError("CUDA requested but torch.cuda.is_available() is False.")

    points_np = np.asarray(points, dtype=np.float32)
    colors_np = np.asarray(colors if colors is not None else np.full((points_np.shape[0], 3), 0.6), dtype=np.float32)
    spacing = float(args.init_scale)
    if args.init_scale <= 0:
        try:
            from scipy.spatial import cKDTree  # type: ignore

            distances, _indices = cKDTree(points_np).query(points_np, k=min(2, points_np.shape[0]))
            if distances.ndim == 2 and distances.shape[1] > 1:
                positive = distances[:, 1][distances[:, 1] > 1e-8]
                spacing = float(np.median(positive)) if positive.size else 0.02
        except Exception:
            spacing = 0.02
    spacing = max(spacing, 1e-4)

    means = torch.nn.Parameter(torch.tensor(points_np, device=device, dtype=torch.float32))
    color_logits = torch.nn.Parameter(torch.logit(torch.tensor(np.clip(colors_np, 1e-4, 1.0 - 1e-4), device=device, dtype=torch.float32)))
    log_scales = torch.nn.Parameter(torch.full((points_np.shape[0], 3), float(np.log(spacing)), device=device, dtype=torch.float32))
    opacity_logits = torch.nn.Parameter(torch.full((points_np.shape[0],), float(args.init_opacity_logit), device=device, dtype=torch.float32))
    quats = torch.zeros((points_np.shape[0], 4), device=device, dtype=torch.float32)
    quats[:, 0] = 1.0

    optimizer = torch.optim.Adam(
        [
            {"params": [means], "lr": args.lr_position},
            {"params": [color_logits], "lr": args.lr_color},
            {"params": [log_scales], "lr": args.lr_scale},
            {"params": [opacity_logits], "lr": args.lr_opacity},
        ]
    )
    frame_records = []
    for frame_path in frames:
        frame_id = frame_id_for_path(frame_path)
        base_intrinsic = intrinsic_for_frame(camera_info, frame_id)
        target_width = int(args.width or base_intrinsic["w"])
        target_height = int(args.height or base_intrinsic["h"])
        intrinsic, viewmat, K = camera_tensors_for_frame(camera_info, frame_id, args.extrinsic_type, device, target_width, target_height)
        target = load_frame_tensor(frame_path, target_width, target_height, device)
        frame_records.append(
            {
                "frame_id": frame_id,
                "path": str(frame_path),
                "viewmat": viewmat,
                "K": K,
                "target": target,
                "width": target_width,
                "height": target_height,
            }
        )
    if not frame_records:
        raise RuntimeError("No training frames available.")

    train_log = []
    start = time.time()
    for step in range(1, int(args.iterations) + 1):
        record = frame_records[(step - 1) % len(frame_records)]
        optimizer.zero_grad(set_to_none=True)
        colors_t = torch.sigmoid(color_logits)
        scales_t = torch.exp(log_scales).clamp(args.min_scale, args.max_scale)
        opacities_t = torch.sigmoid(opacity_logits)
        render, alphas, _meta = gsplat.rasterization(
            means,
            quats,
            scales_t,
            opacities_t,
            colors_t,
            record["viewmat"][None],
            record["K"][None],
            width=int(record["width"]),
            height=int(record["height"]),
            packed=False,
            backgrounds=record["target"].reshape(-1, 3).mean(dim=0, keepdim=True),
            render_mode="RGB",
        )
        pred = render[0]
        loss = torch.nn.functional.l1_loss(pred, record["target"])
        if args.alpha_reg > 0:
            loss = loss + float(args.alpha_reg) * alphas.mean()
        loss.backward()
        optimizer.step()
        if step == 1 or step == args.iterations or step % args.log_every == 0:
            train_log.append({"step": step, "frame_id": record["frame_id"], "loss": float(loss.detach().cpu())})
            print(f"step={step} frame={record['frame_id']} loss={float(loss.detach().cpu()):.6f}")

    with torch.no_grad():
        colors_out = torch.sigmoid(color_logits).detach().cpu().numpy()
        scales_out = torch.exp(log_scales).clamp(args.min_scale, args.max_scale).detach().cpu().numpy()
        opacities_out = torch.sigmoid(opacity_logits).detach().cpu().numpy()
        means_out = means.detach().cpu().numpy()
        quats_out = quats.detach().cpu().numpy()

    splat_ply = iteration_dir / "point_cloud.ply"
    write_gsplat_ply(splat_ply, means_out, colors_out, opacities_out, scales_out, quats_out)
    viewer_exports = export_viewer_plys(splat_ply, iteration_dir, "point_cloud")
    trainer_manifest_path = output_dir / "video2mesh_gsplat_train.json"
    trainer_manifest = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "trainer": "video2mesh_minimal_gsplat",
        "project_root": str(project_root),
        "frames_dir": str(frames_dir),
        "camera_info": str(camera_info_path),
        "input_point_cloud": str(point_cloud_path),
        "output_dir": str(output_dir),
        "splat_ply": str(splat_ply),
        "point_cloud_ply": viewer_exports["point_cloud_ply"],
        "supersplat_ply": viewer_exports["supersplat_ply"],
        "device": device,
        "point_count": int(means_out.shape[0]),
        "frame_count": len(frame_records),
        "iterations": int(args.iterations),
        "elapsed_seconds": round(time.time() - start, 3),
        "log": train_log,
        "notes": (
            "Minimal gsplat trainer for Video2Mesh integration. It optimizes point-initialized "
            "3D Gaussians without densification/pruning or SH; use it as a real differentiable "
            "3DGS smoke/baseline, not as final-quality reconstruction."
        ),
    }
    write_json(trainer_manifest_path, trainer_manifest)

    result = 0
    manifest = load_manifest(project_root)
    if args.register:
        register_args = argparse.Namespace(project_root=project_root, path=output_dir, splat_ply=splat_ply, mode=args.register_mode)
        result = cmd_register_3dgs(register_args)
        manifest = load_manifest(project_root)
        registered_output_dir = project_root / manifest["scene"]["scene_3dgs"]
        registered_splat_ply = str(local_registered_path(output_dir, registered_output_dir, splat_ply))
        registered_point_cloud_ply = str(local_registered_path(output_dir, registered_output_dir, Path(viewer_exports["point_cloud_ply"])))
        registered_supersplat_ply = str(local_registered_path(output_dir, registered_output_dir, Path(viewer_exports["supersplat_ply"])))
        manifest["artifacts"]["scene_3dgs"] = str(registered_output_dir)
        manifest["artifacts"]["scene_3dgs_source"] = str(output_dir)
        manifest["artifacts"]["scene_3dgs_ply"] = registered_splat_ply
        manifest["artifacts"]["scene_3dgs_point_cloud_ply"] = registered_point_cloud_ply
        manifest["artifacts"]["scene_3dgs_supersplat_ply"] = registered_supersplat_ply
        manifest["external_stages"]["video_to_3dgs"] = {
            "status": "gsplat_trained_registered",
            "notes": "Minimal gsplat trainer completed and output was registered.",
            "output_path": str(output_dir),
            "splat_ply": registered_splat_ply,
            "point_cloud_ply": registered_point_cloud_ply,
            "supersplat_ply": registered_supersplat_ply,
            "point_count": int(means_out.shape[0]),
            "iterations": int(args.iterations),
            "frame_count": len(frame_records),
        }
    else:
        manifest["external_stages"]["video_to_3dgs_trial"] = {
            "status": "gsplat_trained_unregistered",
            "notes": "Minimal gsplat trainer completed without registering this trial output.",
            "output_path": str(output_dir),
            "point_cloud_ply": viewer_exports["point_cloud_ply"],
            "supersplat_ply": viewer_exports["supersplat_ply"],
            "point_count": int(means_out.shape[0]),
            "iterations": int(args.iterations),
            "frame_count": len(frame_records),
        }
    manifest["artifacts"]["gsplat_train_manifest"] = str(trainer_manifest_path)
    save_manifest(project_root, manifest)
    print(f"Minimal gsplat output: {splat_ply}")
    print(f"Training manifest: {trainer_manifest_path}")
    return result


def save_rgb_image(path: Path, image_array) -> None:
    np = import_numpy()
    Image = import_pil_image()
    ensure_dir(path.parent)
    if hasattr(image_array, "detach"):
        image_array = image_array.detach().cpu().tolist()
    rgb = np.clip(np.rint(np.asarray(image_array, dtype=np.float32) * 255.0), 0, 255).astype(np.uint8)
    Image.fromarray(rgb, mode="RGB").save(path)


def save_gray_u8_image(path: Path, image_array) -> None:
    np = import_numpy()
    Image = import_pil_image()
    ensure_dir(path.parent)
    arr = np.asarray(image_array, dtype=np.float32)
    u8 = np.clip(np.rint(arr * 255.0), 0, 255).astype(np.uint8)
    Image.fromarray(u8, mode="L").save(path)


def save_depth_preview(path: Path, depth, valid_mask=None, max_depth: float | None = None) -> None:
    np = import_numpy()
    depth_np = np.asarray(depth, dtype=np.float32)
    valid = np.isfinite(depth_np) & (depth_np > 0)
    if valid_mask is not None:
        valid &= np.asarray(valid_mask, dtype=bool)
    if max_depth is None:
        values = depth_np[valid]
        max_depth = float(np.percentile(values, 98)) if values.size else 1.0
    denom = max(float(max_depth), 1e-6)
    preview = np.zeros(depth_np.shape, dtype=np.float32)
    preview[valid] = np.clip(depth_np[valid] / denom, 0.0, 1.0)
    save_gray_u8_image(path, preview)


def save_normal_image(path: Path, normal) -> None:
    np = import_numpy()
    Image = import_pil_image()
    normal_np = np.asarray(normal, dtype=np.float32)
    rgb = np.clip(np.rint((normal_np * 0.5 + 0.5) * 255.0), 0, 255).astype(np.uint8)
    ensure_dir(path.parent)
    Image.fromarray(rgb, mode="RGB").save(path)


def depth_to_normal_map(depth, fx: float, fy: float):
    np = import_numpy()
    depth_np = np.asarray(depth, dtype=np.float32)
    valid = np.isfinite(depth_np) & (depth_np > 0)
    dz_dy, dz_dx = np.gradient(np.where(valid, depth_np, 0.0))
    normal = np.dstack((-dz_dx * float(fx), -dz_dy * float(fy), np.ones_like(depth_np, dtype=np.float32)))
    norm = np.linalg.norm(normal, axis=2, keepdims=True)
    normal = normal / np.maximum(norm, 1e-8)
    normal[~valid] = 0.0
    return normal.astype(np.float32)


def load_mask_probability_image(mask_path: Path, width: int, height: int, probability_scale: float = 255.0):
    np = import_numpy()
    Image = import_pil_image()
    try:
        with Image.open(mask_path) as image:
            image = image.convert("L")
            if image.size != (int(width), int(height)):
                image = image.resize((int(width), int(height)), Image.Resampling.BILINEAR)
            mask = np.asarray(image, dtype=np.float32)
    except Exception as exc:
        raise RuntimeError(f"Failed to read mask image: {mask_path}") from exc
    return clamp_probability_array(mask / max(float(probability_scale), 1e-6))


def mask_active_pixel_count(mask_path: Path, min_probability: float, probability_scale: float) -> int:
    np = import_numpy()
    Image = import_pil_image()
    try:
        with Image.open(mask_path) as image:
            mask = np.asarray(image.convert("L"), dtype=np.float32)
    except Exception:
        return 0
    probability = clamp_probability_array(mask / max(float(probability_scale), 1e-6))
    return int((probability >= float(min_probability)).sum())


def clean_binary_object_mask(
    mask,
    kernel_size: int = 5,
    keep_largest_component: bool = True,
    min_component_pixels: int = 64,
    erode_iterations: int = 0,
):
    np = import_numpy()
    mask_np = np.asarray(mask, dtype=bool)
    if mask_np.size == 0 or not mask_np.any():
        return mask_np

    def numpy_component_filter(binary):
        binary_np = np.asarray(binary, dtype=bool)
        height, width = binary_np.shape
        visited = np.zeros_like(binary_np, dtype=bool)
        components: list[list[tuple[int, int]]] = []
        for y in range(height):
            for x in range(width):
                if not binary_np[y, x] or visited[y, x]:
                    continue
                stack = [(y, x)]
                visited[y, x] = True
                component: list[tuple[int, int]] = []
                while stack:
                    cy, cx = stack.pop()
                    component.append((cy, cx))
                    for ny in range(max(0, cy - 1), min(height, cy + 2)):
                        for nx in range(max(0, cx - 1), min(width, cx + 2)):
                            if visited[ny, nx] or not binary_np[ny, nx]:
                                continue
                            visited[ny, nx] = True
                            stack.append((ny, nx))
                components.append(component)
        filtered = np.zeros_like(binary_np, dtype=bool)
        if keep_largest_component and components:
            largest = max(components, key=len)
            if len(largest) >= int(min_component_pixels):
                for y, x in largest:
                    filtered[y, x] = True
            return filtered
        for component in components:
            if len(component) >= int(min_component_pixels):
                for y, x in component:
                    filtered[y, x] = True
        return filtered

    kernel_size = int(kernel_size or 0)
    try:
        cv2 = import_cv2()
        u8 = (mask_np.astype(np.uint8) * 255)
        if kernel_size > 1:
            k = max(1, kernel_size)
            if k % 2 == 0:
                k += 1
            kernel = np.ones((k, k), dtype=np.uint8)
            u8 = cv2.morphologyEx(u8, cv2.MORPH_OPEN, kernel)
            u8 = cv2.morphologyEx(u8, cv2.MORPH_CLOSE, kernel)
        cleaned = u8 > 0
        if int(erode_iterations or 0) > 0 and cleaned.any():
            k = max(1, kernel_size)
            if k % 2 == 0:
                k += 1
            kernel = np.ones((k, k), dtype=np.uint8)
            cleaned = cv2.erode(cleaned.astype(np.uint8), kernel, iterations=int(erode_iterations)) > 0
        if keep_largest_component and cleaned.any():
            count, labels, stats, _centroids = cv2.connectedComponentsWithStats(cleaned.astype(np.uint8), connectivity=8)
            if count > 1:
                areas = stats[1:, cv2.CC_STAT_AREA]
                keep = int(areas.argmax()) + 1
                if int(stats[keep, cv2.CC_STAT_AREA]) >= int(min_component_pixels):
                    cleaned = labels == keep
        if int(min_component_pixels) > 0 and cleaned.any() and not keep_largest_component:
            count, labels, stats, _centroids = cv2.connectedComponentsWithStats(cleaned.astype(np.uint8), connectivity=8)
            keep_mask = np.zeros_like(cleaned, dtype=bool)
            for label in range(1, count):
                if int(stats[label, cv2.CC_STAT_AREA]) >= int(min_component_pixels):
                    keep_mask |= labels == label
            cleaned = keep_mask
        return cleaned
    except Exception:
        cleaned = mask_np
        for _ in range(max(0, int(erode_iterations or 0))):
            padded = np.pad(cleaned, 1, mode="constant", constant_values=False)
            eroded = (
                padded[:-2, :-2]
                & padded[:-2, 1:-1]
                & padded[:-2, 2:]
                & padded[1:-1, :-2]
                & padded[1:-1, 1:-1]
                & padded[1:-1, 2:]
                & padded[2:, :-2]
                & padded[2:, 1:-1]
                & padded[2:, 2:]
            )
            cleaned = eroded
        return numpy_component_filter(cleaned)


def clip_mask_by_depth_quantiles(mask, depth, q_min: float, q_max: float):
    np = import_numpy()
    mask_np = np.asarray(mask, dtype=bool)
    depth_np = np.asarray(depth, dtype=np.float32)
    if not mask_np.any():
        return mask_np, None
    values = depth_np[mask_np & np.isfinite(depth_np) & (depth_np > 0)]
    if values.size < 2:
        return mask_np, None
    low_q = max(0.0, min(1.0, float(q_min)))
    high_q = max(low_q, min(1.0, float(q_max)))
    low = float(np.quantile(values, low_q))
    high = float(np.quantile(values, high_q))
    clipped = mask_np & np.isfinite(depth_np) & (depth_np >= low) & (depth_np <= high)
    return clipped, {"min_depth": low, "max_depth": high, "q_min": low_q, "q_max": high_q}


def filter_mask_by_depth_edges(mask, depth, edge_quantile: float = 0.85, edge_max: float = 0.35):
    np = import_numpy()
    mask_np = np.asarray(mask, dtype=bool)
    depth_np = np.asarray(depth, dtype=np.float32)
    if not mask_np.any():
        return mask_np, None
    valid = mask_np & np.isfinite(depth_np) & (depth_np > 0)
    if int(valid.sum()) < 8:
        return mask_np, None
    filled = np.where(np.isfinite(depth_np) & (depth_np > 0), depth_np, 0.0)
    gy, gx = np.gradient(filled)
    grad = np.sqrt(gx * gx + gy * gy)
    values = grad[valid]
    if values.size < 8:
        return mask_np, None
    q_threshold = float(np.quantile(values, max(0.0, min(1.0, float(edge_quantile)))))
    threshold = q_threshold
    if float(edge_max or 0) > 0:
        threshold = min(threshold, float(edge_max))
    filtered = mask_np & (grad <= threshold)
    return filtered, {"threshold": threshold, "quantile_threshold": q_threshold, "edge_quantile": float(edge_quantile), "edge_max": float(edge_max)}


def filter_mask_by_world_bounds(mask, depth, intrinsic: dict[str, Any], world_to_camera, bounds):
    np = import_numpy()
    mask_np = np.asarray(mask, dtype=bool)
    if bounds is None or not mask_np.any():
        return mask_np, None
    depth_np = np.asarray(depth, dtype=np.float32)
    valid = mask_np & np.isfinite(depth_np) & (depth_np > 0)
    if int(valid.sum()) == 0:
        return mask_np, None
    ys, xs = np.nonzero(valid)
    z = depth_np[ys, xs].astype(np.float64)
    fx = float(intrinsic["fx"])
    fy = float(intrinsic.get("fy", fx))
    cx = float(intrinsic["cx"])
    cy = float(intrinsic["cy"])
    x = (xs.astype(np.float64) - cx) * z / max(fx, 1e-8)
    y = (ys.astype(np.float64) - cy) * z / max(fy, 1e-8)
    cam_points = np.stack([x, y, z, np.ones_like(z)], axis=1)
    c2w = np.linalg.inv(np.asarray(world_to_camera, dtype=np.float64))
    world = (c2w @ cam_points.T).T[:, :3]
    lower, upper = bounds
    keep_values = np.all((world >= lower) & (world <= upper), axis=1)
    filtered = np.zeros_like(mask_np, dtype=bool)
    filtered[ys[keep_values], xs[keep_values]] = True
    return filtered, {
        "enabled": True,
        "input_pixels": int(mask_np.sum()),
        "valid_depth_pixels": int(valid.sum()),
        "kept_pixels": int(filtered.sum()),
        "removed_pixels": int(mask_np.sum() - int(filtered.sum())),
        "min": [float(value) for value in lower.tolist()],
        "max": [float(value) for value in upper.tolist()],
    }


def mean_or_none(values: list[float]) -> float | None:
    if not values:
        return None
    return float(sum(float(value) for value in values) / len(values))


def psnr_from_mse(mse: float) -> float:
    if mse <= 1e-12:
        return 99.0
    import math

    return float(-10.0 * math.log10(float(mse)))


def cmd_render_gsplat_preview(args: argparse.Namespace) -> int:
    np = import_numpy()
    torch, gsplat = import_torch_and_gsplat()
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    frames_dir = args.frames_dir or (project_root / manifest["scene"]["frames_dir"])
    camera_info_path = args.camera_info or (project_root / manifest["scene"]["camera_info"])
    splat_ply = args.splat_ply or resolve_existing_path(manifest.get("artifacts", {}).get("scene_3dgs_ply"), project_root)
    if splat_ply is None or not splat_ply.exists():
        raise FileNotFoundError("No renderable 3DGS PLY found. Run train-gsplat/register-3dgs or pass --splat-ply.")
    output_dir = ensure_dir(args.output_dir or (project_root / manifest["simulator_assets_dir"] / "gsplat_preview"))

    device = args.device
    if device == "auto":
        device = "cuda" if torch.cuda.is_available() else "cpu"
    if device == "cuda" and not torch.cuda.is_available():
        raise RuntimeError("CUDA requested but torch.cuda.is_available() is False.")

    data = read_gsplat_ply(splat_ply)
    means = torch.tensor(data["means"], device=device, dtype=torch.float32)
    colors = torch.tensor(data["colors"], device=device, dtype=torch.float32)
    opacities = torch.tensor(data["opacities"], device=device, dtype=torch.float32)
    scales = torch.tensor(data["scales"], device=device, dtype=torch.float32)
    quats = torch.tensor(data["quats"], device=device, dtype=torch.float32)
    camera_info = load_camera_info(camera_info_path)
    frames = list_frame_images(frames_dir)
    if args.max_frames and args.max_frames > 0:
        frames = frames[: args.max_frames]

    frame_metrics = []
    with torch.no_grad():
        for frame_path in frames:
            frame_id = frame_id_for_path(frame_path)
            base_intrinsic = intrinsic_for_frame(camera_info, frame_id)
            width = int(args.width or base_intrinsic["w"])
            height = int(args.height or base_intrinsic["h"])
            intrinsic, viewmat, K = camera_tensors_for_frame(camera_info, frame_id, args.extrinsic_type, device, width, height)
            target = load_frame_tensor(frame_path, width, height, device)
            background = target.reshape(-1, 3).mean(dim=0, keepdim=True) if args.background == "target_mean" else None
            if args.background == "white":
                background = torch.ones((1, 3), device=device, dtype=torch.float32)
            elif args.background == "black":
                background = torch.zeros((1, 3), device=device, dtype=torch.float32)
            render, alphas, _meta = gsplat.rasterization(
                means,
                quats,
                scales,
                opacities,
                colors,
                viewmat[None],
                K[None],
                width=width,
                height=height,
                packed=False,
                backgrounds=background,
                render_mode="RGB",
            )
            pred = render[0].clamp(0.0, 1.0)
            error = (pred - target).abs()
            l1 = float(error.mean().detach().cpu())
            mse = float(torch.mean((pred - target) ** 2).detach().cpu())
            alpha_mean = float(alphas.mean().detach().cpu())
            frame_dir = ensure_dir(output_dir / frame_id)
            save_rgb_image(frame_dir / "render.png", pred)
            save_rgb_image(frame_dir / "target.png", target)
            save_rgb_image(frame_dir / "error.png", torch.clamp(error * float(args.error_gain), 0.0, 1.0))
            frame_metrics.append(
                {
                    "frame_id": frame_id,
                    "source_image": str(frame_path),
                    "render": str(frame_dir / "render.png"),
                    "target": str(frame_dir / "target.png"),
                    "error": str(frame_dir / "error.png"),
                    "width": width,
                    "height": height,
                    "l1": l1,
                    "mse": mse,
                    "psnr": psnr_from_mse(mse),
                    "alpha_mean": alpha_mean,
                }
            )

    mean_l1 = mean_or_none([item["l1"] for item in frame_metrics])
    mean_psnr = mean_or_none([item["psnr"] for item in frame_metrics])
    preview_manifest_path = output_dir / "preview_manifest.json"
    preview_manifest = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "splat_ply": str(splat_ply),
        "frames_dir": str(frames_dir),
        "camera_info": str(camera_info_path),
        "output_dir": str(output_dir),
        "device": device,
        "background": args.background,
        "gaussian_count": int(means.shape[0]),
        "frame_count": len(frame_metrics),
        "mean_l1": mean_l1,
        "mean_psnr": mean_psnr,
        "frames": frame_metrics,
        "notes": "Preview render/target/error images for checking whether the registered 3DGS explains the input frames.",
    }
    write_json(preview_manifest_path, preview_manifest)
    if args.update_manifest:
        manifest["artifacts"]["gsplat_preview"] = str(preview_manifest_path)
        save_manifest(project_root, manifest)
    print(f"Rendered {len(frame_metrics)} gsplat preview frame(s) to {output_dir}")
    print(f"mean_l1={mean_l1:.6f} mean_psnr={mean_psnr:.3f}" if mean_l1 is not None and mean_psnr is not None else "No preview frames rendered.")
    print(f"Preview manifest: {preview_manifest_path}")
    return 0


def _load_gsplat_tensors_for_render(splat_ply: Path, device: str):
    torch, _gsplat = import_torch_and_gsplat()
    data = read_gsplat_ply(splat_ply)
    return data, {
        "means": torch.tensor(data["means"], device=device, dtype=torch.float32),
        "colors": torch.tensor(data["colors"], device=device, dtype=torch.float32),
        "opacities": torch.tensor(data["opacities"], device=device, dtype=torch.float32),
        "scales": torch.tensor(data["scales"], device=device, dtype=torch.float32),
        "quats": torch.tensor(data["quats"], device=device, dtype=torch.float32),
    }


def render_gsplat_rgb_depth(
    tensors: dict[str, Any],
    viewmat,
    K,
    width: int,
    height: int,
    background,
):
    _torch, gsplat = import_torch_and_gsplat()
    render, alphas, meta = gsplat.rasterization(
        tensors["means"],
        tensors["quats"],
        tensors["scales"],
        tensors["opacities"],
        tensors["colors"],
        viewmat[None],
        K[None],
        width=int(width),
        height=int(height),
        packed=False,
        backgrounds=background,
        render_mode="RGB+ED",
    )
    image_depth = render[0]
    rgb = image_depth[..., :3].clamp(0.0, 1.0)
    depth = image_depth[..., 3].clamp(min=0.0)
    alpha = alphas[0]
    if alpha.ndim == 3 and alpha.shape[-1] == 1:
        alpha = alpha[..., 0]
    return rgb, depth, alpha, meta


def object_render_frame_records(
    object_id: str,
    records_by_object: dict[str, list[MaskRecord]],
    frames_by_id: dict[str, Path],
    max_frames: int,
    min_probability: float = 0.5,
    probability_scale: float = 255.0,
    selection: str = "largest_mask",
) -> list[MaskRecord]:
    records = [record for record in records_by_object.get(object_id, []) if record.frame_id in frames_by_id]
    if selection == "largest_mask":
        records.sort(
            key=lambda record: (
                -mask_active_pixel_count(record.path, min_probability, probability_scale),
                frame_sort_key(Path(record.frame_id)),
            )
        )
    else:
        records.sort(key=lambda record: frame_sort_key(Path(record.frame_id)))
    if max_frames and max_frames > 0:
        records = records[: int(max_frames)]
    return records


def cmd_export_3dgs_mesh_observations(args: argparse.Namespace) -> int:
    np = import_numpy()
    torch, _gsplat = import_torch_and_gsplat()
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    artifacts = manifest.get("artifacts", {}) if isinstance(manifest.get("artifacts"), dict) else {}
    frames_dir = resolve_project_cli_path(args.frames_dir, project_root) if args.frames_dir else (project_root / manifest["scene"]["frames_dir"])
    camera_info_path = resolve_project_cli_path(args.camera_info, project_root) if args.camera_info else (project_root / manifest["scene"]["camera_info"])
    mask_root = resolve_project_cli_path(args.mask_root, project_root) if args.mask_root else resolve_active_mask_root(project_root, manifest)
    splat_ply = resolve_project_cli_path(args.splat_ply, project_root) if args.splat_ply else resolve_existing_path(artifacts.get("scene_3dgs_ply"), project_root)
    if splat_ply is None or not splat_ply.exists():
        raise FileNotFoundError("No renderable 3DGS PLY found. Run/import 3DGS or pass --splat-ply.")
    output_dir = ensure_dir(resolve_project_relative_path(args.output_dir, project_root) if args.output_dir else (project_root / manifest["simulator_assets_dir"] / "3dgs_mesh_observations"))

    device = args.device
    if device == "auto":
        device = "cuda" if torch.cuda.is_available() else "cpu"
    if device == "cuda" and not torch.cuda.is_available():
        raise RuntimeError("CUDA requested but torch.cuda.is_available() is False.")

    _data, tensors = _load_gsplat_tensors_for_render(splat_ply, device)
    camera_info = load_camera_info(camera_info_path)
    frames = list_frame_images(frames_dir)
    frames_by_id = {frame_id_for_path(frame): frame for frame in frames}
    records_by_object = mask_records_by_object(mask_root)
    object_table, _object_id_to_semantic, records_by_id = object_table_from_records(project_root, manifest)
    requested = {slugify(value) for value in (args.object_ids or [])}
    object_reports: dict[str, Any] = {}
    skipped: dict[str, str] = {}

    with torch.no_grad():
        for item in object_table:
            object_id = slugify(item.get("object_id") or "")
            if object_id == "background":
                continue
            obj = records_by_id.get(object_id, {})
            if is_background_structure_record(obj) and not args.include_background_structures:
                skipped[object_id] = "background_structure"
                continue
            if requested and object_id not in requested:
                skipped[object_id] = "not_requested"
                continue
            object_records = object_render_frame_records(
                object_id,
                records_by_object,
                frames_by_id,
                int(args.max_frames_per_object or 0),
                float(args.min_probability),
                float(args.probability_scale),
                args.frame_selection,
            )
            if not object_records:
                skipped[object_id] = "missing_2d_masks"
                continue
            semantic_support_bounds, semantic_support_source = semantic_support_bounds_for_object(project_root, manifest, object_id, args)
            object_dir = ensure_dir(output_dir / object_id)
            frame_reports: list[dict[str, Any]] = []
            for record in object_records:
                frame_path = frames_by_id[record.frame_id]
                base_intrinsic = intrinsic_for_frame(camera_info, record.frame_id)
                width = int(args.width or base_intrinsic["w"])
                height = int(args.height or base_intrinsic["h"])
                intrinsic, viewmat, K = camera_tensors_for_frame(camera_info, record.frame_id, args.extrinsic_type, device, width, height)
                background = None
                if args.background == "white":
                    background = torch.ones((1, 3), device=device, dtype=torch.float32)
                elif args.background == "black":
                    background = torch.zeros((1, 3), device=device, dtype=torch.float32)
                elif args.background == "target_mean":
                    target = load_frame_tensor(frame_path, width, height, device)
                    background = target.reshape(-1, 3).mean(dim=0, keepdim=True)
                rgb, depth, alpha, _meta = render_gsplat_rgb_depth(tensors, viewmat, K, width, height, background)
                depth_np = depth.detach().cpu().numpy().astype(np.float32)
                alpha_np = alpha.detach().cpu().numpy().astype(np.float32)
                mask_prob = load_mask_probability_image(record.path, width, height, args.probability_scale)
                render_valid = (alpha_np >= float(args.min_alpha)) & (depth_np > 0)
                raw_object_mask = (mask_prob >= float(args.min_probability)) & render_valid
                object_mask = clean_binary_object_mask(
                    raw_object_mask,
                    kernel_size=int(args.mask_morph_kernel),
                    keep_largest_component=bool(args.keep_largest_mask_component),
                    min_component_pixels=int(args.min_component_pixels),
                    erode_iterations=int(args.mask_erode_iterations),
                )
                depth_clip = None
                depth_edge_filter = None
                if bool(args.depth_quantile_clip):
                    object_mask, depth_clip = clip_mask_by_depth_quantiles(
                        object_mask,
                        depth_np,
                        float(args.depth_quantile_min),
                        float(args.depth_quantile_max),
                    )
                if bool(args.depth_edge_filter):
                    object_mask, depth_edge_filter = filter_mask_by_depth_edges(
                        object_mask,
                        depth_np,
                        edge_quantile=float(args.depth_edge_quantile),
                        edge_max=float(args.depth_edge_max),
                    )
                semantic_support_filter = None
                if semantic_support_bounds is not None:
                    w2c_np = world_to_camera_matrix(
                        resolve_extrinsic(camera_info["extrinsic"], record.frame_id),
                        camera_info.get("extrinsic_type") or args.extrinsic_type,
                    )
                    object_mask, semantic_support_filter = filter_mask_by_world_bounds(
                        object_mask,
                        depth_np,
                        intrinsic,
                        w2c_np,
                        semantic_support_bounds,
                    )
                elif semantic_support_source is not None:
                    semantic_support_filter = semantic_support_source
                normal_np = depth_to_normal_map(depth_np, float(intrinsic["fx"]), float(intrinsic.get("fy", intrinsic["fx"])))
                frame_dir = ensure_dir(object_dir / record.frame_id)
                rgb_path = frame_dir / "rgb.png"
                depth_npy_path = frame_dir / "depth.npy"
                depth_png_path = frame_dir / "depth.png"
                normal_npy_path = frame_dir / "normal.npy"
                normal_png_path = frame_dir / "normal.png"
                mask_path = frame_dir / "mask.png"
                alpha_path = frame_dir / "alpha.png"
                save_rgb_image(rgb_path, rgb)
                np.save(depth_npy_path, depth_np)
                save_depth_preview(depth_png_path, depth_np, object_mask)
                np.save(normal_npy_path, normal_np)
                save_normal_image(normal_png_path, normal_np)
                save_gray_u8_image(mask_path, object_mask.astype(np.float32))
                save_gray_u8_image(alpha_path, alpha_np)
                camera_record = {
                    "frame_id": record.frame_id,
                    "source_image": str(frame_path),
                    "mask_source": str(record.path),
                    "width": width,
                    "height": height,
                    "intrinsic": intrinsic,
                    "extrinsic_type": camera_info.get("extrinsic_type") or args.extrinsic_type,
                    "world_to_camera": world_to_camera_matrix(
                        resolve_extrinsic(camera_info["extrinsic"], record.frame_id),
                        camera_info.get("extrinsic_type") or args.extrinsic_type,
                    ).tolist(),
                }
                write_json(frame_dir / "camera.json", camera_record)
                frame_reports.append(
                    {
                        **camera_record,
                        "rgb": str(rgb_path),
                        "depth_npy": str(depth_npy_path),
                        "depth_preview": str(depth_png_path),
                        "normal_npy": str(normal_npy_path),
                        "normal_preview": str(normal_png_path),
                        "mask": str(mask_path),
                        "alpha": str(alpha_path),
                        "mask_pixels": int(object_mask.sum()),
                        "raw_mask_pixels": int(raw_object_mask.sum()),
                        "mask_cleanup": {
                            "frame_selection": args.frame_selection,
                            "mask_morph_kernel": int(args.mask_morph_kernel),
                            "mask_erode_iterations": int(args.mask_erode_iterations),
                            "keep_largest_mask_component": bool(args.keep_largest_mask_component),
                            "min_component_pixels": int(args.min_component_pixels),
                            "depth_quantile_clip": bool(args.depth_quantile_clip),
                            "depth_clip": depth_clip,
                            "depth_edge_filter": bool(args.depth_edge_filter),
                            "depth_edge": depth_edge_filter,
                            "semantic_support_filter": semantic_support_filter,
                        },
                        "alpha_mean": float(alpha_np.mean()),
                        "depth_min": float(depth_np[object_mask].min()) if object_mask.any() else None,
                        "depth_max": float(depth_np[object_mask].max()) if object_mask.any() else None,
                    }
                )
            object_manifest = {
                "schema_version": DEFAULT_SCHEMA_VERSION,
                "object_id": object_id,
                "name": item.get("name", object_id),
                "category": item.get("category", "unknown"),
                "output_dir": str(object_dir),
                "frame_count": len(frame_reports),
                "frames": frame_reports,
            }
            write_json(object_dir / "observations.json", object_manifest)
            object_reports[object_id] = object_manifest

    manifest_path = output_dir / "3dgs_mesh_observations.json"
    report = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "splat_ply": str(splat_ply),
        "frames_dir": str(frames_dir),
        "camera_info": str(camera_info_path),
        "mask_root": str(mask_root),
        "output_dir": str(output_dir),
        "device": device,
        "method": "3dgs_multiview_rgb_depth_normal_mask_rendering",
        "objects": object_reports,
        "skipped_objects": skipped,
        "parameters": {
            "max_frames_per_object": int(args.max_frames_per_object or 0),
            "min_probability": float(args.min_probability),
            "min_alpha": float(args.min_alpha),
            "background": args.background,
            "width": args.width,
            "height": args.height,
            "frame_selection": args.frame_selection,
            "mask_morph_kernel": int(args.mask_morph_kernel),
            "mask_erode_iterations": int(args.mask_erode_iterations),
            "keep_largest_mask_component": bool(args.keep_largest_mask_component),
            "min_component_pixels": int(args.min_component_pixels),
            "depth_quantile_clip": bool(args.depth_quantile_clip),
            "depth_quantile_min": float(args.depth_quantile_min),
            "depth_quantile_max": float(args.depth_quantile_max),
            "depth_edge_filter": bool(args.depth_edge_filter),
            "depth_edge_quantile": float(args.depth_edge_quantile),
            "depth_edge_max": float(args.depth_edge_max),
        },
        "notes": "Object-centric observations rendered from 3DGS using registered real camera poses. Depth uses gsplat RGB+ED expected-depth output; normals are derived from the rendered depth map.",
    }
    write_json(manifest_path, report)
    manifest.setdefault("artifacts", {})["3dgs_mesh_observations"] = str(manifest_path)
    manifest.setdefault("external_stages", {})["3dgs_mesh_observation_rendering"] = {
        "status": "completed" if object_reports else "empty",
        "manifest": str(manifest_path),
        "object_count": len(object_reports),
        "skipped_objects": skipped,
    }
    save_manifest(project_root, manifest)
    print(f"Rendered 3DGS mesh observations for {len(object_reports)} object(s): {manifest_path}")
    if skipped:
        print(f"Skipped objects: {len(skipped)}")
    return 0


def gsplat_trial_records(project_root: Path, trial_root: Path) -> list[dict[str, Any]]:
    records: list[dict[str, Any]] = []
    for preview_path in sorted(trial_root.rglob("preview_manifest.json")):
        try:
            preview = read_json(preview_path)
        except Exception as exc:
            records.append({"preview_manifest": str(preview_path), "status": "invalid", "error": str(exc)})
            continue
        splat_ply = resolve_existing_path(preview.get("splat_ply"), project_root)
        trial_dir = Path(str(preview.get("trial_dir") or preview_path.parent.parent)).resolve()
        status = "ok"
        if not splat_ply or not splat_ply.exists():
            status = "missing_splat"
        else:
            try:
                splat_ply.resolve().relative_to(trial_dir)
            except Exception:
                status = "splat_outside_trial_dir"
        if not preview.get("frame_count") or int(preview.get("frame_count") or 0) <= 0:
            status = "no_preview_frames"
        records.append(
            {
                "status": status,
                "trial_dir": str(trial_dir),
                "preview_manifest": str(preview_path),
                "splat_ply": str(splat_ply) if splat_ply else preview.get("splat_ply"),
                "frame_count": preview.get("frame_count"),
                "gaussian_count": preview.get("gaussian_count"),
                "mean_l1": preview.get("mean_l1"),
                "mean_psnr": preview.get("mean_psnr"),
                "output_dir": preview.get("output_dir"),
            }
        )
    return records


def choose_gsplat_trial(records: list[dict[str, Any]], metric: str) -> dict[str, Any]:
    lower_is_better = metric == "mean_l1"
    candidates = []
    for record in records:
        if record.get("status") != "ok":
            continue
        value = record.get(metric)
        if value is None:
            continue
        try:
            value_float = float(value)
        except Exception:
            continue
        candidates.append((value_float, record))
    if not candidates:
        raise RuntimeError(f"No valid gsplat trial preview contains metric {metric!r}.")
    candidates.sort(key=lambda item: item[0], reverse=not lower_is_better)
    return candidates[0][1]


def cmd_select_gsplat_trial(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    trial_root = resolve_project_cli_path(args.trial_root, project_root)
    if not trial_root.exists():
        raise FileNotFoundError(f"Trial root not found: {trial_root}")
    records = gsplat_trial_records(project_root, trial_root)
    selected = choose_gsplat_trial(records, args.metric)
    selected_splat = Path(str(selected["splat_ply"])).resolve()
    trial_dir = Path(str(selected["trial_dir"])).resolve()
    active_output = project_root / manifest["scene"]["scene_3dgs"]

    if args.register:
        register_args = argparse.Namespace(project_root=project_root, path=trial_dir, splat_ply=selected_splat, mode=args.mode)
        cmd_register_3dgs(register_args)
        manifest = load_manifest(project_root)
        local_splat = local_registered_path(trial_dir, active_output, selected_splat)
        manifest.setdefault("external_stages", {})["video_to_3dgs"] = {
            "status": "gsplat_trial_selected_registered",
            "notes": "Selected and registered the best available gsplat trial by preview metric.",
            "trial_root": str(trial_root),
            "selected_trial_dir": str(trial_dir),
            "selected_splat_ply": str(local_splat),
            "metric": args.metric,
            "metric_value": selected.get(args.metric),
            "candidate_count": len([record for record in records if record.get("status") == "ok"]),
        }
    else:
        manifest.setdefault("external_stages", {})["video_to_3dgs_trial_selection"] = {
            "status": "gsplat_trial_selected_unregistered",
            "notes": "Selected the best available gsplat trial by preview metric without changing active 3DGS.",
            "trial_root": str(trial_root),
            "selected_trial_dir": str(trial_dir),
            "selected_splat_ply": str(selected_splat),
            "metric": args.metric,
            "metric_value": selected.get(args.metric),
            "candidate_count": len([record for record in records if record.get("status") == "ok"]),
        }

    report_path = args.output.resolve() if args.output else project_root / "logs" / "gsplat_trial_selection.json"
    write_json(
        report_path,
        {
            "schema_version": DEFAULT_SCHEMA_VERSION,
            "project_root": str(project_root),
            "trial_root": str(trial_root),
            "metric": args.metric,
            "registered": bool(args.register),
            "selected": selected,
            "records": records,
            "timestamp": int(time.time()),
        },
    )
    manifest.setdefault("artifacts", {})["gsplat_trial_selection"] = str(report_path)
    save_manifest(project_root, manifest)
    print(f"Selected gsplat trial: {selected.get('trial_dir')}")
    print(f"{args.metric}={selected.get(args.metric)}")
    if args.register:
        print(f"Registered active 3DGS from: {selected.get('splat_ply')}")
    print(f"Selection report: {report_path}")
    return 0


def run_import_3dgs_stage(report: dict[str, Any], name: str, fn, *, required: bool = False) -> bool:
    start = time.time()
    try:
        result = fn()
        if isinstance(result, int) and result != 0:
            raise RuntimeError(f"{name} returned non-zero exit code {result}")
        report.setdefault("steps", []).append({"name": name, "status": "completed", "elapsed_seconds": round(time.time() - start, 3)})
        return True
    except Exception as exc:
        report.setdefault("steps", []).append(
            {
                "name": name,
                "status": "failed",
                "elapsed_seconds": round(time.time() - start, 3),
                "error": str(exc),
            }
        )
        if required:
            raise
        return False


def cmd_import_3dgs_result(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    src = resolve_project_cli_path(args.path, project_root)
    splat_ply = resolve_project_cli_path(args.splat_ply, project_root) if args.splat_ply else None
    viewer_output_dir = resolve_project_cli_path(args.viewer_output_dir, project_root) if args.viewer_output_dir else None
    mask_source_ply = resolve_project_cli_path(args.mask_source_ply, project_root) if args.mask_source_ply else None
    semantic_output_ply = resolve_project_cli_path(args.semantic_output_ply, project_root) if args.semantic_output_ply else None
    preview_output_dir = resolve_project_cli_path(args.preview_output_dir, project_root) if args.preview_output_dir else None
    semantic_preview_output_dir = resolve_project_cli_path(args.semantic_preview_output_dir, project_root) if args.semantic_preview_output_dir else None
    output_dir = ensure_dir(resolve_project_cli_path(args.report_dir, project_root) if args.report_dir else (project_root / manifest["simulator_assets_dir"] / "3dgs_import"))
    report_path = resolve_project_cli_path(args.output, project_root) if args.output else (output_dir / "import_3dgs_result.json")
    report: dict[str, Any] = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "provider": args.provider,
        "source_path": str(src),
        "requested_splat_ply": str(splat_ply) if splat_ply else None,
        "mode": args.mode,
        "steps": [],
        "status": "running",
        "timestamp": int(time.time()),
    }

    def register_stage() -> None:
        cmd_register_3dgs(
            argparse.Namespace(
                project_root=project_root,
                path=src,
                splat_ply=splat_ply,
                mode=args.mode,
            )
        )

    run_import_3dgs_stage(report, "register_3dgs", register_stage, required=True)
    manifest = load_manifest(project_root)
    active_splat = resolve_existing_path(manifest.get("artifacts", {}).get("scene_3dgs_ply"), project_root)
    report["active_splat_ply"] = str(active_splat) if active_splat else None

    def export_viewer_stage(kind: str) -> None:
        cmd_export_viewer_plys(
            argparse.Namespace(
                project_root=project_root,
                kind=kind,
                splat_ply=None,
                output_dir=viewer_output_dir,
                prefix=None,
                include_labels=False,
            )
        )

    if args.export_viewer_plys:
        run_import_3dgs_stage(report, "export_scene_viewer_plys", lambda: export_viewer_stage("scene"))
    else:
        report["steps"].append({"name": "export_scene_viewer_plys", "status": "skipped", "detail": "--no-export-viewer-plys"})

    def export_semantic_stage() -> None:
        cmd_export_splat_masks(
            argparse.Namespace(
                project_root=project_root,
                splat_ply=None,
                mask_source_ply=mask_source_ply,
                transfer_mode=args.transfer_mode,
                max_transfer_distance=args.max_transfer_distance,
                output=semantic_output_ply,
                include_probabilities=True,
            )
        )

    if args.export_splat_masks:
        run_import_3dgs_stage(report, "export_semantic_splat_masks", export_semantic_stage)
        if args.export_viewer_plys:
            run_import_3dgs_stage(report, "export_all_viewer_plys", lambda: export_viewer_stage("all"))
    else:
        report["steps"].append({"name": "export_semantic_splat_masks", "status": "skipped", "detail": "--no-export-splat-masks"})

    def render_preview_stage() -> None:
        cmd_render_gsplat_preview(
            argparse.Namespace(
                project_root=project_root,
                splat_ply=None,
                frames_dir=args.frames_dir,
                camera_info=args.camera_info,
                output_dir=preview_output_dir,
                max_frames=args.preview_max_frames,
                width=args.preview_width,
                height=args.preview_height,
                device=args.device,
                extrinsic_type=args.extrinsic_type,
                background=args.preview_background,
                error_gain=args.preview_error_gain,
                update_manifest=True,
            )
        )

    if args.render_preview:
        run_import_3dgs_stage(report, "render_gsplat_preview", render_preview_stage)
    else:
        report["steps"].append({"name": "render_gsplat_preview", "status": "skipped", "detail": "--no-render-preview"})

    def render_semantic_stage() -> None:
        cmd_render_semantic_preview(
            argparse.Namespace(
                project_root=project_root,
                semantic_splats_ply=None,
                semantic_manifest=None,
                frames_dir=args.frames_dir,
                camera_info=args.camera_info,
                output_dir=semantic_preview_output_dir,
                max_frames=args.semantic_preview_max_frames,
                max_points_per_frame=args.semantic_preview_max_points,
                point_radius=args.semantic_preview_point_radius,
                alpha=args.semantic_preview_alpha,
                seed=args.semantic_preview_seed,
                extrinsic_type=args.extrinsic_type,
                occlusion_filter=args.semantic_occlusion_filter,
                depth_tolerance=args.semantic_depth_tolerance,
                relative_depth_tolerance=args.semantic_relative_depth_tolerance,
                include_background=args.semantic_include_background,
            )
        )

    if args.render_semantic_preview:
        run_import_3dgs_stage(report, "render_semantic_preview", render_semantic_stage)
    else:
        report["steps"].append({"name": "render_semantic_preview", "status": "skipped", "detail": "--render-semantic-preview not set"})

    manifest = load_manifest(project_root)
    report["artifacts"] = {
        key: manifest.get("artifacts", {}).get(key)
        for key in [
            "scene_3dgs",
            "scene_3dgs_source",
            "scene_3dgs_ply",
            "scene_3dgs_point_cloud_ply",
            "scene_3dgs_supersplat_ply",
            "semantic_splats_ply",
            "semantic_point_cloud_ply",
            "semantic_supersplat_ply",
            "gsplat_preview",
            "semantic_preview",
            "viewer_plys_manifest",
        ]
        if manifest.get("artifacts", {}).get(key)
    }
    failed = [step for step in report["steps"] if step.get("status") == "failed"]
    report["status"] = "completed_with_warnings" if failed else "completed"
    write_json(report_path, report)
    manifest.setdefault("artifacts", {})["3dgs_import_report"] = str(report_path)
    manifest.setdefault("external_stages", {})["video_to_3dgs"] = {
        "status": "3dgs_imported" if not failed else "3dgs_imported_with_warnings",
        "notes": "Registered an external/high-quality 3DGS result and exported viewer/semantic artifacts where possible.",
        "provider": args.provider,
        "source_path": str(src),
        "active_splat_ply": report.get("active_splat_ply"),
        "report": str(report_path),
    }
    save_manifest(project_root, manifest)

    print(f"Imported 3DGS result: {src}")
    print(f"Active splat PLY: {report.get('active_splat_ply')}")
    print(f"Import report: {report_path}")
    if failed:
        print(f"Completed with {len(failed)} warning(s); see report for failed optional stages.")
    return 1 if (failed and args.strict_stage_failures) else 0


def cmd_import_mast3r_slam(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    traj_path = args.trajectory.resolve()
    if not traj_path.exists():
        raise FileNotFoundError(f"MASt3R-SLAM trajectory not found: {traj_path}")
    poses = read_mast3r_slam_traj(traj_path)

    keyframes_dir = args.frames_dir.resolve() if args.frames_dir else None
    intrinsic_dir = keyframes_dir if (args.use_keyframes_as_scene_frames or args.width is None or args.height is None) else None
    intrinsic = estimate_or_read_intrinsic(args, intrinsic_dir)
    extrinsics = {
        pose["frame_id"]: matrix_inverse(pose["camera_to_world"]).tolist()
        for pose in poses
    }
    camera_info = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "source": "mast3r_slam",
        "extrinsic_type": "world_to_camera",
        "intrinsic": intrinsic,
        "extrinsic": extrinsics,
        "timestamps": {pose["frame_id"]: pose["timestamp"] for pose in poses},
        "camera_to_world": {pose["frame_id"]: pose["camera_to_world"] for pose in poses},
        "notes": "MASt3R-SLAM trajectory is imported from timestamp x y z qx qy qz qw T_WC format.",
    }
    camera_info_path = project_root / manifest["scene"]["camera_info"]
    write_json(camera_info_path, camera_info)
    manifest["artifacts"]["camera_info"] = str(camera_info_path)
    manifest["artifacts"]["mast3r_slam_trajectory"] = str(traj_path)
    manifest["artifacts"]["mast3r_slam_pose_count"] = len(poses)
    manifest["external_stages"]["video_to_3dgs"] = {
        "status": "imported_mast3r_slam",
        "notes": "Imported MASt3R-SLAM trajectory, reconstruction PLY, and keyframes when provided. This is a dense SLAM/point-cloud reconstruction stage; register a trained 3DGS separately if needed.",
    }

    if args.reconstruction_ply:
        point_cloud_path = project_root / manifest["scene"]["point_cloud"]
        copy_or_link(args.reconstruction_ply.resolve(), point_cloud_path, args.mode)
        manifest["artifacts"]["point_cloud"] = str(point_cloud_path)

    if keyframes_dir:
        if args.use_keyframes_as_scene_frames:
            dst_dir = project_root / manifest["scene"]["frames_dir"]
            copied = copy_image_dir(keyframes_dir, dst_dir, args.mode, clear=bool(args.clear_keyframes_output))
            manifest["artifacts"]["frames"] = str(dst_dir)
            manifest["artifacts"]["frames_imported"] = copied
        else:
            dst_dir = project_root / MAST3R_KEYFRAMES_DIR
            copied = copy_image_dir(keyframes_dir, dst_dir, args.mode, clear=bool(args.clear_keyframes_output))
            manifest["artifacts"]["mast3r_keyframes"] = str(dst_dir)
            manifest["artifacts"]["mast3r_keyframes_imported"] = copied

    save_manifest(project_root, manifest)
    print(f"Imported MASt3R-SLAM trajectory: {traj_path}")
    print(f"Poses: {len(poses)}")
    if intrinsic.get("estimated"):
        print("Warning: intrinsics are estimated. Pass --fx --fy --cx --cy for calibrated mask projection.")
    return 0


def find_mast3r_slam_outputs(mast3r_root: Path, save_as: str, dataset_path: Path) -> tuple[Path, Path | None, Path | None]:
    log_dir = mast3r_root / "logs" / save_as if save_as != "default" else mast3r_root / "logs"
    seq_name = dataset_path.stem
    trajectory = log_dir / f"{seq_name}.txt"
    reconstruction = log_dir / f"{seq_name}.ply"
    keyframes = log_dir / "keyframes" / seq_name
    if not trajectory.exists():
        candidates = sorted(log_dir.glob("*.txt"), key=lambda p: p.stat().st_mtime, reverse=True) if log_dir.exists() else []
        if len(candidates) == 1:
            trajectory = candidates[0]
            seq_name = trajectory.stem
            reconstruction = log_dir / f"{seq_name}.ply"
            keyframes = log_dir / "keyframes" / seq_name
        else:
            raise FileNotFoundError(f"MASt3R-SLAM trajectory not found: {trajectory}")
    return trajectory, reconstruction if reconstruction.exists() else None, keyframes if keyframes.exists() else None


def cmd_run_mast3r_slam(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    dataset_value = args.dataset or args.video or manifest.get("inputs", {}).get("video")
    if not dataset_value:
        raise ValueError("Pass --dataset/--video or initialize the project with --video.")
    dataset = Path(dataset_value).resolve()
    if not dataset.exists():
        raise FileNotFoundError(f"MASt3R-SLAM dataset/video not found: {dataset}")

    mast3r_root = args.mast3r_root.resolve()
    main_py = mast3r_root / "main.py"
    if not main_py.exists():
        raise FileNotFoundError(f"MASt3R-SLAM main.py not found: {main_py}")

    save_as = args.save_as or manifest["scene_id"]
    command = [
        sys.executable,
        "main.py",
        "--dataset",
        str(dataset),
        "--config",
        str(args.config),
        "--save-as",
        save_as,
        "--no-viz",
    ]
    if args.calib:
        command.extend(["--calib", str(args.calib.resolve())])

    log_path = project_root / "logs" / "mast3r_slam_run.log"
    ensure_dir(log_path.parent)
    print("Running MASt3R-SLAM:")
    print(" ".join(command))
    env = os.environ.copy()
    mast3r_python_paths = [
        str(mast3r_root),
        str(mast3r_root / "thirdparty" / "mast3r"),
        str(mast3r_root / "thirdparty" / "mast3r" / "dust3r"),
    ]
    if env.get("PYTHONPATH"):
        mast3r_python_paths.append(env["PYTHONPATH"])
    env["PYTHONPATH"] = os.pathsep.join(mast3r_python_paths)
    try:
        import torch  # type: ignore

        torch_lib = Path(torch.__file__).resolve().parent / "lib"
        env["LD_LIBRARY_PATH"] = os.pathsep.join([str(torch_lib), env.get("LD_LIBRARY_PATH", "")]).rstrip(os.pathsep)
    except Exception:
        pass
    with log_path.open("w", encoding="utf-8") as log_file:
        completed = subprocess.run(command, cwd=mast3r_root, env=env, stdout=log_file, stderr=subprocess.STDOUT, check=False)
    if completed.returncode != 0:
        print(f"MASt3R-SLAM failed with exit code {completed.returncode}. See log: {log_path}")
        return completed.returncode

    trajectory, reconstruction, keyframes = find_mast3r_slam_outputs(mast3r_root, save_as, dataset)
    manifest = load_manifest(project_root)
    manifest["artifacts"]["mast3r_slam_log"] = str(log_path)
    save_manifest(project_root, manifest)

    import_args = argparse.Namespace(
        project_root=project_root,
        trajectory=trajectory,
        reconstruction_ply=reconstruction,
        frames_dir=keyframes,
        width=args.width,
        height=args.height,
        fx=args.fx,
        fy=args.fy,
        cx=args.cx,
        cy=args.cy,
        focal_scale=args.focal_scale,
        mode=args.mode,
        use_keyframes_as_scene_frames=args.use_keyframes_as_scene_frames,
        clear_keyframes_output=True,
    )
    result = cmd_import_mast3r_slam(import_args)
    print(f"MASt3R-SLAM log: {log_path}")
    return result


@dataclass
class MaskRecord:
    object_id: str
    frame_id: str
    path: Path


def scan_mask_records(mask_root: Path) -> list[MaskRecord]:
    records: list[MaskRecord] = []
    if not mask_root.exists():
        raise FileNotFoundError(f"2D mask root not found: {mask_root}")

    for child in sorted(mask_root.iterdir()):
        if child.is_dir():
            if child.name.startswith("_"):
                continue
            object_id = slugify(child.name)
            for mask_path in sorted(child.iterdir()):
                if mask_path.suffix.lower() in MASK_EXTENSIONS:
                    records.append(MaskRecord(object_id, frame_stem(mask_path.stem), mask_path))
        elif child.is_file() and child.suffix.lower() in MASK_EXTENSIONS:
            match = re.match(r"^(\d+)[_-](.+)$", child.stem)
            if match:
                frame_id, object_id = match.groups()
                records.append(MaskRecord(slugify(object_id), frame_stem(frame_id), child))

    if not records:
        raise FileNotFoundError(
            f"No masks found in {mask_root}. Use <object_id>/<frame>.png or <frame>_<object_id>.png."
        )
    return records


def read_optional_json(path: Path | None) -> Any:
    if path and path.exists():
        return read_json(path)
    return None


def external_segmentation_prompt_objects(prompts_path: Path | None, frames: list[Path]) -> list[dict[str, Any]]:
    if not prompts_path:
        return []
    data = read_json(prompts_path.resolve())
    raw_objects: list[Any]
    if isinstance(data, dict) and isinstance(data.get("objects"), list):
        raw_objects = data["objects"]
    elif isinstance(data, dict):
        raw_objects = []
        for key, value in data.items():
            if not isinstance(value, dict):
                continue
            item = dict(value)
            item.setdefault("id", key)
            raw_objects.append(item)
    elif isinstance(data, list):
        raw_objects = data
    else:
        raise ValueError("Prompt JSON must be a list, an object map, or contain an objects list.")

    objects = []
    fallback_frame = frame_stem(frames[0].stem) if frames else "000000"
    for idx, raw in enumerate(raw_objects):
        if not isinstance(raw, dict):
            continue
        object_id = slugify(raw.get("object_id") or raw.get("id") or raw.get("name") or f"object_{idx:02d}")
        objects.append(
            {
                "object_id": object_id,
                "name": raw.get("name", object_id.replace("_", " ")),
                "category": raw.get("category", "unknown"),
                "description": raw.get("description", ""),
                "frame_id": frame_stem(raw.get("frame_id", raw.get("frame", fallback_frame))),
                "bbox": raw.get("bbox") or raw.get("box"),
                "prompt": raw,
            }
        )
    return objects


def external_mask_entry_value(entry: dict[str, Any]) -> Any:
    return entry.get("mask") or entry.get("mask_path") or entry.get("path") or entry.get("file") or entry.get("index_mask")


def video_segmentation_manifest_template(
    *,
    project_root: Path,
    manifest: dict[str, Any],
    provider: str,
    frames_dir: Path,
    frame_records: list[dict[str, Any]],
    objects: list[dict[str, Any]],
    prompts_path: Path | None,
    mask_output_root: Path,
) -> dict[str, Any]:
    mask_records: list[dict[str, Any]] = []
    for obj_index, obj in enumerate(objects):
        object_id = slugify(obj.get("object_id") or obj.get("id") or obj.get("name") or f"object_{obj_index:03d}")
        for frame in frame_records:
            frame_id = frame_stem(frame.get("frame_id") or frame.get("index") or "000000")
            mask_path = mask_output_root / object_id / f"{frame_id}.png"
            mask_records.append(
                {
                    "object_id": object_id,
                    "frame_id": frame_id,
                    "mask_path": str(mask_path),
                    "image": frame.get("image"),
                    "provider": provider,
                    "status": "pending_external_mask",
                    "source_layout": "binary_mask",
                    "confidence": None,
                }
            )
    return {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "provider": provider,
        "status": "template_pending_external_results",
        "frames_dir": str(frames_dir),
        "prompts": str(prompts_path) if prompts_path else None,
        "mask_root": str(mask_output_root),
        "layout": "binary_per_object_frame",
        "frame_count": len(frame_records),
        "object_count": len(objects),
        "expected_dense_mask_count": len(mask_records),
        "frames": frame_records,
        "objects": objects,
        "masks": mask_records,
        "notes": (
            "Template for external video segmentation results. Fill each mask_path with a binary mask, "
            "or replace this manifest with the provider's completed mask manifest before importing."
        ),
    }


def video_segmentation_mask_manifest_summary(path: Path | None, project_root: Path) -> dict[str, Any]:
    summary: dict[str, Any] = {
        "manifest": str(path) if path else "",
        "manifest_exists": bool(path and path.exists()),
        "mask_record_count": 0,
        "mask_path_count": 0,
        "existing_mask_count": 0,
        "pending_mask_count": 0,
        "object_count": 0,
        "frame_count": 0,
        "expected_dense_mask_count": 0,
    }
    data = safe_read_json(path) if path and path.exists() else None
    if not isinstance(data, (dict, list)):
        return summary
    entries = external_manifest_entries(data)
    source_root = None
    if isinstance(data, dict):
        root_value = data.get("mask_root") or data.get("source_root")
        if root_value:
            source_root = resolve_project_cli_path(Path(str(root_value)), project_root)
        expected_value = data.get("expected_dense_mask_count") or data.get("expected_mask_count")
        try:
            summary["expected_dense_mask_count"] = int(expected_value)
        except Exception:
            summary["expected_dense_mask_count"] = 0
    objects: set[str] = set()
    frames: set[str] = set()
    mask_path_count = 0
    existing_mask_count = 0
    for entry in entries:
        object_id = entry.get("object_id") or entry.get("id") or entry.get("name")
        frame_id = entry.get("frame_id") or entry.get("frame") or entry.get("image_id") or entry.get("index")
        if object_id not in (None, ""):
            objects.add(slugify(str(object_id)))
        if frame_id not in (None, ""):
            frames.add(frame_stem(frame_id))
        mask_value = external_mask_entry_value(entry)
        if not mask_value:
            continue
        mask_path = resolve_external_mask_path(mask_value, source_root, path, project_root)
        mask_path_count += 1
        if mask_path.is_file() and mask_path.suffix.lower() in MASK_EXTENSIONS:
            existing_mask_count += 1
    summary.update(
        {
            "mask_record_count": len(entries),
            "mask_path_count": mask_path_count,
            "existing_mask_count": existing_mask_count,
            "pending_mask_count": max(0, mask_path_count - existing_mask_count),
            "object_count": len(objects),
            "frame_count": len(frames),
        }
    )
    if not summary["expected_dense_mask_count"]:
        summary["expected_dense_mask_count"] = len(entries)
    return summary


def video_segmentation_manifest_has_template_records(path: Path | None, project_root: Path) -> bool:
    summary = video_segmentation_mask_manifest_summary(path, project_root)
    return int(summary.get("mask_record_count") or 0) > 0 and int(summary.get("mask_path_count") or 0) > 0


def video_segmentation_job_spec(
    *,
    project_root: Path,
    manifest: dict[str, Any],
    provider: str,
    frames_dir: Path,
    frame_records: list[dict[str, Any]],
    objects: list[dict[str, Any]],
    prompts_path: Path | None,
    mask_output_root: Path,
    output_dir: Path,
) -> dict[str, Any]:
    provider_slug = slugify(provider, "external")
    mask_root = resolve_active_mask_root(project_root, manifest)
    mask_manifest_path = output_dir / "external_masks_manifest.json"
    mask_manifest_summary = video_segmentation_mask_manifest_summary(mask_manifest_path, project_root)
    baseline_record_count = 0
    baseline_object_count = 0
    try:
        baseline_records = scan_mask_records(mask_root)
        baseline_record_count = len(baseline_records)
        baseline_object_count = len({record.object_id for record in baseline_records})
    except Exception:
        pass
    expected_mask_count = len(frame_records) * len(objects)
    return {
        "input_contract": {
            "frames_dir": str(frames_dir),
            "frame_count": len(frame_records),
            "object_prompt_count": len(objects),
            "expected_dense_mask_count": expected_mask_count,
            "prompts": str(prompts_path) if prompts_path else "",
            "mask_output_root": str(mask_output_root),
            "baseline_mask_root": str(mask_root),
            "baseline_mask_record_count": baseline_record_count,
            "baseline_mask_object_count": baseline_object_count,
            "provider": provider,
            "provider_slug": provider_slug,
            "production_provider_expected": provider_slug in PRODUCTION_VIDEO_SEGMENTATION_PROVIDERS,
        },
        "provider_contract": {
            "accepted_providers": sorted(PRODUCTION_VIDEO_SEGMENTATION_PROVIDERS),
            "recommended_models": [
                "SAM2 video predictor with object prompts propagated across all frames",
                "DEVA or XMem track masks mapped back to Video2Mesh object_id values",
                "Grounded-SAM/Grounded-SAM2 when open-vocabulary detection and segmentation are jointly produced",
            ],
            "baseline_to_replace": "bbox/SAM/OpenCV mask tracking",
            "required_capabilities": [
                "video_consistent_instance_ids",
                "one_mask_per_object_per_frame_or_indexed_track_masks",
                "mask_resolution_matches_or_can_resize_to_frame_resolution",
                "stable_object_identity_across_occlusion",
                "confidence_or_source_metadata_per_track",
            ],
        },
        "expected_output": {
            "mask_root": str(mask_output_root),
            "binary_mask_layouts": [
                "<mask_root>/<object_id>/<frame_id>.png",
                "<mask_root>/<frame_id>/<object_id>.png",
                "<mask_root>/<frame_id>_<object_id>.png",
                "<mask_root>/<object_id>_<frame_id>.png",
            ],
            "indexed_track_layout": {
                "layout": "index",
                "requires_object_id_map": True,
                "description": "DEVA/XMem style per-frame indexed masks plus track_id to object_id map.",
            },
            "manifest": str(mask_manifest_path),
            "manifest_summary": mask_manifest_summary,
            "normalized_import_command": f"python -m video2mesh.cli import-video-segmentation-masks --project-root {project_root} --source-manifest {mask_manifest_path} --provider {provider} --resize-to-frames",
        },
        "quality_targets": {
            "min_coverage_ratio": 0.7,
            "max_area_cv": 1.0,
            "max_center_jump_ratio": 0.35,
            "max_missing_frame_records": 0,
            "max_unreadable_masks": 0,
            "max_unstable_objects_for_production": 0,
            "requires_imported_or_executed_external_stage": True,
        },
        "acceptance_criteria": [
            "External masks cover every foreground object across the expected frame set or explicitly mark valid occlusion gaps.",
            "mask-track-quality-report reports production_tracking before masks are treated as production-ready.",
            "Imported masks use a production provider such as SAM2, DEVA, XMem, Grounded-SAM, or Grounded-SAM2.",
            "The import step records provider/source metadata so baseline bbox/SAM/OpenCV masks are not mistaken for production outputs.",
            "After import, rerun fuse-masks, export-splat-masks, backproject-gaussian-probabilities, render-semantic-preview, evaluate, and production-readiness.",
        ],
        "post_import_validation": {
            "import_binary_masks": f"python -m video2mesh.cli import-video-segmentation-masks --project-root {project_root} --source-root <external_mask_root> --provider {provider} --resize-to-frames",
            "import_index_masks": f"python -m video2mesh.cli import-video-segmentation-masks --project-root {project_root} --source-root <external_index_mask_root> --layout index --object-id-map <track_id_to_object_id.json> --provider {provider} --resize-to-frames",
            "mask_track_quality": f"python -m video2mesh.cli mask-track-quality-report --project-root {project_root} --fail-on-quality-issues --fail-on-baseline",
            "fuse_masks": f"python -m video2mesh.cli fuse-masks --project-root {project_root} --fusion-mode probability --occlusion-filter",
            "refresh_semantic_splats": f"python -m video2mesh.cli export-splat-masks --project-root {project_root}",
            "production_readiness": f"python -m video2mesh.cli production-readiness --project-root {project_root}",
            "showcase_verification": f"python -m video2mesh.cli verify-showcase-pack --project-root {project_root} --fail-on-issues",
        },
    }


def video_segmentation_job_summary_from_job(path: Path | None) -> dict[str, Any]:
    job = safe_read_json(path) if path and path.exists() else None
    if not isinstance(job, dict):
        return {
            "job": str(path) if path else "",
            "job_exists": bool(path and path.exists()),
            "input_contract": {},
            "quality_targets": {},
            "acceptance_criteria_count": 0,
            "post_import_validation_count": 0,
        }
    input_contract = job.get("input_contract") if isinstance(job.get("input_contract"), dict) else {}
    provider_contract = job.get("provider_contract") if isinstance(job.get("provider_contract"), dict) else {}
    quality_targets = job.get("quality_targets") if isinstance(job.get("quality_targets"), dict) else {}
    expected_output = job.get("expected_output") if isinstance(job.get("expected_output"), dict) else {}
    project_root = Path(str(job.get("project_root") or (path.parent if path else "."))).resolve()
    manifest_value = expected_output.get("manifest")
    mask_manifest_path = resolve_project_cli_path(Path(str(manifest_value)), project_root) if manifest_value else None
    mask_manifest_summary = video_segmentation_mask_manifest_summary(mask_manifest_path, project_root)
    if not mask_manifest_summary.get("manifest_exists") and isinstance(expected_output.get("manifest_summary"), dict):
        mask_manifest_summary = expected_output["manifest_summary"]
    return {
        "job": str(path) if path else "",
        "job_exists": True,
        "provider": job.get("provider"),
        "frames_dir": job.get("frames_dir"),
        "frame_count": input_contract.get("frame_count", job.get("frame_count")),
        "object_prompt_count": input_contract.get("object_prompt_count", len(job.get("objects") if isinstance(job.get("objects"), list) else [])),
        "expected_dense_mask_count": input_contract.get("expected_dense_mask_count"),
        "baseline_mask_record_count": input_contract.get("baseline_mask_record_count"),
        "baseline_mask_object_count": input_contract.get("baseline_mask_object_count"),
        "production_provider_expected": input_contract.get("production_provider_expected"),
        "accepted_providers": provider_contract.get("accepted_providers") or [],
        "required_capabilities": provider_contract.get("required_capabilities") or [],
        "quality_targets": quality_targets,
        "expected_output": expected_output,
        "mask_manifest": str(mask_manifest_path) if mask_manifest_path else "",
        "mask_manifest_exists": bool(mask_manifest_path and mask_manifest_path.exists()),
        "mask_manifest_record_count": mask_manifest_summary.get("mask_record_count"),
        "mask_manifest_path_count": mask_manifest_summary.get("mask_path_count"),
        "mask_manifest_existing_mask_count": mask_manifest_summary.get("existing_mask_count"),
        "mask_manifest_pending_mask_count": mask_manifest_summary.get("pending_mask_count"),
        "mask_manifest_object_count": mask_manifest_summary.get("object_count"),
        "mask_manifest_frame_count": mask_manifest_summary.get("frame_count"),
        "acceptance_criteria_count": len(job.get("acceptance_criteria") if isinstance(job.get("acceptance_criteria"), list) else []),
        "post_import_validation_count": len(job.get("post_import_validation") if isinstance(job.get("post_import_validation"), dict) else {}),
    }


def cmd_prepare_video_segmentation_jobs(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    frames_dir = args.frames_dir or (project_root / manifest["scene"]["frames_dir"])
    frames_dir = frames_dir.resolve()
    frames = list_frame_images(frames_dir)
    if args.max_frames and args.max_frames > 0:
        frames = frames[: args.max_frames]
    prompts_path = args.prompts or resolve_existing_path(manifest.get("artifacts", {}).get("tracking_prompts"), project_root)
    prompts = external_segmentation_prompt_objects(prompts_path, frames)
    output_dir = ensure_dir(args.output_dir or (project_root / manifest["simulator_assets_dir"] / "video_segmentation_jobs"))
    job_root = ensure_dir(output_dir / "jobs")
    mask_output_root = args.mask_output_root or (output_dir / "masks")

    frame_records = [
        {
            "frame_id": frame_stem(frame.stem),
            "image": str(frame),
            "index": index,
        }
        for index, frame in enumerate(frames)
    ]
    objects = []
    for prompt in prompts:
        objects.append(
            {
                "object_id": prompt["object_id"],
                "name": prompt.get("name"),
                "category": prompt.get("category"),
                "description": prompt.get("description", ""),
                "prompt_frame": prompt.get("frame_id"),
                "bbox": prompt.get("bbox"),
                "bbox_format": (prompt.get("prompt") or {}).get("bbox_format") or (prompt.get("prompt") or {}).get("format") or "xyxy",
            }
        )

    external_masks_manifest_path = output_dir / "external_masks_manifest.json"
    external_masks_manifest = video_segmentation_manifest_template(
        project_root=project_root,
        manifest=manifest,
        provider=args.provider,
        frames_dir=frames_dir,
        frame_records=frame_records,
        objects=objects,
        prompts_path=prompts_path,
        mask_output_root=mask_output_root,
    )
    write_json(external_masks_manifest_path, external_masks_manifest)

    job = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "provider": args.provider,
        "frames_dir": str(frames_dir),
        "frame_count": len(frame_records),
        "frames": frame_records,
        "prompts": str(prompts_path) if prompts_path else None,
        "objects": objects,
        "expected_output": {
            "mask_root": str(mask_output_root),
            "layout": "masks/<object_id>/<frame_id>.png",
            "manifest": str(external_masks_manifest_path),
        },
        "notes": (
            "Prepared for external video segmentation/tracking tools such as SAM2, DEVA, XMem, or Grounded-SAM. "
            "Run the external tool, then use import-video-segmentation-masks to normalize outputs into masks/2d."
        ),
    }
    job.update(
        video_segmentation_job_spec(
            project_root=project_root,
            manifest=manifest,
            provider=args.provider,
            frames_dir=frames_dir,
            frame_records=frame_records,
            objects=objects,
            prompts_path=prompts_path,
            mask_output_root=mask_output_root,
            output_dir=output_dir,
        )
    )
    job_path = output_dir / "video_segmentation_job.json"
    write_json(job_path, job)
    per_provider_job_path = job_root / f"{slugify(args.provider, 'external')}.json"
    write_json(per_provider_job_path, job)

    command = None
    if args.command_template:
        values = {
            "job_path": str(job_path),
            "project_root": str(project_root),
            "frames_dir": str(frames_dir),
            "prompts": str(prompts_path) if prompts_path else "",
            "mask_output_root": str(mask_output_root),
            "external_masks_manifest": str(external_masks_manifest_path),
            "provider": args.provider,
        }
        command = args.command_template.format(**values)
    script_path = output_dir / "run_video_segmentation.sh"
    script_lines = ["#!/usr/bin/env bash", "set -euo pipefail"]
    if command:
        script_lines.append(command)
    else:
        script_lines.append(f'echo "Fill in external {args.provider} segmentation command for job: {job_path}"')
    script_path.write_text("\n".join(script_lines) + "\n", encoding="utf-8")
    script_path.chmod(0o755)

    manifest.setdefault("artifacts", {})["video_segmentation_job"] = str(job_path)
    manifest.setdefault("artifacts", {})["video_segmentation_external_masks_manifest"] = str(external_masks_manifest_path)
    manifest.setdefault("external_stages", {})["segmentation_2d_tracking"] = {
        "status": "external_video_segmentation_job_prepared",
        "notes": "Prepared external video segmentation job; run/import external masks before fuse-masks.",
        "provider": args.provider,
        "job": str(job_path),
        "script": str(script_path),
        "external_masks_manifest": str(external_masks_manifest_path),
        "mask_output_root": str(mask_output_root),
        "object_count": len(objects),
        "frame_count": len(frame_records),
        "expected_dense_mask_count": len(external_masks_manifest.get("masks", [])),
    }
    save_manifest(project_root, manifest)

    print(f"Prepared external video segmentation job: {job_path}")
    print(f"Frames: {len(frame_records)}; objects/prompts: {len(objects)}")
    print(f"External mask manifest template: {external_masks_manifest_path}")
    print(f"Script: {script_path}")
    return 0


def external_manifest_entries(data: Any) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    if isinstance(data, dict) and isinstance(data.get("masks"), list):
        for item in data["masks"]:
            if isinstance(item, dict):
                entries.append(dict(item))
    elif isinstance(data, dict) and isinstance(data.get("frames"), list):
        for frame in data["frames"]:
            if not isinstance(frame, dict):
                continue
            frame_id = frame.get("frame_id") or frame.get("frame") or frame.get("image_id") or frame.get("index")
            frame_mask = frame.get("index_mask") or frame.get("annotation") or frame.get("annotation_mask") or frame.get("mask")
            frame_items = frame.get("objects") or frame.get("segments") or frame.get("masks") or []
            if isinstance(frame_items, dict):
                frame_items = [{"object_id": key, **(value if isinstance(value, dict) else {"mask": value})} for key, value in frame_items.items()]
            for item in frame_items:
                if not isinstance(item, dict):
                    continue
                record = dict(item)
                record.setdefault("frame_id", frame_id)
                if frame_mask and not any(record.get(key) for key in ("mask", "mask_path", "path", "file", "index_mask", "annotation")):
                    record["index_mask"] = frame_mask
                entries.append(record)
    elif isinstance(data, dict) and isinstance(data.get("objects"), list):
        for obj in data["objects"]:
            if not isinstance(obj, dict):
                continue
            object_id = obj.get("object_id") or obj.get("id") or obj.get("name")
            frames = obj.get("frames") or obj.get("masks") or []
            if isinstance(frames, dict):
                frames = [{"frame_id": key, "mask": value} for key, value in frames.items()]
            for frame in frames:
                if isinstance(frame, dict):
                    item = dict(frame)
                    item.setdefault("object_id", object_id)
                    entries.append(item)
    elif isinstance(data, dict):
        for object_id, frames in data.items():
            if object_id in {"schema_version", "project_root", "scene_id", "notes"}:
                continue
            if isinstance(frames, dict):
                for frame_id, mask in frames.items():
                    entries.append({"object_id": object_id, "frame_id": frame_id, "mask": mask})
            elif isinstance(frames, list):
                for frame in frames:
                    if isinstance(frame, dict):
                        item = dict(frame)
                        item.setdefault("object_id", object_id)
                        entries.append(item)
    elif isinstance(data, list):
        for item in data:
            if isinstance(item, dict):
                entries.append(dict(item))
    return entries


INDEX_MASK_CONTAINER_NAMES = {
    "annotation",
    "annotations",
    "ann",
    "indexed",
    "index_masks",
    "mask",
    "masks",
    "pred",
    "prediction",
    "predictions",
    "result",
    "results",
    "seg",
    "segs",
    "segmentation",
    "segmentations",
}


def looks_like_frame_token(value: Any) -> bool:
    stem = Path(str(value)).stem.lower()
    return bool(re.fullmatch(r"(?:frame|image|img|mask|annotation|ann|seg)?[_-]?\d+", stem))


def normalize_external_frame_id(value: Any) -> str:
    stem = Path(str(value)).stem
    match = re.search(r"(\d+)$", stem)
    return frame_stem(match.group(1)) if match else frame_stem(stem)


def split_external_name_tokens(stem: str) -> list[str]:
    return [token for token in re.split(r"[_\-.]+", stem) if token]


def parse_external_binary_mask_path(path: Path, root: Path) -> dict[str, Any] | None:
    rel = path.relative_to(root)
    parts = list(rel.parts)
    stem = path.stem
    parent = path.parent.name
    object_raw = None
    frame_raw = None

    if len(parts) >= 2 and looks_like_frame_token(stem) and parent.lower() not in INDEX_MASK_CONTAINER_NAMES:
        object_raw = parent
        frame_raw = stem
    elif len(parts) >= 2 and looks_like_frame_token(parent):
        object_raw = stem
        frame_raw = parent
    else:
        tokens = split_external_name_tokens(stem)
        if len(tokens) >= 2 and looks_like_frame_token(tokens[0]):
            frame_raw = tokens[0]
            object_raw = "_".join(tokens[1:])
        elif len(tokens) >= 2 and looks_like_frame_token(tokens[-1]):
            frame_raw = tokens[-1]
            object_raw = "_".join(tokens[:-1])

    if not object_raw or not frame_raw:
        return None
    return {
        "object_id": object_raw,
        "frame_id": normalize_external_frame_id(frame_raw),
        "mask": str(path),
        "source_layout": "binary_mask_path",
    }


def discover_external_binary_mask_entries(mask_root: Path) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for mask_path in sorted(path for path in mask_root.rglob("*") if path.is_file() and path.suffix.lower() in MASK_EXTENSIONS):
        parsed = parse_external_binary_mask_path(mask_path, mask_root)
        if parsed:
            entries.append(parsed)
    if not entries:
        raise FileNotFoundError(
            f"No binary masks found in {mask_root}. Supported layouts include <object_id>/<frame>.png, <frame>/<object_id>.png, <frame>_<object>.png, or <object>_<frame>.png."
        )
    return entries


def load_object_id_map(path: Path | None) -> dict[str, str]:
    if not path:
        return {}
    raw = read_json(path.resolve())
    mapping: dict[str, str] = {}
    if isinstance(raw, dict) and isinstance(raw.get("objects"), list):
        for item in raw["objects"]:
            if not isinstance(item, dict):
                continue
            keys = [item.get("external_id"), item.get("track_id"), item.get("label_id"), item.get("id")]
            object_id = item.get("object_id") or item.get("name")
            if object_id:
                for key in keys:
                    if key not in (None, ""):
                        mapping[str(key)] = slugify(object_id)
    elif isinstance(raw, dict):
        for key, value in raw.items():
            if isinstance(value, dict):
                object_id = value.get("object_id") or value.get("id") or value.get("name")
            else:
                object_id = value
            if object_id not in (None, ""):
                mapping[str(key)] = slugify(str(object_id))
    return mapping


def mapped_external_object_id(raw_value: Any, object_id_map: dict[str, str], prefix: str) -> str:
    if raw_value is None:
        return slugify(prefix)
    if isinstance(raw_value, (list, tuple)):
        key = ",".join(str(int(value)) for value in raw_value)
    else:
        key = str(raw_value)
    for candidate in (key, slugify(key), key.strip()):
        if candidate in object_id_map:
            return slugify(object_id_map[candidate])
    if isinstance(raw_value, int) or (isinstance(raw_value, str) and raw_value.strip().isdigit()):
        return slugify(f"{prefix}_{int(raw_value):03d}")
    if isinstance(raw_value, (list, tuple)):
        return slugify(f"{prefix}_rgb_{'_'.join(str(int(value)) for value in raw_value[:3])}")
    return slugify(f"{prefix}_{key}")


def parse_background_label_values(value: str) -> set[str]:
    labels: set[str] = set()
    for item in str(value or "").split(","):
        item = item.strip()
        if not item:
            continue
        labels.add(item)
        if item.isdigit():
            labels.add(str(int(item)))
    return labels


def index_label_key(value: Any) -> str:
    if isinstance(value, (list, tuple)):
        return ",".join(str(int(item)) for item in value)
    return str(int(value)) if isinstance(value, int) else str(value)


def infer_index_mask_frame_id(path: Path, root: Path) -> str:
    rel = path.relative_to(root)
    stem = path.stem
    parent = path.parent.name
    if looks_like_frame_token(stem):
        return normalize_external_frame_id(stem)
    if looks_like_frame_token(parent):
        return normalize_external_frame_id(parent)
    match = re.search(r"(\d+)", stem)
    return frame_stem(match.group(1)) if match else frame_stem(stem)


def unique_index_label_values(mask_path: Path) -> list[Any]:
    cv2 = import_cv2()
    np = import_numpy()
    image = cv2.imread(str(mask_path), cv2.IMREAD_UNCHANGED)
    if image is None:
        raise RuntimeError(f"Failed to read index mask: {mask_path}")
    if image.ndim == 2:
        return [int(value) for value in np.unique(image)]
    channels = image[:, :, :3].reshape(-1, 3)
    values = np.unique(channels, axis=0)
    return [[int(channel) for channel in value.tolist()] for value in values]


def discover_external_index_mask_entries(mask_root: Path, object_id_map: dict[str, str], prefix: str, background_values: set[str], min_area: int) -> list[dict[str, Any]]:
    cv2 = import_cv2()
    np = import_numpy()
    entries: list[dict[str, Any]] = []
    for mask_path in sorted(path for path in mask_root.rglob("*") if path.is_file() and path.suffix.lower() in MASK_EXTENSIONS):
        image = cv2.imread(str(mask_path), cv2.IMREAD_UNCHANGED)
        if image is None:
            continue
        frame_id = infer_index_mask_frame_id(mask_path, mask_root)
        for label_value in unique_index_label_values(mask_path):
            key = index_label_key(label_value)
            if key in background_values:
                continue
            if isinstance(label_value, list):
                selector = np.all(image[:, :, :3] == np.asarray(label_value, dtype=image.dtype).reshape(1, 1, 3), axis=2)
            else:
                selector = image == int(label_value)
            area = int(selector.sum())
            if area < int(min_area):
                continue
            entries.append(
                {
                    "object_id": mapped_external_object_id(label_value, object_id_map, prefix),
                    "frame_id": frame_id,
                    "index_mask": str(mask_path),
                    "label_value": label_value,
                    "mask_area": area,
                    "source_layout": "index_mask",
                }
            )
    if not entries:
        raise FileNotFoundError(f"No non-background labels found in index masks under {mask_root}.")
    return entries


def resolve_external_mask_path(mask_value: Any, source_root: Path | None, source_manifest_path: Path | None, project_root: Path) -> Path:
    mask_path = Path(str(mask_value))
    if mask_path.is_absolute():
        return mask_path
    if source_root and (source_root / mask_path).exists():
        return source_root / mask_path
    if source_manifest_path and (source_manifest_path.parent / mask_path).exists():
        return source_manifest_path.parent / mask_path
    return (source_root or project_root) / mask_path


def binary_mask_from_image(mask_path: Path, threshold: int):
    cv2 = import_cv2()
    np = import_numpy()
    image = cv2.imread(str(mask_path), cv2.IMREAD_UNCHANGED)
    if image is None:
        raise RuntimeError(f"Failed to read mask: {mask_path}")
    if image.ndim == 3:
        image = cv2.cvtColor(image[:, :, :3], cv2.COLOR_BGR2GRAY)
    if int(image.max()) <= 1:
        binary = image > 0
    else:
        binary = image >= int(threshold)
    return binary.astype(np.uint8) * 255


def binary_mask_from_index_label(mask_path: Path, label_value: Any):
    cv2 = import_cv2()
    np = import_numpy()
    image = cv2.imread(str(mask_path), cv2.IMREAD_UNCHANGED)
    if image is None:
        raise RuntimeError(f"Failed to read index mask: {mask_path}")
    if isinstance(label_value, list):
        if image.ndim < 3:
            raise ValueError(f"RGB label {label_value} cannot be selected from single-channel mask: {mask_path}")
        selector = np.all(image[:, :, :3] == np.asarray(label_value, dtype=image.dtype).reshape(1, 1, 3), axis=2)
    else:
        selector = image == int(label_value)
    return selector.astype(np.uint8) * 255


def frame_size_lookup(project_root: Path, manifest: dict[str, Any]) -> dict[str, tuple[int, int]]:
    cv2 = import_cv2()
    frames_dir = resolve_project_frames_dir(project_root, manifest)
    sizes: dict[str, tuple[int, int]] = {}
    if not frames_dir.exists():
        return sizes
    for frame_path in list_frame_images(frames_dir):
        image = cv2.imread(str(frame_path), cv2.IMREAD_UNCHANGED)
        if image is None:
            continue
        height, width = image.shape[:2]
        sizes[frame_stem(frame_path.stem)] = (int(width), int(height))
    return sizes


def resize_mask_to_frame(mask, frame_id: str, sizes: dict[str, tuple[int, int]], enabled: bool) -> tuple[Any, dict[str, Any]]:
    cv2 = import_cv2()
    original_height, original_width = mask.shape[:2]
    target = sizes.get(frame_stem(frame_id))
    resize_info = {
        "original_size": [int(original_width), int(original_height)],
        "target_size": list(target) if target else None,
        "resized": False,
    }
    if enabled and target and (int(original_width), int(original_height)) != target:
        mask = cv2.resize(mask, target, interpolation=cv2.INTER_NEAREST)
        resize_info["resized"] = True
    return mask, resize_info


def cmd_import_video_segmentation_masks(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    source_root = args.source_root.resolve() if args.source_root else None
    source_manifest_path = args.source_manifest.resolve() if args.source_manifest else None
    output_root = args.output_dir or (project_root / manifest["masks"]["mask_2d_dir"])
    output_root = resolve_project_cli_path(output_root, project_root)
    if args.clear_output and output_root.exists():
        shutil.rmtree(output_root)
    output_root = ensure_dir(output_root)

    imported: dict[str, Any] = {}
    missing: list[dict[str, Any]] = []
    entries: list[dict[str, Any]] = []
    import_layout = args.layout
    object_id_map = load_object_id_map(args.object_id_map)
    target_frame_sizes = frame_size_lookup(project_root, manifest) if args.resize_to_frames else {}
    source_manifest = read_optional_json(source_manifest_path)
    if source_manifest is not None:
        entries = external_manifest_entries(source_manifest)
    elif source_root:
        if args.layout == "index":
            entries = discover_external_index_mask_entries(
                source_root,
                object_id_map,
                args.object_prefix,
                parse_background_label_values(args.background_labels),
                args.min_area,
            )
        elif args.layout == "binary":
            entries = discover_external_binary_mask_entries(source_root)
        else:
            try:
                entries = discover_external_binary_mask_entries(source_root)
                import_layout = "binary"
            except FileNotFoundError:
                entries = discover_external_index_mask_entries(
                    source_root,
                    object_id_map,
                    args.object_prefix,
                    parse_background_label_values(args.background_labels),
                    args.min_area,
                )
                import_layout = "index"
    else:
        raise ValueError("Pass --source-root or --source-manifest.")

    for index, entry in enumerate(entries):
        raw_named_object_id = entry.get("object_id") or entry.get("name")
        if raw_named_object_id not in (None, ""):
            object_id = slugify(object_id_map.get(str(raw_named_object_id), str(raw_named_object_id)))
        else:
            raw_external_id = entry.get("track_id") or entry.get("label_id") or entry.get("id")
            object_id = mapped_external_object_id(raw_external_id, object_id_map, args.object_prefix) if raw_external_id not in (None, "") else slugify(f"{args.object_prefix}_{index:03d}")
        frame_id = frame_stem(entry.get("frame_id") or entry.get("frame") or entry.get("image_id") or entry.get("index") or "000000")
        mask_value = entry.get("mask") or entry.get("mask_path") or entry.get("path") or entry.get("file")
        index_mask_value = entry.get("index_mask") or entry.get("annotation") or entry.get("annotation_mask")
        label_value = entry.get("label_value")
        if label_value is None:
            label_value = entry.get("label") or entry.get("label_id") or entry.get("track_id") or entry.get("segment_id")
        if label_value is not None and isinstance(label_value, str) and "," in label_value:
            try:
                label_value = [int(part.strip()) for part in label_value.split(",")]
            except Exception:
                pass
        if label_value is not None and not isinstance(label_value, list):
            try:
                label_value = int(label_value)
            except Exception:
                pass
        if not mask_value and index_mask_value and label_value is not None:
            mask_value = index_mask_value
        if not mask_value:
            missing.append({"entry": entry, "reason": "missing_mask_path"})
            continue
        mask_path = resolve_external_mask_path(mask_value, source_root, source_manifest_path, project_root)
        if not mask_path.exists():
            missing.append({"object_id": object_id, "frame_id": frame_id, "mask": str(mask_path), "reason": "not_found"})
            if not args.skip_missing:
                raise FileNotFoundError(f"External mask not found: {mask_path}")
            continue
        if mask_path.suffix.lower() not in MASK_EXTENSIONS:
            missing.append({"object_id": object_id, "frame_id": frame_id, "mask": str(mask_path), "reason": "unsupported_extension"})
            if not args.skip_missing:
                raise ValueError(f"Unsupported mask extension: {mask_path}")
            continue
        dst = output_root / object_id / f"{frame_id}.png"
        if index_mask_value or entry.get("source_layout") == "index_mask" or label_value is not None and args.layout == "index":
            if label_value is None:
                missing.append({"object_id": object_id, "frame_id": frame_id, "mask": str(mask_path), "reason": "missing_index_label"})
                if not args.skip_missing:
                    raise ValueError(f"Missing label_value for index mask entry: {entry}")
                continue
            mask = binary_mask_from_index_label(mask_path, label_value)
            source_layout = "index_mask"
        else:
            mask = binary_mask_from_image(mask_path, args.mask_threshold)
            source_layout = entry.get("source_layout") or "binary_mask"
        mask, resize_info = resize_mask_to_frame(mask, frame_id, target_frame_sizes, args.resize_to_frames)
        ensure_dir(dst.parent)
        import_cv2().imwrite(str(dst), mask)
        copied = dst
        imported.setdefault(object_id, {"frames": []})
        imported[object_id]["frames"].append(
            {
                "frame_id": frame_id,
                "source_mask": str(mask_path),
                "mask": str(copied),
                "score": entry.get("score") or entry.get("confidence"),
                "bbox": entry.get("bbox"),
                "label_value": label_value,
                "source_layout": source_layout,
                "mask_area": int((mask >= 128).sum()) if "mask" in locals() else entry.get("mask_area"),
                "resize": resize_info,
            }
        )
        try:
            del mask
        except Exception:
            pass

    tracking_manifest = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "method": "external_video_segmentation_import",
        "provider": args.provider,
        "source_root": str(source_root) if source_root else None,
        "source_manifest": str(source_manifest_path) if source_manifest_path else None,
        "source_layout": import_layout,
        "mask_root": str(output_root),
        "resize_to_frames": bool(args.resize_to_frames),
        "target_frame_count": len(target_frame_sizes),
        "objects": {
            object_id: {
                "frames_written": len(record["frames"]),
                "frames": record["frames"],
            }
            for object_id, record in sorted(imported.items())
        },
        "missing": missing,
        "notes": "External video segmentation masks normalized to Video2Mesh masks/2d layout.",
    }
    tracking_manifest_path = output_root / "tracking_manifest.json"
    write_json(tracking_manifest_path, tracking_manifest)
    manifest.setdefault("artifacts", {})["object_masks_2d"] = str(output_root)
    manifest.setdefault("artifacts", {})["mask_tracking_manifest"] = str(tracking_manifest_path)
    manifest.setdefault("external_stages", {})["segmentation_2d_tracking"] = {
        "status": "external_video_segmentation_masks_imported",
        "notes": "Imported external video segmentation masks into standard Video2Mesh masks/2d layout.",
        "provider": args.provider,
        "source_layout": import_layout,
        "resize_to_frames": bool(args.resize_to_frames),
        "object_count": len(imported),
        "mask_count": sum(len(record["frames"]) for record in imported.values()),
        "missing_count": len(missing),
    }
    save_manifest(project_root, manifest)

    total = sum(len(record["frames"]) for record in imported.values())
    print(f"Imported {total} external 2D mask(s) for {len(imported)} object(s) into {output_root}")
    if missing:
        print(f"Missing/skipped entries: {len(missing)}")
    print(f"Tracking manifest: {tracking_manifest_path}")
    return 0


