def production_gate_pending(stage: str, status: str, reason: str) -> dict[str, Any]:
    return {
        "stage": stage,
        "status": "pending",
        "production_validated": False,
        "reason": reason or status,
        "checks": {},
    }


def path_from_check(check: dict[str, Any], key: str, project_root: Path) -> Path | None:
    value = check.get(key)
    if not value:
        return None
    try:
        return resolve_project_cli_path(Path(str(value)), project_root)
    except Exception:
        return Path(str(value))


def production_quality_gate_for_check(check: dict[str, Any], project_root: Path, jobs_root: Path) -> dict[str, Any]:
    stage = str(check.get("name") or "")
    status = str(check.get("status") or "")
    reason = str(check.get("reason") or "")
    if status != "ready_to_import":
        return production_gate_pending(stage, status, reason)

    if stage == "high_quality_3dgs":
        result_path = path_from_check(check, "result_path", project_root)
        try:
            splat_ply = find_latest_splat_ply(result_path) if result_path else None
            summary = summarize_ply_contract(
                splat_ply,
                {"x", "y", "z", "f_dc_0", "f_dc_1", "f_dc_2", "opacity", "scale_0", "scale_1", "scale_2", "rot_0", "rot_1", "rot_2", "rot_3"},
                set(),
            )
            importable = bool(summary.get("exists") and summary.get("ok") and int(summary.get("vertex_count") or 0) > 0)
        except Exception as exc:
            splat_ply = None
            summary = {"error": str(exc)}
            importable = False
        return {
            "stage": stage,
            "status": "import_ready_quality_pending" if importable else "invalid_result",
            "production_validated": False,
            "reason": "splat_importable_but_visual_quality_requires_post_import_preview" if importable else "splat_contract_failed",
            "checks": {"splat_ply": str(splat_ply) if splat_ply else "", "ply_contract": summary},
        }

    if stage == "open_vocab_detection":
        path = path_from_check(check, "result_path", project_root)
        entries = []
        if path and path.exists():
            try:
                entries = detection_entries(read_json(path))
            except Exception:
                entries = []
        bbox_count = len([item for item in entries if item.get("bbox")])
        label_count = len([item for item in entries if item.get("label") or item.get("category")])
        score_count = len([item for item in entries if item.get("score") not in (None, "")])
        frame_count = len([item for item in entries if item.get("frame_id") or item.get("image")])
        ok = bool(entries and bbox_count == len(entries) and label_count == len(entries) and frame_count == len(entries) and score_count > 0)
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "detections_have_required_fields" if ok else "detections_missing_required_fields",
            "checks": {
                "detection_count": len(entries),
                "with_bbox": bbox_count,
                "with_label_or_category": label_count,
                "with_score": score_count,
                "with_frame_or_image": frame_count,
            },
        }

    if stage == "video_segmentation":
        path = path_from_check(check, "result_path", project_root)
        root = path_from_check(check, "result_root", project_root)
        existing_masks = 0
        object_ids: set[str] = set()
        frame_ids: set[str] = set()
        if path and path.exists():
            try:
                source_manifest = read_json(path)
                source_root = None
                if isinstance(source_manifest, dict):
                    root_value = source_manifest.get("mask_root") or source_manifest.get("source_root")
                    if root_value:
                        source_root = Path(str(root_value))
                        if not source_root.is_absolute():
                            source_root = (path.parent / source_root).resolve()
                for entry in external_manifest_entries(source_manifest):
                    object_id = entry.get("object_id") or entry.get("id") or entry.get("label")
                    frame_id = entry.get("frame_id") or entry.get("frame") or entry.get("image")
                    if object_id:
                        object_ids.add(str(object_id))
                    if frame_id:
                        frame_ids.add(str(frame_id))
                    mask_value = external_mask_entry_value(entry)
                    if mask_value:
                        mask_path = resolve_external_mask_path(mask_value, source_root, path, path.parent)
                        if mask_path.is_file() and mask_path.suffix.lower() in MASK_EXTENSIONS:
                            existing_masks += 1
            except Exception:
                existing_masks = 0
        if root and root.exists():
            existing_masks = max(existing_masks, len([p for p in root.rglob("*") if p.is_file() and p.suffix.lower() in MASK_EXTENSIONS]))
        ok = existing_masks > 0 and len(object_ids) > 0
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "external_masks_exist" if ok else "mask_records_missing_object_or_file_evidence",
            "checks": {"existing_mask_files": existing_masks, "object_count": len(object_ids), "frame_count": len(frame_ids)},
        }

    if stage == "object_labels":
        path = path_from_check(check, "result_path", project_root)
        production_count = 0
        total = 0
        if path and path.exists():
            try:
                updates = load_object_label_updates(path)
                total = len(updates)
                production_count = len([label for label in updates.values() if label_record_is_production_result(label)])
            except Exception:
                pass
        ok = production_count > 0 and production_count == total
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "all_labels_production_quality" if ok else "some_labels_not_production_quality",
            "checks": {"label_count": total, "production_label_count": production_count},
        }

    if stage == "scene_structure":
        path = path_from_check(check, "result_path", project_root)
        entries = []
        if path and path.exists():
            try:
                entries = scene_structure_entries(read_json(path))
            except Exception:
                entries = []
        with_indices = [
            item
            for item in entries
            if item.get("point_indices") or item.get("point_ids") or item.get("indices") or item.get("point_indices_json") or item.get("point_indices_npy")
        ]
        categories = {str(item.get("category") or item.get("label") or item.get("name") or "") for item in with_indices}
        ok = bool(with_indices)
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "scene_structure_indices_present" if ok else "no_scene_structure_indices",
            "checks": {"structure_count": len(entries), "with_indices": len(with_indices), "categories": sorted(item for item in categories if item)},
        }

    if stage == "object_meshes":
        manifest_path = path_from_check(check, "result_path", project_root)
        root = path_from_check(check, "result_root", project_root)
        entries = load_external_mesh_manifest(manifest_path, project_root) if manifest_path and manifest_path.exists() else {}
        if not entries and root and root.exists():
            mesh_files = [p for p in root.rglob("*") if p.is_file() and p.suffix.lower() in MODEL_EXTENSIONS]
            entries = {path.stem: {"object_id": path.stem, "mesh_path": str(path)} for path in mesh_files}
        existing = [record for record in entries.values() if Path(str(record.get("mesh_path") or "")).is_file()]
        with_provider = [record for record in existing if record.get("provider")]
        with_frame = [record for record in existing if record.get("coordinate_frame")]
        ok = bool(existing and len(with_provider) == len(existing) and len(with_frame) == len(existing))
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "external_meshes_have_metadata" if ok else "external_mesh_metadata_incomplete",
            "checks": {"mesh_count": len(existing), "with_provider": len(with_provider), "with_coordinate_frame": len(with_frame)},
        }

    if stage == "scale_calibration":
        path = path_from_check(check, "result_path", project_root)
        reference = normalize_scale_calibration_reference(read_json(path)) if path and path.exists() else None
        ok = reference is not None
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "scale_reference_found" if ok else "scale_reference_missing",
            "checks": {
                "reference_object": reference.get("reference_object") if reference else None,
                "reference_length_m": reference.get("reference_length_m") if reference else None,
                "scale_to_meters": reference.get("scale_to_meters") if reference else None,
                "confidence": reference.get("confidence") if reference else None,
            },
        }

    if stage == "simulator_physics":
        path = path_from_check(check, "result_path", project_root)
        entries = physics_entries(read_json(path)) if path and path.exists() else []
        with_object = [item for item in entries if item.get("object_id") or item.get("id") or item.get("name")]
        with_mass = [item for item in entries if item.get("mass_kg") not in (None, "", 0) or item.get("density_kg_m3") not in (None, "", 0)]
        with_body = [item for item in entries if item.get("body_type") not in (None, "")]
        with_collider = [item for item in entries if item.get("collider") not in (None, "")]
        with_material = [item for item in entries if item.get("material") not in (None, "", {}, []) or item.get("friction") not in (None, "", [], {})]
        ok = bool(entries and len(with_object) == len(entries) and with_mass and with_body and with_collider and with_material)
        return {
            "stage": stage,
            "status": "production_validated" if ok else "import_ready_quality_warning",
            "production_validated": ok,
            "reason": "physics_records_have_required_fields" if ok else "physics_records_missing_required_fields",
            "checks": {
                "record_count": len(entries),
                "with_object_id": len(with_object),
                "with_mass_or_density": len(with_mass),
                "with_body_type": len(with_body),
                "with_collider": len(with_collider),
                "with_material_or_friction": len(with_material),
            },
        }

    return production_gate_pending(stage, status, reason)


def attach_production_quality_gates(checks: list[dict[str, Any]], project_root: Path, jobs_root: Path) -> None:
    for check in checks:
        if not isinstance(check, dict):
            continue
        stage = str(check.get("name") or "")
        check["acceptance_criteria"] = production_stage_acceptance_criteria(stage)
        check["quality_gate"] = production_quality_gate_for_check(check, project_root, jobs_root)


def production_upgrade_prepared_stages(jobs_root: Path) -> dict[str, dict[str, Any]]:
    report_path = jobs_root / "production_upgrade_jobs.json"
    data = safe_read_json(report_path)
    if not isinstance(data, dict) or not isinstance(data.get("stages"), list):
        return {}
    result = {}
    for stage in data["stages"]:
        if isinstance(stage, dict) and stage.get("name"):
            result[str(stage["name"])] = stage
    return result


def prepared_status_for(stages: dict[str, dict[str, Any]], name: str) -> str | None:
    stage = stages.get(name)
    if not isinstance(stage, dict):
        return None
    return str(stage.get("status") or "")


def infer_prepared_3dgs_result_path(jobs_root: Path, project_root: Path, explicit: Path | None) -> tuple[Path | None, str | None]:
    if explicit:
        return resolve_project_cli_path(explicit, project_root), None
    job_path = jobs_root / "high_quality_3dgs" / "high_quality_3dgs_job.json"
    provider = None
    if job_path.exists():
        try:
            job = read_json(job_path)
            provider = job.get("provider")
            if job.get("output_path"):
                return resolve_project_cli_path(Path(str(job["output_path"])), project_root), provider
        except Exception:
            return None, provider
    return None, provider


def infer_mesh_manifest_path(jobs_root: Path, project_root: Path, explicit: Path | None) -> Path | None:
    if explicit:
        return resolve_project_cli_path(explicit, project_root)
    for candidate in [
        jobs_root / "multiview_mesh_jobs" / "mesh_manifest.json",
        jobs_root / "multiview_mesh_jobs" / "multiview_mesh_manifest.json",
        jobs_root / "multiview_mesh_jobs" / "multiview_mesh_jobs.json",
    ]:
        if candidate.exists():
            return candidate
    return None


def mesh_manifest_has_template_records(path: Path | None) -> bool:
    if not path or not path.exists():
        return False
    data = safe_read_json(path)
    if not isinstance(data, (dict, list)):
        return False
    return len(external_mesh_manifest_entries(data)) > 0


def count_present_fields(records: list[dict[str, Any]], fields: list[str]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for field in fields:
        present = 0
        for record in records:
            value: Any = record
            for part in field.split("."):
                if isinstance(value, dict):
                    value = value.get(part)
                else:
                    value = None
                    break
            if value not in (None, "", [], {}):
                present += 1
        counts[field] = present
    return counts


def production_result_contract(stage: str, check: dict[str, Any], project_root: Path, jobs_root: Path) -> dict[str, Any]:
    status = str(check.get("status") or "")
    path = path_from_check(check, "result_path", project_root) or path_from_check(check, "expected_path", project_root)
    root = path_from_check(check, "result_root", project_root) or path_from_check(check, "expected_root", project_root)
    contract: dict[str, Any] = {
        "stage": stage,
        "status": status,
        "ready_to_import": status == "ready_to_import",
        "path": str(path) if path else "",
        "path_exists": bool(path and path.exists()),
        "root": str(root) if root else "",
        "root_exists": bool(root and root.exists()),
        "diagnostics": {},
        "missing_requirements": [],
        "next_action": production_stage_next_step(check),
    }

    if stage == "high_quality_3dgs":
        candidate = path or (jobs_root / "high_quality_3dgs" / "output")
        splat_candidates = []
        if candidate and candidate.exists():
            try:
                splat_candidates = [str(find_latest_splat_ply(candidate))]
            except Exception:
                splat_candidates = []
        contract["diagnostics"] = {"expected_result_path": str(candidate), "splat_candidates": splat_candidates}
        if not candidate or not candidate.exists():
            contract["missing_requirements"].append("external_3dgs_output_path")
        if not splat_candidates:
            contract["missing_requirements"].append("gaussian_splat_ply")
        return contract

    if stage == "open_vocab_detection":
        data = safe_read_json(path) if path and path.exists() else None
        entries = detection_entries(data) if isinstance(data, (dict, list)) else []
        requests = data.get("detection_requests") if isinstance(data, dict) and isinstance(data.get("detection_requests"), list) else []
        field_counts = count_present_fields(entries, ["frame_id", "image", "label", "category", "bbox", "score"])
        contract["diagnostics"] = {
            "detection_count": len(entries),
            "request_count": len(requests),
            "field_counts": field_counts,
            "pending_request_count": max(0, len(requests) - len(entries)),
        }
        if not entries:
            contract["missing_requirements"].append("filled_detections")
        for field in ["frame_id", "bbox", "score"]:
            if entries and field_counts.get(field, 0) < len(entries):
                contract["missing_requirements"].append(f"detection.{field}")
        return contract

    if stage == "video_segmentation":
        data = safe_read_json(path) if path and path.exists() else None
        summary = video_segmentation_mask_manifest_summary(path, project_root) if path else {}
        expected = int(summary.get("expected_dense_mask_count") or summary.get("mask_record_count") or 0)
        existing = int(summary.get("existing_mask_count") or 0)
        pending = max(0, expected - existing)
        contract["diagnostics"] = {**summary, "pending_mask_count": pending}
        if expected <= 0:
            contract["missing_requirements"].append("mask_records")
        if pending > 0:
            contract["missing_requirements"].append("external_mask_files")
        if isinstance(data, dict) and str(data.get("status") or "").startswith("template"):
            contract["missing_requirements"].append("provider_completed_manifest_status")
        return contract

    if stage == "object_labels":
        updates = load_object_label_updates(path) if path and path.exists() else {}
        labels = list(updates.values())
        production = [item for item in labels if label_record_is_production_result(item)]
        field_counts = count_present_fields(labels, ["object_id", "name", "category", "description", "confidence", "source"])
        contract["diagnostics"] = {
            "label_count": len(labels),
            "production_label_count": len(production),
            "field_counts": field_counts,
            "non_production_label_count": max(0, len(labels) - len(production)),
        }
        if not labels:
            contract["missing_requirements"].append("label_records")
        if len(production) < len(labels):
            contract["missing_requirements"].append("production_label_source_or_evidence")
        return contract

    if stage == "scene_structure":
        data = safe_read_json(path) if path and path.exists() else None
        entries = scene_structure_entries(data) if isinstance(data, (dict, list)) else []
        with_indices = [
            item
            for item in entries
            if item.get("point_indices") or item.get("point_ids") or item.get("indices") or item.get("point_indices_json") or item.get("point_indices_npy")
        ]
        categories = sorted({str(item.get("category") or item.get("label") or item.get("name") or "") for item in entries if item})
        contract["diagnostics"] = {
            "structure_count": len(entries),
            "with_indices": len(with_indices),
            "categories": [item for item in categories if item],
        }
        if not entries:
            contract["missing_requirements"].append("structure_records")
        if len(with_indices) < len(entries):
            contract["missing_requirements"].append("point_indices")
        return contract

    if stage == "object_meshes":
        entries = load_external_mesh_manifest(path, project_root) if path and path.exists() else {}
        records = list(entries.values())
        existing = [record for record in records if Path(str(record.get("mesh_path") or "")).is_file()]
        field_counts = count_present_fields(records, ["object_id", "mesh_path", "provider", "coordinate_frame"])
        contract["diagnostics"] = {
            "mesh_record_count": len(records),
            "existing_mesh_count": len(existing),
            "pending_mesh_count": max(0, len(records) - len(existing)),
            "field_counts": field_counts,
        }
        if not records:
            contract["missing_requirements"].append("mesh_records")
        if len(existing) < len(records):
            contract["missing_requirements"].append("mesh_files")
        for field in ["provider", "coordinate_frame"]:
            if records and field_counts.get(field, 0) < len(records):
                contract["missing_requirements"].append(f"mesh.{field}")
        return contract

    if stage == "scale_calibration":
        data = safe_read_json(path) if path and path.exists() else None
        reference = normalize_scale_calibration_reference(data)
        candidates = scale_calibration_reference_candidates(data) if isinstance(data, (dict, list)) else []
        contract["diagnostics"] = {
            "candidate_count": len(candidates),
            "reference_filled": reference is not None,
            "reference": reference,
        }
        if reference is None:
            contract["missing_requirements"].append("reference_length_m_or_scale_to_meters")
        return contract

    if stage == "simulator_physics":
        data = safe_read_json(path) if path and path.exists() else None
        entries = physics_entries(data) if isinstance(data, (dict, list)) else []
        field_counts = count_present_fields(entries, ["object_id", "body_type", "collider", "mass_kg", "density_kg_m3", "material", "friction", "restitution"])
        filled = physics_result_has_filled_values(path) if path and path.exists() else False
        contract["diagnostics"] = {
            "physics_record_count": len(entries),
            "field_counts": field_counts,
            "filled_result_ready": filled,
        }
        if not entries:
            contract["missing_requirements"].append("physics_records")
        if not filled:
            contract["missing_requirements"].append("measured_or_reviewed_physics_values")
        return contract

    if stage == "sceneversepp":
        metadata_files = sorted((root or (jobs_root / "sceneversepp_jobs")).glob("svpp_data/*/metadata.json")) if (root or (jobs_root / "sceneversepp_jobs")).exists() else []
        contract["diagnostics"] = {
            "svpp_metadata_file_count": len(metadata_files),
            "metadata_files": [str(item) for item in metadata_files[:10]],
            "bridge_only": True,
        }
        if not metadata_files:
            contract["missing_requirements"].append("svpp_metadata")
        contract["missing_requirements"].append("external_sceneversepp_execution_result")
        return contract

    return contract


def attach_production_result_contracts(checks: list[dict[str, Any]], project_root: Path, jobs_root: Path) -> None:
    for check in checks:
        if not isinstance(check, dict):
            continue
        stage = str(check.get("name") or "")
        check["result_contract"] = production_result_contract(stage, check, project_root, jobs_root)


def cmd_verify_production_upgrade_results(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = project_root / manifest["simulator_assets_dir"] / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else jobs_root / "production_upgrade_results_verification.json"
    prepared_stages = production_upgrade_prepared_stages(jobs_root)
    checks: list[dict[str, Any]] = []

    g3dgs_path, g3dgs_provider = infer_prepared_3dgs_result_path(jobs_root, project_root, args.g3dgs_path)
    if not g3dgs_path:
        checks.append(
            production_stage_status(
                "high_quality_3dgs",
                "missing_result",
                "missing_result_path",
                prepared_status=prepared_status_for(prepared_stages, "high_quality_3dgs"),
                expected_path=jobs_root / "high_quality_3dgs" / "high_quality_3dgs_job.json",
                import_command="import-3dgs-result",
            )
        )
    elif not g3dgs_path.exists():
        checks.append(
            production_stage_status(
                "high_quality_3dgs",
                "missing_result",
                "path_does_not_exist",
                prepared_status=prepared_status_for(prepared_stages, "high_quality_3dgs"),
                expected_path=g3dgs_path,
                import_command="import-3dgs-result",
            )
        )
    elif not gsplat_result_has_ply(args.g3dgs_splat_ply or g3dgs_path):
        checks.append(
            production_stage_status(
                "high_quality_3dgs",
                "invalid_result",
                "no_splat_ply_found",
                prepared_status=prepared_status_for(prepared_stages, "high_quality_3dgs"),
                result_path=g3dgs_path,
                detail=f"provider={g3dgs_provider or args.g3dgs_provider or 'external_3dgs'}",
                import_command="import-3dgs-result",
            )
        )
    else:
        checks.append(
            production_stage_status(
                "high_quality_3dgs",
                "ready_to_import",
                "splat_ply_found",
                prepared_status=prepared_status_for(prepared_stages, "high_quality_3dgs"),
                result_path=g3dgs_path,
                detail=f"provider={g3dgs_provider or args.g3dgs_provider or 'external_3dgs'}",
                import_command="import-3dgs-result",
            )
        )

    open_vocab_path = resolve_project_cli_path(args.open_vocab_manifest, project_root) if args.open_vocab_manifest else jobs_root / "open_vocab_detection_jobs" / "detections_template.json"
    if not open_vocab_path.exists():
        status = production_stage_status("open_vocab_detection", "missing_result", "manifest_missing", prepared_status=prepared_status_for(prepared_stages, "open_vocab_detection"), expected_path=open_vocab_path, import_command="import-open-vocab-detections")
    elif detection_result_has_entries(open_vocab_path):
        status = production_stage_status("open_vocab_detection", "ready_to_import", "detections_found", prepared_status=prepared_status_for(prepared_stages, "open_vocab_detection"), result_path=open_vocab_path, import_command="import-open-vocab-detections")
    elif open_vocab_detection_template_has_requests(open_vocab_path):
        status = production_stage_status("open_vocab_detection", "empty_template", "detection_requests_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "open_vocab_detection"), result_path=open_vocab_path, import_command="import-open-vocab-detections")
    else:
        status = production_stage_status("open_vocab_detection", "empty_template", "no_detections", prepared_status=prepared_status_for(prepared_stages, "open_vocab_detection"), result_path=open_vocab_path, import_command="import-open-vocab-detections")
    checks.append(status)

    video_manifest = resolve_project_cli_path(args.video_segmentation_manifest, project_root) if args.video_segmentation_manifest else jobs_root / "video_segmentation_jobs" / "external_masks_manifest.json"
    video_root = resolve_project_cli_path(args.video_segmentation_root, project_root) if args.video_segmentation_root else jobs_root / "video_segmentation_jobs" / "masks"
    video_manifest_exists = video_manifest.exists()
    video_root_exists = video_root.exists()
    if not video_manifest_exists and not video_root_exists:
        status = production_stage_status("video_segmentation", "missing_result", "manifest_and_mask_root_missing", prepared_status=prepared_status_for(prepared_stages, "video_segmentation"), expected_path=video_manifest, expected_root=video_root, import_command="import-video-segmentation-masks")
    elif video_segmentation_result_has_entries(video_manifest if video_manifest_exists else None, video_root if video_root_exists else None):
        status = production_stage_status("video_segmentation", "ready_to_import", "masks_found", prepared_status=prepared_status_for(prepared_stages, "video_segmentation"), result_path=video_manifest if video_manifest_exists else None, result_root=video_root if video_root_exists else None, import_command="import-video-segmentation-masks")
    elif video_segmentation_manifest_has_template_records(video_manifest if video_manifest_exists else None, project_root):
        status = production_stage_status("video_segmentation", "empty_template", "mask_manifest_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "video_segmentation"), result_path=video_manifest if video_manifest_exists else None, expected_root=video_root, import_command="import-video-segmentation-masks")
    else:
        status = production_stage_status("video_segmentation", "empty_template", "no_masks_found", prepared_status=prepared_status_for(prepared_stages, "video_segmentation"), result_path=video_manifest if video_manifest_exists else None, result_root=video_root if video_root_exists else None, import_command="import-video-segmentation-masks")
    checks.append(status)

    labels_path = resolve_project_cli_path(args.labels, project_root) if args.labels else jobs_root / "object_labeling_jobs" / "labels_template.json"
    if not labels_path.exists():
        status = production_stage_status("object_labels", "missing_result", "labels_missing", prepared_status=prepared_status_for(prepared_stages, "object_labeling"), expected_path=labels_path, import_command="import-object-labels")
    elif label_result_has_filled_values(labels_path):
        status = production_stage_status("object_labels", "ready_to_import", "filled_labels_found", prepared_status=prepared_status_for(prepared_stages, "object_labeling"), result_path=labels_path, import_command="import-object-labels --sync-simulator-assets")
    else:
        status = production_stage_status("object_labels", "empty_template", "labels_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "object_labeling"), result_path=labels_path, import_command="import-object-labels --sync-simulator-assets")
    checks.append(status)

    scene_structure_path = resolve_project_cli_path(args.scene_structure_manifest, project_root) if args.scene_structure_manifest else jobs_root / "scene_structure_jobs" / "scene_structure_masks_template.json"
    if not scene_structure_path.exists():
        status = production_stage_status("scene_structure", "missing_result", "scene_structure_manifest_missing", prepared_status=prepared_status_for(prepared_stages, "scene_structure"), expected_path=scene_structure_path, import_command="import-scene-structure-masks")
    elif scene_structure_result_has_indices(scene_structure_path):
        status = production_stage_status("scene_structure", "ready_to_import", "point_indices_found", prepared_status=prepared_status_for(prepared_stages, "scene_structure"), result_path=scene_structure_path, import_command="import-scene-structure-masks")
    else:
        status = production_stage_status("scene_structure", "empty_template", "no_point_indices", prepared_status=prepared_status_for(prepared_stages, "scene_structure"), result_path=scene_structure_path, import_command="import-scene-structure-masks")
    checks.append(status)

    mesh_manifest = infer_mesh_manifest_path(jobs_root, project_root, args.mesh_manifest)
    mesh_root = resolve_project_cli_path(args.mesh_root, project_root) if args.mesh_root else jobs_root / "multiview_mesh_jobs" / "meshes"
    if mesh_result_has_assets(mesh_manifest, mesh_root, project_root):
        status = production_stage_status("object_meshes", "ready_to_import", "mesh_assets_found", prepared_status=prepared_status_for(prepared_stages, "multiview_mesh"), result_path=mesh_manifest, result_root=mesh_root if mesh_root.exists() else None, import_command="import-object-meshes")
    elif mesh_manifest_has_template_records(mesh_manifest):
        status = production_stage_status("object_meshes", "empty_template", "mesh_manifest_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "multiview_mesh"), result_path=mesh_manifest, expected_root=mesh_root, import_command="import-object-meshes")
    else:
        status = production_stage_status("object_meshes", "missing_result", "no_mesh_assets_found", prepared_status=prepared_status_for(prepared_stages, "multiview_mesh"), expected_path=mesh_manifest, expected_root=mesh_root, import_command="import-object-meshes")
    checks.append(status)

    scale_path = resolve_project_cli_path(args.scale_calibration, project_root) if args.scale_calibration else jobs_root / "scale_calibration_jobs" / "scale_calibration_template.json"
    has_cli_scale_measurement = args.scale_to_meters is not None or bool(args.reference_object and args.reference_length_m)
    if has_cli_scale_measurement:
        status = production_stage_status("scale_calibration", "ready_to_import", "cli_scale_measurement_provided", prepared_status=prepared_status_for(prepared_stages, "scale_calibration"), result_path=scale_path if scale_path.exists() else None, import_command="import-scale-calibration")
    elif not scale_path.exists():
        status = production_stage_status("scale_calibration", "missing_result", "scale_calibration_missing", prepared_status=prepared_status_for(prepared_stages, "scale_calibration"), expected_path=scale_path, import_command="import-scale-calibration")
    elif scale_calibration_result_has_filled_values(scale_path):
        status = production_stage_status("scale_calibration", "ready_to_import", "filled_scale_reference_found", prepared_status=prepared_status_for(prepared_stages, "scale_calibration"), result_path=scale_path, import_command="import-scale-calibration")
    else:
        status = production_stage_status("scale_calibration", "empty_template", "scale_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "scale_calibration"), result_path=scale_path, import_command="import-scale-calibration")
    checks.append(status)

    physics_path = resolve_project_cli_path(args.physics, project_root) if args.physics else jobs_root / "physics_properties_jobs" / "physics_properties_template.json"
    if not physics_path.exists():
        status = production_stage_status("simulator_physics", "missing_result", "physics_template_missing", prepared_status=prepared_status_for(prepared_stages, "simulator_physics"), expected_path=physics_path, import_command="import-simulator-physics")
    elif physics_result_has_filled_values(physics_path):
        status = production_stage_status("simulator_physics", "ready_to_import", "filled_physics_found", prepared_status=prepared_status_for(prepared_stages, "simulator_physics"), result_path=physics_path, import_command="import-simulator-physics")
    else:
        status = production_stage_status("simulator_physics", "empty_template", "physics_template_unfilled", prepared_status=prepared_status_for(prepared_stages, "simulator_physics"), result_path=physics_path, import_command="import-simulator-physics")
    checks.append(status)

    sceneverse_root = jobs_root / "sceneversepp_jobs"
    svpp_metadata_files = sorted(sceneverse_root.glob("svpp_data/*/metadata.json")) if sceneverse_root.exists() else []
    if svpp_metadata_files:
        status = production_stage_status(
            "sceneversepp",
            "prepared_only",
            "svpp_style_data_prepared",
            prepared_status=prepared_status_for(prepared_stages, "sceneversepp"),
            result_root=sceneverse_root,
            detail="SceneVerse++/PQ3D assets are prepared for external execution; there is no unified import stage in this verifier.",
        )
    else:
        status = production_stage_status(
            "sceneversepp",
            "missing_result",
            "svpp_style_data_missing",
            prepared_status=prepared_status_for(prepared_stages, "sceneversepp"),
            expected_root=sceneverse_root,
        )
    checks.append(status)

    attach_production_result_contracts(checks, project_root, jobs_root)
    attach_production_quality_gates(checks, project_root, jobs_root)
    counts = count_gate_statuses(checks)
    contract_missing_requirements = {
        item["name"]: list((item.get("result_contract") or {}).get("missing_requirements") or [])
        for item in checks
        if isinstance(item.get("result_contract"), dict) and (item.get("result_contract") or {}).get("missing_requirements")
    }
    contract_ready = [
        item["name"]
        for item in checks
        if isinstance(item.get("result_contract"), dict)
        and not (item.get("result_contract") or {}).get("missing_requirements")
        and item.get("status") == "ready_to_import"
    ]
    quality_gates = [item.get("quality_gate") for item in checks if isinstance(item.get("quality_gate"), dict)]
    quality_counts = count_gate_statuses([{"status": gate.get("status")} for gate in quality_gates])
    production_validated = [
        item["name"]
        for item in checks
        if isinstance(item.get("quality_gate"), dict) and bool(item["quality_gate"].get("production_validated"))
    ]
    quality_warning = [
        item["name"]
        for item in checks
        if isinstance(item.get("quality_gate"), dict) and str(item["quality_gate"].get("status")) == "import_ready_quality_warning"
    ]
    quality_pending = [
        item["name"]
        for item in checks
        if isinstance(item.get("quality_gate"), dict) and str(item["quality_gate"].get("status")) in {"pending", "import_ready_quality_pending"}
    ]
    ready = [item["name"] for item in checks if item["status"] == "ready_to_import"]
    empty = [item["name"] for item in checks if item["status"] == "empty_template"]
    missing = [item["name"] for item in checks if item["status"] == "missing_result"]
    invalid = [item["name"] for item in checks if item["status"] == "invalid_result"]
    required = set(args.require_stage or [])
    if args.require_all_importable_stages:
        required.update(item["name"] for item in checks if item["status"] != "prepared_only")
    required_not_ready = sorted(name for name in required if name not in ready)
    ok = not invalid and not required_not_ready
    if args.fail_on_missing and missing:
        ok = False
    if args.fail_on_empty and empty:
        ok = False
    report = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_upgrade_results_verification",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "jobs_root": str(jobs_root),
        "timestamp": int(time.time()),
        "ok": bool(ok),
        "summary": {
            "ready_to_import": len(ready),
            "empty_template": len(empty),
            "missing_result": len(missing),
            "invalid_result": len(invalid),
            "prepared_only": counts.get("prepared_only", 0),
            "status_counts": counts,
            "ready_stages": ready,
            "empty_stages": empty,
            "missing_stages": missing,
            "invalid_stages": invalid,
            "required_not_ready": required_not_ready,
            "contract_ready": len(contract_ready),
            "contract_ready_stages": contract_ready,
            "contract_missing_requirement_stage_count": len(contract_missing_requirements),
            "contract_missing_requirements": contract_missing_requirements,
            "production_validated": len(production_validated),
            "production_validated_stages": production_validated,
            "quality_warning": len(quality_warning),
            "quality_warning_stages": quality_warning,
            "quality_pending": len(quality_pending),
            "quality_pending_stages": quality_pending,
            "quality_status_counts": quality_counts,
        },
        "checks": checks,
        "notes": [
            "This verifier inspects existing external results only.",
            "It does not import files, run heavy models, call paid APIs, or modify stage outputs.",
            "ready_to_import means import-production-upgrade-results should have enough input for that stage.",
            "quality_gate.production_validated is stronger than ready_to_import; it records whether local, non-heavy checks can treat the result as production-quality before post-import QA.",
        ],
    }
    write_json(output_path, report)
    if args.update_manifest:
        manifest = load_manifest(project_root)
        manifest.setdefault("artifacts", {})["production_upgrade_results_verification"] = str(output_path)
        manifest.setdefault("external_stages", {})["production_upgrade_results_verification"] = {
            "status": "ready_to_import" if ready else "no_ready_results",
            "report": str(output_path),
            "ready_stages": ready,
            "missing_stages": missing,
            "empty_stages": empty,
            "invalid_stages": invalid,
        }
        save_manifest(project_root, manifest)

    if getattr(args, "quiet", False):
        pass
    elif args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        pending_count = len(empty) + len(missing)
        status_text = "READY" if report["ok"] and pending_count == 0 else "PENDING" if report["ok"] else "ISSUES"
        print(f"Production upgrade result verification: {status_text} ({report['scene_id']})")
        print(
            f"ready={len(ready)} empty={len(empty)} missing={len(missing)} "
            f"invalid={len(invalid)} prepared_only={counts.get('prepared_only', 0)}"
        )
        for item in checks:
            print(f"- {item['name']}: {item['status']} ({item['reason']})")
        print(f"Report: {output_path}")
    return 1 if args.fail_on_issues and not ok else 0


def audit_script_record(path: Path, project_root: Path) -> dict[str, Any]:
    exists = path.exists()
    return {
        "path": str(path),
        "relative_path": rel_or_abs(path, project_root),
        "exists": bool(exists),
        "executable": bool(exists and os.access(path, os.X_OK)),
        "size_bytes": int(path.stat().st_size) if exists else 0,
    }


def audit_template_record(path: Path, project_root: Path) -> dict[str, Any]:
    exists = path.exists()
    data = safe_read_json(path) if exists else None
    return {
        "path": str(path),
        "relative_path": rel_or_abs(path, project_root),
        "exists": bool(exists),
        "json_readable": isinstance(data, (dict, list)),
        "size_bytes": int(path.stat().st_size) if exists else 0,
    }


def production_stage_next_step(check: dict[str, Any]) -> str:
    stage = str(check.get("name") or "")
    status = str(check.get("status") or "")
    if status == "ready_to_import":
        return f"Import with `{check.get('import_command')}` or run `import-production-upgrade-results`."
    if stage == "high_quality_3dgs":
        return "Run the prepared GraphDECO/nerfstudio/full-gsplat script and ensure the output directory contains a valid 3DGS PLY."
    if stage == "open_vocab_detection":
        return "Fill open_vocab_detection_jobs/detections_template.json with external detector results, then rerun verification."
    if stage == "video_segmentation":
        return "Run SAM2/DEVA/XMem/Grounded-SAM and write external_masks_manifest.json or masks/ under video_segmentation_jobs."
    if stage == "object_labels":
        return "Fill labels_template.json with production VLM/open-vocabulary labels including confidence/open_vocab/vlm evidence."
    if stage == "scene_structure":
        return "Run SpatialLM/PQ3D/open-vocabulary scene-structure segmentation and fill point_indices in scene_structure_masks_template.json."
    if stage == "object_meshes":
        return "Run multiview/Hunyuan/Meshy/image-blaster mesh jobs and write mesh_manifest.json or meshes/."
    if stage == "scale_calibration":
        return "Measure a real reference length in scale_calibration_template.json or provide --scale-to-meters/--reference-object."
    if stage == "simulator_physics":
        return "Fill physics_properties_template.json with measured/manual mass, material, collider, and body type values."
    if stage == "sceneversepp":
        return "Run prepared SceneVerse++/SpatialLM/PQ3D scripts externally; this stage remains prepared_only until downstream outputs are consumed."
    return "Inspect the prepared job JSON and complete the external result expected by this stage."


def cmd_audit_production_upgrade_jobs(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = project_root / manifest["simulator_assets_dir"] / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else jobs_root / "production_upgrade_execution_audit.json"

    prepared_report_path = jobs_root / "production_upgrade_jobs.json"
    prepared_report = safe_read_json(prepared_report_path)
    job_files = collect_upgrade_job_files(jobs_root)
    scripts = [audit_script_record(Path(path), project_root) for path in job_files.get("scripts", [])]
    templates = [audit_template_record(Path(path), project_root) for path in job_files.get("templates", [])]

    verification_args = argparse.Namespace(
        project_root=project_root,
        jobs_root=jobs_root,
        output=jobs_root / "_production_upgrade_audit_verification_tmp.json",
        update_manifest=False,
        json=True,
        fail_on_issues=False,
        fail_on_missing=False,
        fail_on_empty=False,
        require_stage=[],
        require_all_importable_stages=False,
        g3dgs_path=None,
        g3dgs_splat_ply=None,
        g3dgs_provider=None,
        open_vocab_manifest=None,
        video_segmentation_manifest=None,
        video_segmentation_root=None,
        labels=None,
        scene_structure_manifest=None,
        mesh_manifest=None,
        mesh_root=None,
        scale_calibration=None,
        scale_to_meters=None,
        reference_object=None,
        reference_length_m=None,
        physics=None,
        quiet=True,
    )
    # Reuse the result verifier without printing nested text by calling its core
    # output path and reading the generated temporary JSON.
    cmd_verify_production_upgrade_results(verification_args)
    verification_tmp = verification_args.output
    verification = safe_read_json(verification_tmp)
    try:
        verification_tmp.unlink()
    except Exception:
        pass
    verification_summary = verification.get("summary") if isinstance(verification, dict) else {}
    checks = verification.get("checks") if isinstance(verification, dict) and isinstance(verification.get("checks"), list) else []

    stage_audits = []
    for check in checks:
        item = dict(check)
        item["next_step"] = production_stage_next_step(check)
        stage_audits.append(item)

    missing_scripts = [item for item in scripts if not item["exists"]]
    non_executable_scripts = [item for item in scripts if item["exists"] and not item["executable"]]
    missing_templates = [item for item in templates if not item["exists"]]
    unreadable_templates = [item for item in templates if item["exists"] and not item["json_readable"]]
    prepared_summary = prepared_report.get("summary") if isinstance(prepared_report, dict) else {}
    prepared_stages = prepared_report.get("stages") if isinstance(prepared_report, dict) and isinstance(prepared_report.get("stages"), list) else []
    completed_prepared = len([stage for stage in prepared_stages if isinstance(stage, dict) and stage.get("status") == "completed"])
    skipped_prepared = len([stage for stage in prepared_stages if isinstance(stage, dict) and stage.get("status") == "skipped"])
    ready_count = int((verification_summary or {}).get("ready_to_import") or 0)
    missing_count = int((verification_summary or {}).get("missing_result") or 0)
    empty_count = int((verification_summary or {}).get("empty_template") or 0)
    invalid_count = int((verification_summary or {}).get("invalid_result") or 0)
    prepared_only_count = int((verification_summary or {}).get("prepared_only") or 0)
    ok = (
        prepared_report_path.exists()
        and completed_prepared > 0
        and not missing_scripts
        and not non_executable_scripts
        and not missing_templates
        and not unreadable_templates
        and invalid_count == 0
    )
    report = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_upgrade_execution_audit",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "jobs_root": str(jobs_root),
        "timestamp": int(time.time()),
        "ok": bool(ok),
        "status": "jobs_ready_for_external_execution" if ok else "job_package_issues",
        "summary": {
            "prepared_report": str(prepared_report_path),
            "prepared_report_exists": prepared_report_path.exists(),
            "prepared_completed": completed_prepared or int((prepared_summary or {}).get("completed") or 0),
            "prepared_skipped": skipped_prepared or int((prepared_summary or {}).get("skipped") or 0),
            "script_count": len(scripts),
            "missing_scripts": len(missing_scripts),
            "non_executable_scripts": len(non_executable_scripts),
            "template_count": len(templates),
            "missing_templates": len(missing_templates),
            "unreadable_templates": len(unreadable_templates),
            "ready_to_import": ready_count,
            "empty_template": empty_count,
            "missing_result": missing_count,
            "invalid_result": invalid_count,
            "prepared_only": prepared_only_count,
        },
        "scripts": scripts,
        "templates": templates,
        "verification_summary": verification_summary,
        "stages": stage_audits,
        "notes": [
            "This audit checks the prepared job package and current external-result status only.",
            "It does not execute GraphDECO/nerfstudio, SAM2/DEVA/XMem, VLM labeling, mesh APIs, scale measurement, physics annotation, or SceneVerse++ jobs.",
            "A ready job package can still have missing_result/empty_template stages because external tools have not run yet.",
        ],
    }
    write_json(output_path, report)
    manifest.setdefault("artifacts", {})["production_upgrade_execution_audit"] = str(output_path)
    save_manifest(project_root, manifest)

    if getattr(args, "quiet", False):
        pass
    elif args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        summary = report["summary"]
        print(f"Production upgrade job audit: {report['status']} ({report['scene_id']})")
        print(
            f"prepared={summary['prepared_completed']} skipped={summary['prepared_skipped']} "
            f"scripts={summary['script_count']} nonexec={summary['non_executable_scripts']} "
            f"templates={summary['template_count']} unreadable={summary['unreadable_templates']} "
            f"ready={summary['ready_to_import']} empty={summary['empty_template']} missing={summary['missing_result']} invalid={summary['invalid_result']}"
        )
        for item in stage_audits:
            print(f"- {item['name']}: {item['status']} ({item['reason']})")
        print(f"Report: {output_path}")
    return 1 if args.fail_on_issues and not ok else 0


def production_handoff_stage_priority(stage_name: str) -> int:
    order = {
        "high_quality_3dgs": 10,
        "open_vocab_detection": 20,
        "video_segmentation": 30,
        "object_labels": 40,
        "scene_structure": 50,
        "object_meshes": 60,
        "scale_calibration": 70,
        "simulator_physics": 80,
        "sceneversepp": 90,
    }
    return order.get(stage_name, 999)


def production_handoff_stage_command(stage_name: str, jobs_root: Path) -> str:
    commands = {
        "high_quality_3dgs": jobs_root / "high_quality_3dgs" / "run_high_quality_3dgs.sh",
        "open_vocab_detection": jobs_root / "open_vocab_detection_jobs" / "run_open_vocab_detection.sh",
        "video_segmentation": jobs_root / "video_segmentation_jobs" / "run_video_segmentation.sh",
        "scene_structure": jobs_root / "scene_structure_jobs" / "run_scene_structure_segmentation.sh",
        "object_meshes": jobs_root / "multiview_mesh_jobs" / "run_mesh_jobs.sh",
        "scale_calibration": jobs_root / "scale_calibration_jobs" / "run_scale_calibration_example.sh",
        "sceneversepp": jobs_root / "sceneversepp_jobs" / "run_sceneversepp_data_jobs.sh",
    }
    path = commands.get(stage_name)
    if path and path.exists():
        return str(path)
    if stage_name == "object_labels":
        return str(jobs_root / "object_labeling_jobs" / "labels_template.json")
    if stage_name == "simulator_physics":
        return str(jobs_root / "physics_properties_jobs" / "physics_properties_template.json")
    return ""


def production_handoff_import_command(stage_name: str, project_root: Path) -> str:
    commands = {
        "high_quality_3dgs": "python -m video2mesh.cli import-3dgs-result --project-root <project> --path <external_3dgs_output>",
        "open_vocab_detection": "python -m video2mesh.cli import-open-vocab-detections --project-root <project> --source-manifest <detections.json>",
        "video_segmentation": "python -m video2mesh.cli import-video-segmentation-masks --project-root <project> --source-manifest <external_masks_manifest.json>",
        "object_labels": "python -m video2mesh.cli import-object-labels --project-root <project> --labels <labels.json> --sync-simulator-assets",
        "scene_structure": "python -m video2mesh.cli import-scene-structure-masks --project-root <project> --source-manifest <scene_structure_masks.json>",
        "object_meshes": "python -m video2mesh.cli import-object-meshes --project-root <project> --mesh-manifest <mesh_manifest.json>",
        "scale_calibration": "python -m video2mesh.cli import-scale-calibration --project-root <project> --scale-calibration <scale_calibration.json>",
        "simulator_physics": "python -m video2mesh.cli import-simulator-physics --project-root <project> --physics <physics_properties.json>",
        "sceneversepp": "python -m video2mesh.cli prepare-sceneversepp-jobs / run SceneVerse++ scripts; no unified production import yet",
    }
    return commands.get(stage_name, "").replace("<project>", str(project_root))


def generate_production_upgrade_handoff(project_root: Path, manifest: dict[str, Any], jobs_root: Path, audit: dict[str, Any]) -> dict[str, Any]:
    summary = audit.get("summary") if isinstance(audit.get("summary"), dict) else {}
    stages = audit.get("stages") if isinstance(audit.get("stages"), list) else []
    stage_records = []
    for stage in sorted([item for item in stages if isinstance(item, dict)], key=lambda item: production_handoff_stage_priority(str(item.get("name") or ""))):
        stage_name = str(stage.get("name") or "")
        stage_records.append(
            {
                "name": stage_name,
                "status": stage.get("status"),
                "reason": stage.get("reason"),
                "prepared_status": stage.get("prepared_status"),
                "script_or_template": production_handoff_stage_command(stage_name, jobs_root),
                "import_command": production_handoff_import_command(stage_name, project_root) or stage.get("import_command"),
                "next_step": stage.get("next_step") or production_stage_next_step(stage),
            }
        )
    return {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_upgrade_handoff",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "jobs_root": str(jobs_root),
        "timestamp": int(time.time()),
        "summary": {
            "audit_status": audit.get("status"),
            "audit_ok": audit.get("ok"),
            "prepared_completed": summary.get("prepared_completed"),
            "prepared_skipped": summary.get("prepared_skipped"),
            "script_count": summary.get("script_count"),
            "template_count": summary.get("template_count"),
            "ready_to_import": summary.get("ready_to_import"),
            "empty_template": summary.get("empty_template"),
            "missing_result": summary.get("missing_result"),
            "invalid_result": summary.get("invalid_result"),
            "prepared_only": summary.get("prepared_only"),
        },
        "stages": stage_records,
        "global_commands": {
            "audit_before_execution": f"python -m video2mesh.cli audit-production-upgrade-jobs --project-root {project_root}",
            "run_all_prepared_scripts": str(jobs_root / "run_prepared_external_jobs.sh"),
            "verify_after_external_results": f"python -m video2mesh.cli verify-production-upgrade-results --project-root {project_root}",
            "import_ready_results": f"python -m video2mesh.cli import-production-upgrade-results --project-root {project_root} --render-preview --render-semantic-preview --sync-simulator-assets",
            "refresh_readiness": f"python -m video2mesh.cli production-readiness --project-root {project_root}",
        },
        "notes": [
            "This handoff is for server-side execution planning. It does not run heavy models.",
            "Run individual scripts selectively if GPU memory, dependencies, or API credentials are limited.",
            "After any external result is produced, rerun verify-production-upgrade-results before importing.",
            "Only import stages that are ready_to_import; empty templates and missing results are intentionally skipped by import-production-upgrade-results.",
        ],
    }


def write_production_upgrade_handoff_markdown(report: dict[str, Any], output_path: Path) -> None:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    commands = report.get("global_commands") if isinstance(report.get("global_commands"), dict) else {}
    lines = [
        f"# Video2Mesh Production Upgrade Handoff: {report.get('scene_id') or 'scene'}",
        "",
        "## Overall",
        "",
        markdown_table(
            ["Field", "Value"],
            [
                ["audit_status", summary.get("audit_status")],
                ["audit_ok", summary.get("audit_ok")],
                ["prepared_completed", summary.get("prepared_completed")],
                ["prepared_skipped", summary.get("prepared_skipped")],
                ["script_count", summary.get("script_count")],
                ["template_count", summary.get("template_count")],
                ["ready_to_import", summary.get("ready_to_import")],
                ["empty_template", summary.get("empty_template")],
                ["missing_result", summary.get("missing_result")],
                ["invalid_result", summary.get("invalid_result")],
                ["prepared_only", summary.get("prepared_only")],
            ],
        ),
        "",
        "## Global Commands",
        "",
        "```bash",
    ]
    for _name, command in commands.items():
        if command:
            lines.append(str(command))
    lines.extend(
        [
            "```",
            "",
            "## Stage Plan",
            "",
            markdown_table(
                ["Stage", "Status", "Reason", "Script Or Template", "Import Command", "Next Step"],
                [
                    [
                        item.get("name"),
                        item.get("status"),
                        item.get("reason"),
                        item.get("script_or_template"),
                        item.get("import_command"),
                        item.get("next_step"),
                    ]
                    for item in report.get("stages", [])
                ],
            ),
            "",
            "## Notes",
            "",
        ]
    )
    for note in report.get("notes", []):
        lines.append(f"- {md_cell(note)}")
    lines.append("")
    ensure_dir(output_path.parent)
    output_path.write_text("\n".join(lines), encoding="utf-8")


def cmd_export_production_upgrade_handoff(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = project_root / manifest["simulator_assets_dir"] / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    audit_path = jobs_root / "production_upgrade_execution_audit.json"
    audit = safe_read_json(audit_path)
    if not isinstance(audit, dict) or args.refresh_audit:
        cmd_audit_production_upgrade_jobs(
            argparse.Namespace(project_root=project_root, jobs_root=jobs_root, output=audit_path, json=False, quiet=True, fail_on_issues=False)
        )
        audit = safe_read_json(audit_path)
    if not isinstance(audit, dict):
        raise RuntimeError(f"Failed to read production upgrade audit: {audit_path}")
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else jobs_root / "production_upgrade_handoff.json"
    markdown_path = resolve_project_cli_path(args.markdown_output, project_root) if args.markdown_output else jobs_root / "production_upgrade_handoff.md"
    report = generate_production_upgrade_handoff(project_root, manifest, jobs_root, audit)
    write_json(output_path, report)
    if not args.no_markdown:
        write_production_upgrade_handoff_markdown(report, markdown_path)
    manifest.setdefault("artifacts", {})["production_upgrade_handoff"] = str(output_path)
    if not args.no_markdown:
        manifest.setdefault("artifacts", {})["production_upgrade_handoff_markdown"] = str(markdown_path)
    save_manifest(project_root, manifest)

    if args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        summary = report["summary"]
        print(f"Production upgrade handoff: {summary.get('audit_status')} ({report['scene_id']})")
        print(
            f"prepared={summary.get('prepared_completed')} ready={summary.get('ready_to_import')} "
            f"empty={summary.get('empty_template')} missing={summary.get('missing_result')} invalid={summary.get('invalid_result')}"
        )
        print(f"JSON: {output_path}")
        if not args.no_markdown:
            print(f"Markdown: {markdown_path}")
    return 0


