def production_task_action_from_status(status: str) -> str:
    if status == "ready_to_import":
        return "import_result"
    if status == "missing_result":
        return "run_external_job"
    if status == "empty_template":
        return "fill_template_or_run_external_job"
    if status == "prepared_only":
        return "execute_external_bridge"
    if status == "invalid_result":
        return "fix_external_result"
    return "inspect_stage"


def production_task_status_label(status: str) -> str:
    labels = {
        "ready_to_import": "ready_to_import",
        "missing_result": "needs_external_run",
        "empty_template": "needs_external_result_or_template_fill",
        "prepared_only": "prepared_bridge_only",
        "invalid_result": "invalid_external_result",
    }
    return labels.get(status, status or "unknown")


def shell_command_for_path(path_value: str) -> str:
    if not path_value:
        return ""
    path = Path(path_value)
    if path.suffix.lower() == ".sh":
        return f"bash {shlex.quote(path_value)}"
    if path.suffix.lower() == ".json":
        return f"# fill template: {shlex.quote(path_value)}"
    return shlex.quote(path_value)


def production_task_validation_commands(project_root: Path) -> list[str]:
    return [
        f"python -m video2mesh.cli verify-production-upgrade-results --project-root {project_root}",
        f"python -m video2mesh.cli production-readiness --project-root {project_root}",
        f"python -m video2mesh.cli verify-showcase-pack --project-root {project_root} --fail-on-issues",
    ]


def capability_lookup_from_matrix(matrix: dict[str, Any]) -> dict[str, dict[str, Any]]:
    capabilities = matrix.get("capabilities") if isinstance(matrix.get("capabilities"), list) else []
    result = {}
    for item in capabilities:
        if isinstance(item, dict) and item.get("id"):
            result[str(item["id"])] = item
    return result


def production_upgrade_stage_map(report: dict[str, Any] | None) -> dict[str, dict[str, Any]]:
    if not isinstance(report, dict) or not isinstance(report.get("stages"), list):
        return {}
    result = {}
    for item in report.get("stages", []):
        if isinstance(item, dict) and item.get("name"):
            result[str(item["name"])] = item
    return result


def production_verification_stage_map(report: dict[str, Any] | None) -> dict[str, dict[str, Any]]:
    if not isinstance(report, dict) or not isinstance(report.get("checks"), list):
        return {}
    result = {}
    for item in report.get("checks", []):
        if isinstance(item, dict) and item.get("name"):
            result[str(item["name"])] = item
    return result


def production_quality_gate_summary_from_checks(checks: list[dict[str, Any]]) -> dict[str, Any]:
    gates = [item.get("quality_gate") for item in checks if isinstance(item, dict) and isinstance(item.get("quality_gate"), dict)]
    status_counts = count_gate_statuses([{"status": gate.get("status")} for gate in gates])
    production_validated = [
        str(gate.get("stage") or "")
        for gate in gates
        if bool(gate.get("production_validated")) and gate.get("stage")
    ]
    quality_warning = [
        str(gate.get("stage") or "")
        for gate in gates
        if str(gate.get("status") or "") == "import_ready_quality_warning" and gate.get("stage")
    ]
    quality_pending = [
        str(gate.get("stage") or "")
        for gate in gates
        if str(gate.get("status") or "") in {"pending", "import_ready_quality_pending"} and gate.get("stage")
    ]
    return {
        "production_validated": len(production_validated),
        "production_validated_stages": production_validated,
        "quality_warning": len(quality_warning),
        "quality_warning_stages": quality_warning,
        "quality_pending": len(quality_pending),
        "quality_pending_stages": quality_pending,
        "quality_status_counts": status_counts,
    }


def existing_execution_artifact(path_value: str, project_root: Path) -> tuple[bool, str]:
    if not path_value:
        return False, ""
    path = resolve_project_cli_path(Path(path_value), project_root)
    return path.exists(), str(path)


def generate_production_upgrade_task_queue(
    project_root: Path,
    manifest: dict[str, Any],
    jobs_root: Path,
    audit: dict[str, Any],
    handoff: dict[str, Any],
    verification: dict[str, Any],
    target_matrix: dict[str, Any],
) -> dict[str, Any]:
    stage_defs = production_upgrade_task_stage_definitions()
    handoff_stages = production_upgrade_stage_map(handoff)
    verification_stages = production_verification_stage_map(verification)
    capability_by_id = capability_lookup_from_matrix(target_matrix)
    validation_commands = production_task_validation_commands(project_root)

    audit_summary = audit.get("summary") if isinstance(audit.get("summary"), dict) else {}
    verification_summary = verification.get("summary") if isinstance(verification.get("summary"), dict) else {}
    target_summary = target_matrix.get("summary") if isinstance(target_matrix.get("summary"), dict) else {}
    tasks: list[dict[str, Any]] = []
    missing_stage_definitions: list[str] = []

    stage_names = sorted(
        set(stage_defs.keys()) | set(handoff_stages.keys()) | set(verification_stages.keys()),
        key=lambda name: stage_defs.get(name, {}).get("priority", production_handoff_stage_priority(name)),
    )
    for stage_name in stage_names:
        stage_def = stage_defs.get(stage_name)
        if not isinstance(stage_def, dict):
            missing_stage_definitions.append(stage_name)
            stage_def = {
                "capability_id": "production_upgrade_execution",
                "capability_name": "生产升级作业执行与回流",
                "priority": production_handoff_stage_priority(stage_name),
                "execution_kind": "unknown",
                "expected_result": "Inspect the prepared stage output.",
                "why": "No explicit task definition exists for this stage.",
            }
        handoff_stage = handoff_stages.get(stage_name, {})
        verification_stage = verification_stages.get(stage_name, {})
        status = str(verification_stage.get("status") or handoff_stage.get("status") or "unknown")
        quality_gate = verification_stage.get("quality_gate") if isinstance(verification_stage.get("quality_gate"), dict) else {}
        result_contract = verification_stage.get("result_contract") if isinstance(verification_stage.get("result_contract"), dict) else {}
        acceptance_criteria = (
            verification_stage.get("acceptance_criteria")
            if isinstance(verification_stage.get("acceptance_criteria"), list)
            else production_stage_acceptance_criteria(stage_name)
        )
        script_or_template = str(handoff_stage.get("script_or_template") or production_handoff_stage_command(stage_name, jobs_root) or "")
        artifact_exists, artifact_path = existing_execution_artifact(script_or_template, project_root)
        capability_id = str(stage_def.get("capability_id") or "production_upgrade_execution")
        capability = capability_by_id.get(capability_id, {})
        import_command = str(handoff_stage.get("import_command") or production_handoff_import_command(stage_name, project_root) or verification_stage.get("import_command") or "")
        result_path = str(verification_stage.get("result_path") or verification_stage.get("expected_path") or "")
        result_root = str(verification_stage.get("result_root") or verification_stage.get("expected_root") or "")
        execution_command = shell_command_for_path(script_or_template)
        blocked = False
        blockers: list[str] = []
        if not artifact_exists and script_or_template:
            blocked = True
            blockers.append("script_or_template_missing")
        if status == "invalid_result":
            blocked = True
            blockers.append("invalid_external_result")
        if status == "unknown":
            blocked = True
            blockers.append("unknown_stage_status")
        tasks.append(
            {
                "priority": int(stage_def.get("priority") or production_handoff_stage_priority(stage_name)),
                "stage": stage_name,
                "capability_id": capability_id,
                "capability_name": stage_def.get("capability_name") or capability.get("name"),
                "capability_status": capability.get("status"),
                "task_status": production_task_status_label(status),
                "source_status": status,
                "action": production_task_action_from_status(status),
                "execution_kind": stage_def.get("execution_kind"),
                "why": stage_def.get("why"),
                "current_gap": capability.get("gap"),
                "next_step": handoff_stage.get("next_step") or production_stage_next_step(verification_stage),
                "script_or_template": artifact_path or script_or_template,
                "script_or_template_exists": artifact_exists,
                "execution_command": execution_command,
                "expected_result": stage_def.get("expected_result"),
                "result_path": result_path,
                "result_root": result_root,
                "import_command": import_command,
                "validation_commands": validation_commands,
                "prepared_status": verification_stage.get("prepared_status") or handoff_stage.get("prepared_status"),
                "reason": verification_stage.get("reason") or handoff_stage.get("reason"),
                "quality_gate": quality_gate,
                "quality_status": quality_gate.get("status"),
                "production_validated": bool(quality_gate.get("production_validated")),
                "result_contract": result_contract,
                "missing_requirements": result_contract.get("missing_requirements") if isinstance(result_contract.get("missing_requirements"), list) else [],
                "acceptance_criteria": acceptance_criteria,
                "blocked": blocked,
                "blockers": blockers,
                "evidence": {
                    "handoff_stage": handoff_stage,
                    "verification_stage": verification_stage,
                    "capability": capability,
                },
            }
        )

    status_counts = count_gate_statuses([{"status": item["task_status"]} for item in tasks])
    action_counts = count_gate_statuses([{"status": item["action"]} for item in tasks])
    capability_status_counts = count_gate_statuses([{"status": item.get("capability_status") or "unknown"} for item in tasks])
    task_quality_summary = production_quality_gate_summary_from_checks(tasks)
    tasks_with_missing_contract_requirements = [
        item for item in tasks if isinstance(item.get("missing_requirements"), list) and item.get("missing_requirements")
    ]
    blocked_tasks = [item for item in tasks if item.get("blocked")]
    high_priority_pending = [
        item
        for item in tasks
        if int(item.get("priority") or 999) <= 40 and item.get("task_status") not in {"ready_to_import"}
    ]
    ready_to_import = [item for item in tasks if item.get("task_status") == "ready_to_import"]
    external_required = [
        item
        for item in tasks
        if item.get("task_status") in {"needs_external_run", "needs_external_result_or_template_fill", "prepared_bridge_only"}
    ]

    report = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_upgrade_task_queue",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "jobs_root": str(jobs_root),
        "timestamp": int(time.time()),
        "summary": {
            "task_count": len(tasks),
            "blocked_count": len(blocked_tasks),
            "ready_to_import": len(ready_to_import),
            "external_action_required": len(external_required),
            "high_priority_pending": len(high_priority_pending),
            "missing_stage_definition_count": len(missing_stage_definitions),
            "status_counts": status_counts,
            "action_counts": action_counts,
            "capability_status_counts": capability_status_counts,
            "audit_status": audit.get("status"),
            "audit_ok": audit.get("ok"),
            "verification_ready_to_import": verification_summary.get("ready_to_import"),
            "verification_empty_template": verification_summary.get("empty_template"),
            "verification_missing_result": verification_summary.get("missing_result"),
            "verification_prepared_only": verification_summary.get("prepared_only"),
            "verification_production_validated": verification_summary.get("production_validated"),
            "verification_quality_warning": verification_summary.get("quality_warning"),
            "verification_quality_pending": verification_summary.get("quality_pending"),
            "verification_quality_status_counts": verification_summary.get("quality_status_counts"),
            "task_production_validated": task_quality_summary.get("production_validated"),
            "task_quality_warning": task_quality_summary.get("quality_warning"),
            "task_quality_pending": task_quality_summary.get("quality_pending"),
            "task_quality_status_counts": task_quality_summary.get("quality_status_counts"),
            "task_contract_missing_requirement_count": len(tasks_with_missing_contract_requirements),
            "verification_contract_missing_requirement_stage_count": verification_summary.get("contract_missing_requirement_stage_count"),
            "target_ready_count": target_summary.get("ready_count"),
            "target_baseline_count": target_summary.get("baseline_count"),
            "target_missing_count": target_summary.get("missing_count"),
            "production_ready": target_summary.get("production_ready"),
            "script_count": audit_summary.get("script_count"),
            "template_count": audit_summary.get("template_count"),
        },
        "tasks": tasks,
        "global_commands": {
            "run_all_prepared_scripts": str(jobs_root / "run_prepared_external_jobs.sh"),
            "audit_before_execution": f"python -m video2mesh.cli audit-production-upgrade-jobs --project-root {project_root}",
            "verify_after_external_results": validation_commands[0],
            "import_ready_results": f"python -m video2mesh.cli import-production-upgrade-results --project-root {project_root} --render-preview --render-semantic-preview --sync-simulator-assets",
            "refresh_target_matrix": f"python -m video2mesh.cli target-capability-matrix --project-root {project_root}",
            "refresh_advisor_summary": f"python -m video2mesh.cli export-advisor-demo-summary --project-root {project_root}",
        },
        "source_reports": {
            "production_upgrade_execution_audit": str(jobs_root / "production_upgrade_execution_audit.json"),
            "production_upgrade_handoff": str(jobs_root / "production_upgrade_handoff.json"),
            "production_upgrade_results_verification": str(jobs_root / "production_upgrade_results_verification.json"),
            "target_capability_matrix": str(project_root / manifest.get("simulator_assets_dir", "simulator_assets") / "target_capability_matrix.json"),
        },
        "missing_stage_definitions": missing_stage_definitions,
        "notes": [
            "This queue is an execution map, not proof that production outputs already exist.",
            "Run heavy stages selectively according to GPU memory, installed dependencies, API credentials, and available time.",
            "After each external stage finishes, rerun verify-production-upgrade-results before importing results.",
            "Only ready_to_import stages should be imported automatically; empty templates and missing results are intentionally left pending.",
            "quality_gate.production_validated is stronger than ready_to_import and records whether local non-heavy checks see production-quality evidence.",
            "result_contract.missing_requirements explains why a prepared template is not yet importable or production-valid.",
        ],
    }
    return report


def write_production_upgrade_task_queue_markdown(report: dict[str, Any], output_path: Path) -> None:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    commands = report.get("global_commands") if isinstance(report.get("global_commands"), dict) else {}
    lines = [
        f"# Video2Mesh Production Upgrade Task Queue: {report.get('scene_id') or 'scene'}",
        "",
        "This queue translates baseline production gaps into concrete external jobs, import commands, and validation commands.",
        "",
        "## Summary",
        "",
        markdown_table(
            ["Field", "Value"],
            [
                ["task_count", summary.get("task_count")],
                ["blocked_count", summary.get("blocked_count")],
                ["ready_to_import", summary.get("ready_to_import")],
                ["external_action_required", summary.get("external_action_required")],
                ["high_priority_pending", summary.get("high_priority_pending")],
                ["verification_production_validated", summary.get("verification_production_validated")],
                ["verification_quality_warning", summary.get("verification_quality_warning")],
                ["verification_quality_pending", summary.get("verification_quality_pending")],
                ["contract_missing_requirement_stages", summary.get("verification_contract_missing_requirement_stage_count")],
                ["missing_stage_definition_count", summary.get("missing_stage_definition_count")],
                ["target ready/baseline/missing", f"{summary.get('target_ready_count')} / {summary.get('target_baseline_count')} / {summary.get('target_missing_count')}"],
                ["production_ready", summary.get("production_ready")],
                ["audit_status", summary.get("audit_status")],
            ],
        ),
        "",
        "## Execution Queue",
        "",
        markdown_table(
            [
                "Priority",
                "Stage",
                "Capability",
                "Status",
                "Quality Gate",
                "Missing Requirements",
                "Action",
                "Script Or Template",
                "Expected Result",
                "Import Command",
            ],
            [
                [
                    item.get("priority"),
                    item.get("stage"),
                    item.get("capability_name"),
                    item.get("task_status"),
                    item.get("quality_status"),
                    ", ".join(str(value) for value in item.get("missing_requirements", [])),
                    item.get("action"),
                    item.get("script_or_template"),
                    item.get("expected_result"),
                    item.get("import_command"),
                ]
                for item in report.get("tasks", [])
            ],
        ),
        "",
        "## Per-stage Detail",
        "",
    ]
    for item in report.get("tasks", []):
        if not isinstance(item, dict):
            continue
        lines.extend(
            [
                f"### {md_cell(item.get('priority'))}. {md_cell(item.get('stage'))}",
                "",
                f"- Capability: {md_cell(item.get('capability_name'))} (`{md_cell(item.get('capability_id'))}`), current status `{md_cell(item.get('capability_status'))}`.",
                f"- Why this matters: {md_cell(item.get('why'))}",
                f"- Current gap: {md_cell(item.get('current_gap'))}",
                f"- Next step: {md_cell(item.get('next_step'))}",
                f"- Quality gate: `{md_cell(item.get('quality_status'))}`, production_validated={md_cell(item.get('production_validated'))}.",
                f"- Missing requirements: {md_cell(item.get('missing_requirements'))}",
                f"- Script/template exists: {md_cell(item.get('script_or_template_exists'))}",
                "",
                "```bash",
            ]
        )
        command = item.get("execution_command")
        if command:
            lines.append(str(command))
        if item.get("import_command"):
            lines.append(str(item.get("import_command")))
        for validation_command in item.get("validation_commands", []):
            lines.append(str(validation_command))
        lines.extend(["```", ""])
        blockers = item.get("blockers") if isinstance(item.get("blockers"), list) else []
        if blockers:
            lines.append(f"- Blockers: {md_cell(blockers)}")
            lines.append("")
        criteria = item.get("acceptance_criteria") if isinstance(item.get("acceptance_criteria"), list) else []
        if criteria:
            lines.append("- Acceptance criteria:")
            for criterion in criteria:
                lines.append(f"  - {md_cell(criterion)}")
            lines.append("")
    lines.extend(["## Global Commands", "", "```bash"])
    for _name, command in commands.items():
        if command:
            lines.append(str(command))
    lines.extend(["```", "", "## Source Reports", "", "| Report | Path |", "| --- | --- |"])
    source_reports = report.get("source_reports") if isinstance(report.get("source_reports"), dict) else {}
    for key, value in sorted(source_reports.items()):
        lines.append(f"| {md_cell(key)} | `{md_cell(value)}` |")
    lines.extend(["", "## Notes", ""])
    for note in report.get("notes", []):
        lines.append(f"- {md_cell(note)}")
    lines.append("")
    ensure_dir(output_path.parent)
    output_path.write_text("\n".join(lines), encoding="utf-8")


def cmd_export_production_upgrade_task_queue(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = project_root / manifest["simulator_assets_dir"] / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    audit_path = jobs_root / "production_upgrade_execution_audit.json"
    handoff_path = jobs_root / "production_upgrade_handoff.json"
    verification_path = jobs_root / "production_upgrade_results_verification.json"
    target_matrix_path = project_root / manifest.get("simulator_assets_dir", "simulator_assets") / "target_capability_matrix.json"
    if args.refresh:
        cmd_audit_production_upgrade_jobs(
            argparse.Namespace(project_root=project_root, jobs_root=jobs_root, output=audit_path, json=False, quiet=True, fail_on_issues=False)
        )
        audit = safe_read_json(audit_path)
        if isinstance(audit, dict):
            handoff = generate_production_upgrade_handoff(project_root, manifest, jobs_root, audit)
            write_json(handoff_path, handoff)
            write_production_upgrade_handoff_markdown(handoff, jobs_root / "production_upgrade_handoff.md")
        target_matrix = generate_target_capability_matrix(project_root, manifest)
        write_json(target_matrix_path, target_matrix)
        write_target_capability_matrix_markdown(target_matrix, target_matrix_path.with_suffix(".md"))
    audit = safe_read_json(audit_path)
    handoff = safe_read_json(handoff_path)
    verification = safe_read_json(verification_path)
    target_matrix = safe_read_json(target_matrix_path)
    if not isinstance(audit, dict):
        raise RuntimeError(f"Failed to read production upgrade audit: {audit_path}")
    if not isinstance(handoff, dict):
        handoff = generate_production_upgrade_handoff(project_root, manifest, jobs_root, audit)
    if not isinstance(verification, dict):
        raise RuntimeError(f"Failed to read production upgrade verification: {verification_path}")
    if not isinstance(target_matrix, dict):
        target_matrix = generate_target_capability_matrix(project_root, manifest)
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else jobs_root / "production_upgrade_task_queue.json"
    markdown_path = resolve_project_cli_path(args.markdown_output, project_root) if args.markdown_output else jobs_root / "production_upgrade_task_queue.md"
    report = generate_production_upgrade_task_queue(project_root, manifest, jobs_root, audit, handoff, verification, target_matrix)
    write_json(output_path, report)
    if not args.no_markdown:
        write_production_upgrade_task_queue_markdown(report, markdown_path)
    manifest = load_manifest(project_root)
    manifest.setdefault("artifacts", {})["production_upgrade_task_queue"] = str(output_path)
    if not args.no_markdown:
        manifest["artifacts"]["production_upgrade_task_queue_markdown"] = str(markdown_path)
    manifest.setdefault("external_stages", {})["production_upgrade_task_queue"] = {
        "status": "ready" if int(report.get("summary", {}).get("blocked_count") or 0) == 0 else "blocked",
        "report": str(output_path),
        "markdown": str(markdown_path) if not args.no_markdown else "",
        "task_count": report.get("summary", {}).get("task_count"),
        "ready_to_import": report.get("summary", {}).get("ready_to_import"),
        "external_action_required": report.get("summary", {}).get("external_action_required"),
    }
    save_manifest(project_root, manifest)

    if args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        summary = report["summary"]
        print(f"Production upgrade task queue: tasks={summary.get('task_count')} ({report['scene_id']})")
        print(
            f"ready={summary.get('ready_to_import')} external_required={summary.get('external_action_required')} "
            f"blocked={summary.get('blocked_count')} high_priority_pending={summary.get('high_priority_pending')}"
        )
        print(f"JSON: {output_path}")
        if not args.no_markdown:
            print(f"Markdown: {markdown_path}")
    return 1 if args.fail_on_blocked and int(report["summary"].get("blocked_count") or 0) else 0


def package_available(package: str) -> bool:
    try:
        return importlib.util.find_spec(package) is not None
    except (ImportError, ValueError):
        return False


def command_available(command: str) -> bool:
    return shutil.which(command) is not None


def env_key_present(name: str) -> bool:
    return bool(str(os.environ.get(name) or "").strip())


def torch_environment_summary() -> dict[str, Any]:
    summary: dict[str, Any] = {
        "torch_importable": False,
        "torch_version": "",
        "cuda_available": False,
        "cuda_device_count": 0,
        "cuda_devices": [],
    }
    try:
        import torch  # type: ignore

        summary["torch_importable"] = True
        summary["torch_version"] = str(getattr(torch, "__version__", ""))
        cuda_available = bool(torch.cuda.is_available())
        summary["cuda_available"] = cuda_available
        if cuda_available:
            count = int(torch.cuda.device_count())
            summary["cuda_device_count"] = count
            devices = []
            for idx in range(count):
                props = torch.cuda.get_device_properties(idx)
                devices.append(
                    {
                        "index": idx,
                        "name": str(props.name),
                        "total_memory_gb": round(float(props.total_memory) / (1024**3), 3),
                        "major": int(props.major),
                        "minor": int(props.minor),
                    }
                )
            summary["cuda_devices"] = devices
    except Exception as exc:  # pragma: no cover - environment dependent
        summary["error"] = str(exc)
    return summary


