def evaluate_requirement_any(names: list[str], kind: str, project_root: Path) -> dict[str, Any]:
    results = []
    for name in names:
        if kind == "package":
            available = package_available(name)
        elif kind == "command":
            available = command_available(name)
        elif kind == "env":
            available = env_key_present(name)
        elif kind == "path":
            path = resolve_project_cli_path(Path(name), project_root)
            available = path.exists()
        else:
            available = False
        item = {"name": name, "available": bool(available)}
        if kind == "path":
            item["path"] = str(resolve_project_cli_path(Path(name), project_root))
        results.append(item)
    return {"any_available": any(item["available"] for item in results), "items": results}


def stage_environment_status(
    stage: str,
    requirement: dict[str, Any],
    project_root: Path,
    torch_summary: dict[str, Any],
    task: dict[str, Any] | None = None,
) -> dict[str, Any]:
    required = requirement.get("required") if isinstance(requirement.get("required"), dict) else {}
    checks: dict[str, Any] = {}
    blockers: list[str] = []
    warnings: list[str] = []

    if required.get("cuda"):
        cuda_ok = bool(torch_summary.get("cuda_available"))
        checks["cuda"] = {
            "required": True,
            "available": cuda_ok,
            "device_count": torch_summary.get("cuda_device_count"),
            "devices": torch_summary.get("cuda_devices"),
        }
        if not cuda_ok:
            blockers.append("cuda_unavailable")
    else:
        checks["cuda"] = {"required": False, "available": bool(torch_summary.get("cuda_available"))}

    packages = required.get("packages_any") if isinstance(required.get("packages_any"), list) else []
    if packages:
        package_check = evaluate_requirement_any([str(item) for item in packages], "package", project_root)
        checks["packages_any"] = package_check
        if not package_check["any_available"]:
            warnings.append("no_preferred_package_detected")

    commands = required.get("commands_any") if isinstance(required.get("commands_any"), list) else []
    if commands:
        command_check = evaluate_requirement_any([str(item) for item in commands], "command", project_root)
        checks["commands_any"] = command_check
        if not command_check["any_available"]:
            warnings.append("no_preferred_command_detected")

    env_keys = required.get("env_any") if isinstance(required.get("env_any"), list) else []
    if env_keys:
        env_check = evaluate_requirement_any([str(item) for item in env_keys], "env", project_root)
        checks["env_any"] = env_check
        if not env_check["any_available"]:
            blockers.append("missing_required_api_key_or_manual_alternative")

    paths = required.get("paths_any") if isinstance(required.get("paths_any"), list) else []
    if paths:
        path_check = evaluate_requirement_any([str(item) for item in paths], "path", project_root)
        checks["paths_any"] = path_check
        if not path_check["any_available"]:
            warnings.append("no_reference_repo_or_path_detected")

    if required.get("manual_input"):
        checks["manual_input"] = {"required": True, "available": False}
        blockers.append("manual_measurement_or_annotation_required")

    task_status = str(task.get("task_status") if isinstance(task, dict) else "")
    task_action = str(task.get("action") if isinstance(task, dict) else "")
    script_or_template = str(task.get("script_or_template") if isinstance(task, dict) else "")
    if task_status in {"needs_external_result_or_template_fill", "prepared_bridge_only"}:
        checks["prepared_task"] = {
            "task_status": task_status,
            "action": task_action,
            "script_or_template": script_or_template,
            "requires_external_result": True,
        }
        if task_action in {"fill_template_or_run_external_job", "execute_external_bridge"}:
            if "external_result_or_bridge_not_executed" not in warnings:
                warnings.append("external_result_or_bridge_not_executed")
    if task_status == "needs_external_run":
        checks["prepared_task"] = {
            "task_status": task_status,
            "action": task_action,
            "script_or_template": script_or_template,
            "requires_external_result": True,
        }

    if blockers:
        status = "blocked_or_manual"
    elif warnings:
        status = "possibly_runnable_with_setup"
    else:
        status = "runnable_environment_detected"
    return {
        "stage": stage,
        "label": requirement.get("label") or stage,
        "status": status,
        "checks": checks,
        "blockers": blockers,
        "warnings": warnings,
        "soft_requirements": requirement.get("soft_requirements") or [],
    }


def generate_production_backend_environment_report(
    project_root: Path,
    manifest: dict[str, Any],
    task_queue: dict[str, Any] | None = None,
) -> dict[str, Any]:
    requirements = production_backend_stage_requirements()
    torch_summary = torch_environment_summary()
    task_map = {}
    if isinstance(task_queue, dict) and isinstance(task_queue.get("tasks"), list):
        for task in task_queue["tasks"]:
            if isinstance(task, dict) and task.get("stage"):
                task_map[str(task["stage"])] = task
    stage_reports = [
        stage_environment_status(stage, requirement, project_root, torch_summary, task_map.get(stage))
        for stage, requirement in sorted(requirements.items(), key=lambda item: production_handoff_stage_priority(item[0]))
    ]
    for report in stage_reports:
        task = task_map.get(str(report.get("stage")))
        if task:
            report["task_status"] = task.get("task_status")
            report["task_action"] = task.get("action")
            report["task_priority"] = task.get("priority")
    status_counts = count_gate_statuses([{"status": item["status"]} for item in stage_reports])
    runnable = [item for item in stage_reports if item["status"] == "runnable_environment_detected"]
    setup = [item for item in stage_reports if item["status"] == "possibly_runnable_with_setup"]
    blocked = [item for item in stage_reports if item["status"] == "blocked_or_manual"]
    return {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_backend_environment",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "timestamp": int(time.time()),
        "summary": {
            "runnable_environment_detected": len(runnable),
            "possibly_runnable_with_setup": len(setup),
            "blocked_or_manual": len(blocked),
            "status_counts": status_counts,
            "torch_cuda_available": torch_summary.get("cuda_available"),
            "cuda_device_count": torch_summary.get("cuda_device_count"),
            "task_queue_linked": bool(task_map),
        },
        "environment": {
            "python": sys.executable,
            "platform": sys.platform,
            "torch": torch_summary,
            "commands": {
                "python": shutil.which("python") or "",
                "python3": shutil.which("python3") or "",
                "ns-train": shutil.which("ns-train") or "",
                "colmap": shutil.which("colmap") or "",
                "nvidia-smi": shutil.which("nvidia-smi") or "",
            },
            "packages": {
                name: package_available(name)
                for name in [
                    "torch",
                    "gsplat",
                    "nerfstudio",
                    "segment_anything",
                    "sam2",
                    "open3d",
                    "trimesh",
                    "fal_client",
                    "openai",
                    "anthropic",
                    "transformers",
                    "ultralytics",
                ]
            },
            "api_keys_present": {
                name: env_key_present(name)
                for name in [
                    "OPENAI_API_KEY",
                    "ANTHROPIC_API_KEY",
                    "DASHSCOPE_API_KEY",
                    "GOOGLE_API_KEY",
                    "FAL_KEY",
                    "FAL_API_KEY",
                    "MESHY_API_KEY",
                    "HUNYUAN3D_API_KEY",
                ]
            },
        },
        "stages": stage_reports,
        "notes": [
            "This report is read-only. It does not execute heavy trainers, video segmenters, VLM calls, mesh APIs, or SceneVerse++ scripts.",
            "API key checks only record whether an environment variable is present; values are never written.",
            "blocked_or_manual can be acceptable for local Mac review runs; execute those stages on a GPU/API/manual environment and import results later.",
        ],
    }


def write_production_backend_environment_markdown(report: dict[str, Any], output_path: Path) -> None:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    env = report.get("environment") if isinstance(report.get("environment"), dict) else {}
    torch_env = env.get("torch") if isinstance(env.get("torch"), dict) else {}
    lines = [
        f"# Video2Mesh Production Backend Environment: {report.get('scene_id') or 'scene'}",
        "",
        "This read-only audit maps the current machine environment to the production upgrade stages.",
        "",
        "## Summary",
        "",
        markdown_table(
            ["Field", "Value"],
            [
                ["runnable_environment_detected", summary.get("runnable_environment_detected")],
                ["possibly_runnable_with_setup", summary.get("possibly_runnable_with_setup")],
                ["blocked_or_manual", summary.get("blocked_or_manual")],
                ["torch_cuda_available", summary.get("torch_cuda_available")],
                ["cuda_device_count", summary.get("cuda_device_count")],
                ["task_queue_linked", summary.get("task_queue_linked")],
                ["python", env.get("python")],
                ["torch_version", torch_env.get("torch_version")],
            ],
        ),
        "",
        "## Stage Environment Matrix",
        "",
        markdown_table(
            ["Stage", "Status", "Task Status", "Blockers", "Warnings"],
            [
                [
                    item.get("stage"),
                    item.get("status"),
                    item.get("task_status"),
                    item.get("blockers"),
                    item.get("warnings"),
                ]
                for item in report.get("stages", [])
            ],
        ),
        "",
        "## Package Snapshot",
        "",
        markdown_table(
            ["Package", "Available"],
            [[key, value] for key, value in sorted((env.get("packages") or {}).items())],
        ),
        "",
        "## API Key Presence",
        "",
        markdown_table(
            ["Key", "Present"],
            [[key, value] for key, value in sorted((env.get("api_keys_present") or {}).items())],
        ),
        "",
        "## Notes",
        "",
    ]
    for note in report.get("notes", []):
        lines.append(f"- {md_cell(note)}")
    lines.append("")
    ensure_dir(output_path.parent)
    output_path.write_text("\n".join(lines), encoding="utf-8")


def cmd_production_backend_environment(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    sim_dir = project_root / manifest.get("simulator_assets_dir", "simulator_assets")
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = sim_dir / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    task_queue_path = resolve_existing_artifact_or_default(
        project_root,
        manifest.get("artifacts", {}).get("production_upgrade_task_queue"),
        jobs_root / "production_upgrade_task_queue.json",
    )
    task_queue = safe_read_json(task_queue_path)
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else sim_dir / "production_backend_environment.json"
    markdown_path = resolve_project_cli_path(args.markdown_output, project_root) if args.markdown_output else sim_dir / "production_backend_environment.md"
    report = generate_production_backend_environment_report(project_root, manifest, task_queue if isinstance(task_queue, dict) else None)
    write_json(output_path, report)
    if not args.no_markdown:
        write_production_backend_environment_markdown(report, markdown_path)
    manifest.setdefault("artifacts", {})["production_backend_environment"] = str(output_path)
    if not args.no_markdown:
        manifest["artifacts"]["production_backend_environment_markdown"] = str(markdown_path)
    manifest.setdefault("external_stages", {})["production_backend_environment"] = {
        "status": "audited",
        "report": str(output_path),
        "markdown": str(markdown_path) if not args.no_markdown else "",
        "summary": report.get("summary"),
    }
    save_manifest(project_root, manifest)
    if args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        summary = report["summary"]
        print(f"Production backend environment: {report['scene_id']}")
        print(
            f"runnable={summary.get('runnable_environment_detected')} "
            f"setup={summary.get('possibly_runnable_with_setup')} "
            f"blocked_or_manual={summary.get('blocked_or_manual')} "
            f"cuda={summary.get('torch_cuda_available')}"
        )
        print(f"JSON: {output_path}")
        if not args.no_markdown:
            print(f"Markdown: {markdown_path}")
    return 1 if args.fail_on_blocked and int(report["summary"].get("blocked_or_manual") or 0) else 0


PRODUCTION_EXECUTION_LANE_LABELS = {
    "local_import_ready": "Local import ready",
    "local_or_current_environment_execution": "Current environment execution",
    "setup_then_execute": "Setup then execute",
    "gpu_server_execution": "GPU server execution",
    "api_or_manual_execution": "API/manual execution",
    "external_setup_required": "External setup required",
    "post_import_validation": "Post-import validation",
}


def production_execution_lane_for_stage(
    stage: str,
    task: dict[str, Any],
    env_stage: dict[str, Any] | None,
) -> dict[str, Any]:
    task_status = str(task.get("task_status") or "")
    quality_gate = task.get("quality_gate") if isinstance(task.get("quality_gate"), dict) else {}
    result_contract = task.get("result_contract") if isinstance(task.get("result_contract"), dict) else {}
    acceptance_criteria = task.get("acceptance_criteria") if isinstance(task.get("acceptance_criteria"), list) else []
    env_status = str(env_stage.get("status") if isinstance(env_stage, dict) else "")
    blockers = [str(item) for item in (env_stage.get("blockers") if isinstance(env_stage, dict) and isinstance(env_stage.get("blockers"), list) else [])]
    warnings = [str(item) for item in (env_stage.get("warnings") if isinstance(env_stage, dict) and isinstance(env_stage.get("warnings"), list) else [])]
    why: list[str] = []

    if task_status == "ready_to_import":
        lane = "local_import_ready"
        location = "local_or_current_project"
        why.append("external result is already verified as importable")
    elif "manual_measurement_or_annotation_required" in blockers or "missing_required_api_key_or_manual_alternative" in blockers:
        lane = "api_or_manual_execution"
        location = "api_provider_or_manual_review"
        why.extend(blockers)
    elif "cuda_unavailable" in blockers:
        lane = "gpu_server_execution"
        location = "cuda_gpu_server"
        why.append("current environment has no CUDA for this stage")
    elif env_status == "runnable_environment_detected":
        lane = "local_or_current_environment_execution"
        location = "current_environment"
        why.append("required runtime appears available in the current environment")
    elif env_status == "possibly_runnable_with_setup":
        lane = "setup_then_execute"
        location = "current_environment_after_dependency_setup"
        why.extend(warnings or ["preferred packages or commands need setup"])
    elif task_status == "prepared_bridge_only":
        lane = "external_setup_required"
        location = "external_backend_environment"
        why.append("stage is a prepared bridge and still needs backend execution")
    else:
        lane = "external_setup_required"
        location = "external_backend_environment"
        if blockers:
            why.extend(blockers)
        if warnings:
            why.extend(warnings)
        if not why:
            why.append("stage still needs external execution or result inspection")

    validation = list(task.get("validation_commands") if isinstance(task.get("validation_commands"), list) else [])
    if task.get("import_command"):
        validation = [str(task.get("import_command"))] + [str(item) for item in validation]
    return {
        "stage": stage,
        "lane": lane,
        "lane_label": PRODUCTION_EXECUTION_LANE_LABELS.get(lane, lane),
        "location": location,
        "why": why,
        "task_status": task_status,
        "task_action": task.get("action"),
        "environment_status": env_status,
        "environment_blockers": blockers,
        "environment_warnings": warnings,
        "script_or_template": task.get("script_or_template") or "",
        "execution_command": task.get("execution_command") or "",
        "expected_result": task.get("expected_result") or "",
        "import_command": task.get("import_command") or "",
        "validation_commands": validation,
        "priority": task.get("priority"),
        "capability_id": task.get("capability_id"),
        "capability_name": task.get("capability_name"),
        "current_gap": task.get("current_gap"),
        "next_step": task.get("next_step"),
        "quality_gate": quality_gate,
        "quality_status": quality_gate.get("status"),
        "production_validated": bool(quality_gate.get("production_validated")),
        "result_contract": result_contract,
        "missing_requirements": result_contract.get("missing_requirements") if isinstance(result_contract.get("missing_requirements"), list) else [],
        "acceptance_criteria": acceptance_criteria,
    }


def production_execution_plan_stage_maps(
    task_queue: dict[str, Any],
    backend_environment: dict[str, Any],
) -> tuple[dict[str, dict[str, Any]], dict[str, dict[str, Any]]]:
    tasks = task_queue.get("tasks") if isinstance(task_queue.get("tasks"), list) else []
    stages = backend_environment.get("stages") if isinstance(backend_environment.get("stages"), list) else []
    task_map = {str(item.get("stage")): item for item in tasks if isinstance(item, dict) and item.get("stage")}
    env_map = {str(item.get("stage")): item for item in stages if isinstance(item, dict) and item.get("stage")}
    return task_map, env_map


def generate_production_upgrade_execution_plan(
    project_root: Path,
    manifest: dict[str, Any],
    jobs_root: Path,
    task_queue: dict[str, Any],
    backend_environment: dict[str, Any],
) -> dict[str, Any]:
    task_map, env_map = production_execution_plan_stage_maps(task_queue, backend_environment)
    stage_names = sorted(
        set(task_map.keys()) | set(env_map.keys()),
        key=lambda name: int(task_map.get(name, {}).get("priority") or production_handoff_stage_priority(name)),
    )
    lanes: dict[str, list[dict[str, Any]]] = {key: [] for key in PRODUCTION_EXECUTION_LANE_LABELS}
    stages: list[dict[str, Any]] = []
    for stage in stage_names:
        task = task_map.get(stage, {"stage": stage, "task_status": "unknown", "action": "inspect_stage"})
        env_stage = env_map.get(stage, {})
        item = production_execution_lane_for_stage(stage, task, env_stage)
        stages.append(item)
        lanes.setdefault(str(item["lane"]), []).append(item)

    lane_counts = {lane: len(items) for lane, items in lanes.items() if items}
    quality_counts = count_gate_statuses([{"status": item.get("quality_status") or "missing_quality_gate"} for item in stages])
    production_validated = [item.get("stage") for item in stages if item.get("production_validated")]
    quality_warning = [item.get("stage") for item in stages if item.get("quality_status") == "import_ready_quality_warning"]
    quality_pending = [
        item.get("stage")
        for item in stages
        if item.get("quality_status") in {"pending", "import_ready_quality_pending", "missing_quality_gate", None, ""}
    ]
    contract_missing = [item.get("stage") for item in stages if item.get("missing_requirements")]
    backend_summary = backend_environment.get("summary") if isinstance(backend_environment.get("summary"), dict) else {}
    task_summary = task_queue.get("summary") if isinstance(task_queue.get("summary"), dict) else {}
    validation_commands = production_task_validation_commands(project_root)
    script_path = jobs_root / "run_production_upgrade_execution_plan.sh"
    return {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "stage": "production_upgrade_execution_plan",
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "jobs_root": str(jobs_root),
        "timestamp": int(time.time()),
        "summary": {
            "task_count": len(stages),
            "lane_counts": lane_counts,
            "local_import_ready": lane_counts.get("local_import_ready", 0),
            "local_or_current_environment_execution": lane_counts.get("local_or_current_environment_execution", 0),
            "setup_then_execute": lane_counts.get("setup_then_execute", 0),
            "gpu_server_execution": lane_counts.get("gpu_server_execution", 0),
            "api_or_manual_execution": lane_counts.get("api_or_manual_execution", 0),
            "external_setup_required": lane_counts.get("external_setup_required", 0),
            "blocked_by_current_environment": lane_counts.get("gpu_server_execution", 0)
            + lane_counts.get("api_or_manual_execution", 0)
            + lane_counts.get("external_setup_required", 0),
            "post_import_validation_count": len(validation_commands),
            "cuda_available": backend_summary.get("torch_cuda_available"),
            "task_queue_ready_to_import": task_summary.get("ready_to_import"),
            "task_queue_external_action_required": task_summary.get("external_action_required"),
            "production_validated": len(production_validated),
            "production_validated_stages": production_validated,
            "quality_warning": len(quality_warning),
            "quality_warning_stages": quality_warning,
            "quality_pending": len(quality_pending),
            "quality_pending_stages": quality_pending,
            "quality_status_counts": quality_counts,
            "contract_missing_requirement_stage_count": len(contract_missing),
            "contract_missing_requirement_stages": contract_missing,
            "script_path": str(script_path),
        },
        "stages": stages,
        "lanes": {lane: [item.get("stage") for item in items] for lane, items in lanes.items() if items},
        "post_import_validation": validation_commands,
        "source_reports": {
            "production_upgrade_task_queue": str(jobs_root / "production_upgrade_task_queue.json"),
            "production_backend_environment": str(project_root / manifest.get("simulator_assets_dir", "simulator_assets") / "production_backend_environment.json"),
        },
        "script": {
            "path": str(script_path),
            "default_mode": "dry_run",
            "run_heavy_env": "RUN_HEAVY=1",
            "run_imports_env": "RUN_IMPORTS=1",
            "run_validation_env": "RUN_VALIDATION=1",
            "stage_filter_env": "RUN_STAGES=stage_a,stage_b",
        },
        "notes": [
            "This plan routes prepared production-upgrade tasks to local review/import, GPU server execution, API/manual work, or setup-first execution.",
            "The generated shell script is safe by default: it prints commands unless RUN_HEAVY, RUN_IMPORTS, or RUN_VALIDATION are enabled.",
            "Set RUN_STAGES to a comma-separated list such as high_quality_3dgs,video_segmentation to run only selected stage blocks.",
            "Do not claim production readiness from this plan alone. Production readiness requires external results to be imported and validators to pass.",
            "quality_status is carried forward from verify-production-upgrade-results; production_validated is stricter than local_import_ready.",
        ],
    }


def write_production_upgrade_execution_plan_markdown(report: dict[str, Any], output_path: Path) -> None:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        f"# Video2Mesh Production Upgrade Execution Plan: {report.get('scene_id') or 'scene'}",
        "",
        "This plan combines the production task queue with the current backend environment audit.",
        "",
        "## Summary",
        "",
        markdown_table(
            ["Field", "Value"],
            [
                ["task_count", summary.get("task_count")],
                ["local_import_ready", summary.get("local_import_ready")],
                ["local_or_current_environment_execution", summary.get("local_or_current_environment_execution")],
                ["setup_then_execute", summary.get("setup_then_execute")],
                ["gpu_server_execution", summary.get("gpu_server_execution")],
                ["api_or_manual_execution", summary.get("api_or_manual_execution")],
                ["external_setup_required", summary.get("external_setup_required")],
                ["blocked_by_current_environment", summary.get("blocked_by_current_environment")],
                ["production_validated", summary.get("production_validated")],
                ["quality_warning", summary.get("quality_warning")],
                ["quality_pending", summary.get("quality_pending")],
                ["contract_missing_requirement_stages", summary.get("contract_missing_requirement_stage_count")],
                ["cuda_available", summary.get("cuda_available")],
                ["script_path", summary.get("script_path")],
            ],
        ),
        "",
        "## Stage Routing",
        "",
        markdown_table(
            ["Priority", "Stage", "Task Status", "Quality", "Missing Requirements", "Environment", "Lane", "Why", "Command Or Template", "Import/Validation"],
            [
                [
                    item.get("priority"),
                    item.get("stage"),
                    item.get("task_status"),
                    item.get("quality_status"),
                    ", ".join(str(value) for value in item.get("missing_requirements", [])),
                    item.get("environment_status"),
                    item.get("lane"),
                    "; ".join(str(value) for value in item.get("why", [])),
                    item.get("execution_command") or item.get("script_or_template"),
                    item.get("import_command") or (item.get("validation_commands") or [""])[0],
                ]
                for item in report.get("stages", [])
            ],
        ),
        "",
        "## Lanes",
        "",
    ]
    lanes = report.get("lanes") if isinstance(report.get("lanes"), dict) else {}
    for lane, stage_names in lanes.items():
        lines.extend([f"### {md_cell(PRODUCTION_EXECUTION_LANE_LABELS.get(lane, lane))}", ""])
        for stage_name in stage_names:
            lines.append(f"- `{md_cell(stage_name)}`")
        lines.append("")
    lines.extend(
        [
            "## Safe Runner",
            "",
            "```bash",
            f"bash {report.get('script', {}).get('path')}",
            "RUN_HEAVY=1 bash <script>      # execute heavy/script stages",
            "RUN_IMPORTS=1 bash <script>    # execute ready import commands",
            "RUN_VALIDATION=1 bash <script> # execute validation commands",
            "RUN_STAGES=sceneversepp bash <script>",
            "RUN_STAGES=high_quality_3dgs,video_segmentation RUN_HEAVY=1 bash <script>",
            "```",
            "",
        ]
    )
    lines.extend(["## Notes", ""])
    for note in report.get("notes", []):
        lines.append(f"- {md_cell(note)}")
    lines.append("")
    ensure_dir(output_path.parent)
    output_path.write_text("\n".join(lines), encoding="utf-8")


def production_runner_cli_command(command: str) -> str:
    command = str(command or "").strip()
    prefix = "python -m video2mesh.cli"
    if command == prefix:
        return '"${V2M_PYTHON}" -B -m video2mesh.cli'
    if command.startswith(prefix + " "):
        return '"${V2M_PYTHON}" -B -m video2mesh.cli ' + command[len(prefix) + 1 :]
    return command


def write_production_upgrade_execution_script(report: dict[str, Any], script_path: Path) -> None:
    project_root = str(report.get("project_root") or "")
    jobs_root = str(report.get("jobs_root") or "")
    lines = [
        "#!/usr/bin/env bash",
        "set -euo pipefail",
        "",
        f"PROJECT_ROOT={shlex.quote(project_root)}",
        f"JOBS_ROOT={shlex.quote(jobs_root)}",
        'RUN_HEAVY="${RUN_HEAVY:-0}"',
        'RUN_IMPORTS="${RUN_IMPORTS:-0}"',
        'RUN_VALIDATION="${RUN_VALIDATION:-0}"',
        'RUN_STAGES="${RUN_STAGES:-${STAGE_FILTER:-}}"',
        'if [[ -z "${V2M_PYTHON:-}" ]]; then',
        "  if [[ -x /root/autodl-tmp/venvs/v2m-svpp/bin/python ]]; then",
        "    V2M_PYTHON=/root/autodl-tmp/venvs/v2m-svpp/bin/python",
        "  elif command -v python3 >/dev/null 2>&1; then",
        "    V2M_PYTHON=$(command -v python3)",
        "  elif command -v python >/dev/null 2>&1; then",
        "    V2M_PYTHON=$(command -v python)",
        "  else",
        '    echo "ERROR: no Python interpreter found; set V2M_PYTHON=/path/to/python" >&2',
        "    exit 2",
        "  fi",
        "fi",
        'export V2M_PYTHON',
        'if [[ -d /root/autodl-tmp/venvs/v2m-svpp/bin ]]; then',
        '  export PATH="/root/autodl-tmp/venvs/v2m-svpp/bin:${PATH}"',
        "fi",
        "",
        'run_or_echo() {',
        '  local gate="$1"',
        '  shift',
        '  if [ "$gate" = "1" ]; then',
        '    "$@"',
        '  else',
        '    printf "[dry-run] "',
        '    printf "%q " "$@"',
        '    printf "\\n"',
        "  fi",
        "}",
        "",
        'stage_selected() {',
        '  local stage="$1"',
        '  local filter="${RUN_STAGES:-}"',
        '  filter="${filter// /}"',
        '  filter="${filter//;/,}"',
        '  if [[ -z "$filter" || "$filter" == "all" || "$filter" == "*" ]]; then',
        "    return 0",
        "  fi",
        '  filter=",${filter},"',
        '  [[ "$filter" == *",${stage},"* ]]',
        "}",
        "",
        'echo "Video2Mesh production upgrade execution plan"',
        'echo "PROJECT_ROOT=${PROJECT_ROOT}"',
        'echo "JOBS_ROOT=${JOBS_ROOT}"',
        'echo "V2M_PYTHON=${V2M_PYTHON}"',
        'echo "RUN_STAGES=${RUN_STAGES:-all}"',
        "",
    ]
    for item in report.get("stages", []):
        if not isinstance(item, dict):
            continue
        stage = str(item.get("stage") or "")
        lane = str(item.get("lane") or "")
        lines.extend(
            [
                f"if stage_selected {shlex.quote(stage)}; then",
                f'echo "== {stage} [{lane}] =="',
                f'echo "task_status={item.get("task_status")} environment_status={item.get("environment_status")}"',
            ]
        )
        command = str(item.get("execution_command") or "")
        if command and not command.lstrip().startswith("#"):
            lines.append(f"  run_or_echo \"$RUN_HEAVY\" bash -lc {shlex.quote(command)}")
        elif command:
            lines.append(f"  echo {shlex.quote(command)}")
        import_command = str(item.get("import_command") or "")
        if import_command:
            if "<" in import_command or ">" in import_command or " / " in import_command:
                lines.append(f"  echo {shlex.quote('# import after filling real result path: ' + import_command)}")
            else:
                import_command = production_runner_cli_command(import_command)
                lines.append(f"  run_or_echo \"$RUN_IMPORTS\" bash -lc {shlex.quote(import_command)}")
        lines.extend(
            [
                "else",
                f'  echo "== {stage} [{lane}] skipped =="',
                '  echo "skipped_by_RUN_STAGES=${RUN_STAGES}"',
                "fi",
                "",
            ]
        )
    lines.append('echo "== post-import validation =="')
    for command in report.get("post_import_validation", []):
        if command:
            command = production_runner_cli_command(str(command))
            lines.append(f"run_or_echo \"$RUN_VALIDATION\" bash -lc {shlex.quote(command)}")
    lines.append("")
    ensure_dir(script_path.parent)
    script_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    script_path.chmod(0o755)


def cmd_export_production_upgrade_execution_plan(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    sim_dir = project_root / manifest.get("simulator_assets_dir", "simulator_assets")
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = sim_dir / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
    if args.refresh:
        cmd_export_production_upgrade_task_queue(
            argparse.Namespace(
                project_root=project_root,
                jobs_root=jobs_root,
                output=None,
                markdown_output=None,
                refresh=True,
                no_markdown=False,
                json=False,
                fail_on_blocked=False,
            )
        )
        cmd_production_backend_environment(
            argparse.Namespace(
                project_root=project_root,
                jobs_root=jobs_root,
                output=None,
                markdown_output=None,
                no_markdown=False,
                json=False,
                fail_on_blocked=False,
            )
        )
        manifest = load_manifest(project_root)
    task_queue_path = resolve_existing_artifact_or_default(
        project_root,
        manifest.get("artifacts", {}).get("production_upgrade_task_queue"),
        jobs_root / "production_upgrade_task_queue.json",
    )
    backend_environment_path = resolve_existing_artifact_or_default(
        project_root,
        manifest.get("artifacts", {}).get("production_backend_environment"),
        sim_dir / "production_backend_environment.json",
    )
    task_queue = safe_read_json(task_queue_path)
    backend_environment = safe_read_json(backend_environment_path)
    if not isinstance(task_queue, dict):
        raise RuntimeError(f"Failed to read production upgrade task queue: {task_queue_path}")
    if not isinstance(backend_environment, dict):
        raise RuntimeError(f"Failed to read production backend environment: {backend_environment_path}")
    output_path = resolve_project_cli_path(args.output, project_root) if args.output else jobs_root / "production_upgrade_execution_plan.json"
    markdown_path = resolve_project_cli_path(args.markdown_output, project_root) if args.markdown_output else jobs_root / "production_upgrade_execution_plan.md"
    script_path = resolve_project_cli_path(args.script_output, project_root) if args.script_output else jobs_root / "run_production_upgrade_execution_plan.sh"
    report = generate_production_upgrade_execution_plan(project_root, manifest, jobs_root, task_queue, backend_environment)
    report["script"]["path"] = str(script_path)
    report["summary"]["script_path"] = str(script_path)
    write_json(output_path, report)
    if not args.no_markdown:
        write_production_upgrade_execution_plan_markdown(report, markdown_path)
    if not args.no_script:
        write_production_upgrade_execution_script(report, script_path)
    manifest.setdefault("artifacts", {})["production_upgrade_execution_plan"] = str(output_path)
    if not args.no_markdown:
        manifest["artifacts"]["production_upgrade_execution_plan_markdown"] = str(markdown_path)
    if not args.no_script:
        manifest["artifacts"]["production_upgrade_execution_plan_script"] = str(script_path)
    manifest.setdefault("external_stages", {})["production_upgrade_execution_plan"] = {
        "status": "planned",
        "report": str(output_path),
        "markdown": str(markdown_path) if not args.no_markdown else "",
        "script": str(script_path) if not args.no_script else "",
        "summary": report.get("summary"),
    }
    save_manifest(project_root, manifest)
    if args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        summary = report["summary"]
        print(f"Production upgrade execution plan: tasks={summary.get('task_count')} ({report['scene_id']})")
        print(
            f"gpu={summary.get('gpu_server_execution')} api_or_manual={summary.get('api_or_manual_execution')} "
            f"setup={summary.get('setup_then_execute')} local={summary.get('local_or_current_environment_execution')} "
            f"import_ready={summary.get('local_import_ready')}"
        )
        print(f"JSON: {output_path}")
        if not args.no_markdown:
            print(f"Markdown: {markdown_path}")
        if not args.no_script:
            print(f"Script: {script_path}")
    return 0


def run_production_import_stage(
    report: dict[str, Any],
    stage_name: str,
    fn,
    *,
    allow_failures: bool,
) -> bool:
    start = time.time()
    try:
        result = fn()
        if isinstance(result, int) and result != 0:
            raise RuntimeError(f"{stage_name} returned non-zero exit code {result}")
        report.setdefault("stages", {})[stage_name] = {
            "status": "imported",
            "elapsed_seconds": round(time.time() - start, 3),
        }
        return True
    except Exception as exc:
        report.setdefault("stages", {})[stage_name] = {
            "status": "failed",
            "elapsed_seconds": round(time.time() - start, 3),
            "error": str(exc),
        }
        if not allow_failures:
            raise
        return False


def cmd_import_production_upgrade_results(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    jobs_root_value = args.jobs_root
    if jobs_root_value is None:
        prepared_jobs = manifest.get("artifacts", {}).get("production_upgrade_jobs")
        if prepared_jobs:
            jobs_root_value = Path(str(prepared_jobs)).parent
        else:
            jobs_root_value = project_root / manifest["simulator_assets_dir"] / "production_upgrade_jobs"
    jobs_root = resolve_project_cli_path(jobs_root_value, project_root)
