def remap_review_asset_path(path_value: str | None, review_dir: Path, project_root: Path | None = None) -> Path | None:
    if not path_value:
        return None
    text = str(path_value)
    raw = Path(text)
    candidates: list[Path] = []
    if raw.is_absolute():
        candidates.append(raw)
    else:
        candidates.append((project_root / raw) if project_root else (review_dir / raw))

    if project_root:
        # Reports generated on a remote server can contain absolute paths. When an
        # export directory is copied locally, map those paths back into this run.
        for anchor in ["simulator_assets", "objects", "scene", "masks"]:
            marker = f"{anchor}/"
            if marker in text:
                suffix = text.split(marker, 1)[1]
                candidates.append(project_root / anchor / suffix)

    for candidate in candidates:
        if candidate.exists():
            return candidate
    return candidates[-1] if candidates else None


def local_review_path(path_value: str | None, review_dir: Path, project_root: Path | None = None) -> str:
    if not path_value:
        return ""
    path = remap_review_asset_path(path_value, review_dir, project_root)
    if path is None:
        return ""
    review_base = review_dir.resolve()
    try:
        project_base = project_root.resolve() if project_root else None
        resolved = path.resolve()
        if project_base and not resolved.is_relative_to(project_base):
            return html.escape(str(path))
        return html.escape(os.path.relpath(resolved, review_base))
    except Exception:
        return html.escape(str(path))


def review_image_tag(path_value: str | None, review_dir: Path, alt: str, project_root: Path | None = None) -> str:
    if not path_value:
        return '<div class="missing">missing image</div>'
    path = remap_review_asset_path(path_value, review_dir, project_root)
    if not path.exists():
        return f'<div class="missing">missing image<br><code>{html.escape(str(path))}</code></div>'
    src = local_review_path(str(path), review_dir, project_root)
    return f'<img src="{src}" alt="{html.escape(alt)}" loading="lazy">'


def issue_badges(issues: list[dict[str, Any]]) -> str:
    if not issues:
        return '<span class="badge ok">ready</span>'
    badges = []
    for issue in issues:
        severity = html.escape(str(issue.get("severity", "warning")))
        name = html.escape(str(issue.get("name", "issue")))
        badges.append(f'<span class="badge {severity}">{severity}: {name}</span>')
    return "\n".join(badges)


def first_existing_path(values: list[str | None], project_root: Path) -> Path | None:
    for value in values:
        path = resolve_existing_path(value, project_root)
        if path and path.exists():
            return path
    return None


def preview_frame_items(preview: Any, image_keys: list[str], max_frames: int, project_root: Path) -> list[dict[str, Any]]:
    if not isinstance(preview, dict):
        return []
    items = []
    frames = preview.get("frames") if isinstance(preview.get("frames"), list) else []
    for frame in frames:
        if not isinstance(frame, dict) or frame.get("skipped"):
            continue
        image_path = first_existing_path([frame.get(key) for key in image_keys], project_root)
        if image_path is None:
            continue
        items.append(
            {
                "frame_id": frame.get("frame_id"),
                "image": str(image_path),
                "metrics": {key: value for key, value in frame.items() if isinstance(value, (int, float))},
            }
        )
        if max_frames > 0 and len(items) >= max_frames:
            break
    return items


def review_display_path(path_value: str | None, review_dir: Path, project_root: Path) -> str:
    if not path_value:
        return ""
    return local_review_path(path_value, review_dir, project_root)


def review_gallery(title: str, items: list[dict[str, Any]], output_dir: Path, project_root: Path) -> str:
    if not items:
        return ""
    cards = []
    for item in items:
        metrics = item.get("metrics") if isinstance(item.get("metrics"), dict) else {}
        metrics_text = " · ".join(f"{html.escape(str(k))}: {float(v):.4g}" for k, v in list(metrics.items())[:4])
        cards.append(
            '<div class="qa-frame">'
            f'{review_image_tag(item.get("image"), output_dir, str(item.get("frame_id", "")), project_root)}'
            f'<div>frame {html.escape(str(item.get("frame_id", "")))}</div>'
            f'<div>{metrics_text}</div>'
            "</div>"
        )
    return f'<section class="qa-card"><h2>{html.escape(title)}</h2><div class="qa-gallery">{"".join(cards)}</div></section>'


def parse_path_map_items(items: list[str] | None) -> list[tuple[str, str]]:
    mappings: list[tuple[str, str]] = []
    for item in items or []:
        if "=" not in item:
            raise ValueError(f"Invalid --path-map {item!r}; expected OLD=NEW")
        old, new = item.split("=", 1)
        if not old:
            raise ValueError(f"Invalid --path-map {item!r}; OLD cannot be empty")
        mappings.append((old, new))
    return mappings


def path_mapping_report(mappings: list[tuple[str, str]], include_values: bool = False) -> list[dict[str, Any]]:
    report = []
    for old, new in mappings:
        item: dict[str, Any] = {
            "old_sha256": sha256(old.encode("utf-8")).hexdigest(),
            "old_length": len(old),
            "new": new,
        }
        if include_values:
            item["old"] = old
        report.append(item)
    return report


def default_export_path_mappings(project_root: Path, manifest: dict[str, Any], local_root: Path | None = None) -> list[tuple[str, str]]:
    target_root = (local_root or project_root).resolve()
    mappings: list[tuple[str, str]] = []
    remote_root = manifest.get("project_root")
    if isinstance(remote_root, str) and remote_root and remote_root != str(target_root):
        mappings.append((remote_root, str(target_root)))
    project_text = str(project_root.resolve())
    if project_text != str(target_root):
        mappings.append((project_text, str(target_root)))

    # If a copied export still contains paths under another Video2Mesh checkout,
    # map that checkout root to the local checkout root. This handles manifests
    # that refer to image-blaster, dataset, checkpoints, or MASt3R-SLAM siblings.
    for old, new in list(mappings):
        marker = "/exports/"
        if marker in old and marker in new:
            old_base = old.split(marker, 1)[0]
            new_base = new.split(marker, 1)[0]
            if old_base and old_base != new_base:
                mappings.append((old_base, new_base))
    unique: list[tuple[str, str]] = []
    seen = set()
    for old, new in mappings:
        key = (old, new)
        if key not in seen:
            unique.append(key)
            seen.add(key)
    return sorted(unique, key=lambda item: len(item[0]), reverse=True)


def infer_common_remote_root_mappings(project_root: Path, residues: list[str] | None = None) -> list[tuple[str, str]]:
    project_root = project_root.resolve()
    local_project_root = project_root
    try:
        if "exports" in project_root.parts:
            export_index = project_root.parts.index("exports")
            local_project_root = Path(*project_root.parts[:export_index])
    except Exception:
        local_project_root = project_root
    local_workspace_root = local_project_root.parent
    local_autodl_root = local_workspace_root.parent
    replacements = {
        "/root/autodl-tmp/workspace/Video2Mesh": str(local_project_root),
        "/root/autodl-tmp/workspace": str(local_workspace_root),
        "/root/autodl-tmp": str(local_autodl_root),
    }
    residues = residues or []
    mappings = []
    for old in COMMON_REMOTE_EXPORT_ROOT_MARKERS:
        if any(old.startswith(residue) or residue.startswith(old) or old in residue for residue in residues):
            mappings.append((old, replacements[old]))
    return sorted(mappings, key=lambda item: len(item[0]), reverse=True)


def localize_text_files(
    root: Path,
    mappings: list[tuple[str, str]],
    suffixes: set[str],
    skip_dirs: set[str],
    skip_files: set[Path] | None = None,
    dry_run: bool = False,
) -> dict[str, Any]:
    skip_files = {path.resolve() for path in (skip_files or set())}
    changed_files = []
    scanned_files = 0
    replacement_count = 0
    for path in sorted(root.rglob("*")):
        if not path.is_file():
            continue
        if path.resolve() in skip_files:
            continue
        rel_parts = set(path.relative_to(root).parts[:-1])
        if rel_parts.intersection(skip_dirs):
            continue
        if path.suffix.lower() not in suffixes:
            continue
        scanned_files += 1
        try:
            text = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            continue
        new_text = text
        file_replacements = 0
        for old, new in mappings:
            count = new_text.count(old)
            if count:
                new_text = new_text.replace(old, new)
                file_replacements += count
        if new_text != text:
            replacement_count += file_replacements
            changed_files.append(
                {
                    "path": str(path),
                    "relative_path": str(path.relative_to(root)),
                    "replacements": file_replacements,
                }
            )
            if not dry_run:
                path.write_text(new_text, encoding="utf-8")
    return {
        "scanned_files": scanned_files,
        "changed_file_count": len(changed_files),
        "replacement_count": replacement_count,
        "changed_files": changed_files,
    }


def find_text_occurrences(
    root: Path,
    needles: list[str],
    suffixes: set[str],
    skip_dirs: set[str],
    max_matches: int = 200,
    skip_files: set[Path] | None = None,
) -> list[dict[str, Any]]:
    skip_files = {path.resolve() for path in (skip_files or set())}
    matches: list[dict[str, Any]] = []
    for path in sorted(root.rglob("*")):
        if not path.is_file():
            continue
        if path.resolve() in skip_files:
            continue
        rel_parts = set(path.relative_to(root).parts[:-1])
        if rel_parts.intersection(skip_dirs):
            continue
        if path.suffix.lower() not in suffixes:
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="ignore")
        except Exception:
            continue
        for line_no, line in enumerate(text.splitlines(), start=1):
            if any(needle and needle in line for needle in needles):
                matches.append(
                    {
                        "path": str(path),
                        "relative_path": str(path.relative_to(root)),
                        "line": line_no,
                        "text": line[:300],
                    }
                )
                if len(matches) >= max_matches:
                    return matches
    return matches


class ReviewReferenceParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self.references: list[dict[str, str]] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        attrs_dict = {key: value for key, value in attrs if value is not None}
        if tag == "img" and attrs_dict.get("src"):
            self.references.append({"tag": tag, "attr": "src", "value": str(attrs_dict["src"])})
        elif tag in {"a", "link", "script"}:
            attr = "href" if tag in {"a", "link"} else "src"
            if attrs_dict.get(attr):
                self.references.append({"tag": tag, "attr": attr, "value": str(attrs_dict[attr])})


def check_review_html_references(review_index: Path) -> dict[str, Any]:
    if not review_index.exists():
        return {
            "review_index": str(review_index),
            "exists": False,
            "reference_count": 0,
            "missing_count": 0,
            "missing": [],
        }
    parser = ReviewReferenceParser()
    parser.feed(review_index.read_text(encoding="utf-8", errors="ignore"))
    missing = []
    for ref in parser.references:
        value = ref["value"]
        if value.startswith(("http://", "https://", "data:", "file:", "#", "mailto:")):
            continue
        parsed = urlsplit(value)
        if parsed.scheme or parsed.netloc:
            continue
        local_value = unquote(parsed.path)
        if not local_value:
            continue
        target = (review_index.parent / local_value).resolve()
        if not target.exists():
            missing.append({**ref, "resolved_path": str(target)})
    return {
        "review_index": str(review_index),
        "exists": True,
        "reference_count": len(parser.references),
        "missing_count": len(missing),
        "missing": missing,
    }


def cmd_localize_export_paths(args: argparse.Namespace) -> int:
    project_root = args.project_root.resolve()
    manifest = load_manifest(project_root)
    suffixes = {suffix if suffix.startswith(".") else f".{suffix}" for suffix in args.suffix}
    suffixes = {suffix.lower() for suffix in suffixes}
    skip_dirs = set(DEFAULT_LOCALIZE_SKIP_DIRS)
    skip_dirs.update(args.skip_dir or [])
    output_path = args.output.resolve() if args.output else project_root / manifest["simulator_assets_dir"] / "localize_export_paths_report.json"
    mappings = default_export_path_mappings(project_root, manifest, args.local_root)
    explicit_mappings = parse_path_map_items(args.path_map)
    mappings.extend(explicit_mappings)
    if args.infer_common_remote_roots:
        inferred = infer_common_remote_root_mappings(project_root, list(args.residue or []))
        existing_old = {old for old, _new in mappings}
        mappings.extend([(old, new) for old, new in inferred if old not in existing_old])
    if not mappings and not args.json:
        print("No path mappings to apply.")
    skip_files = {output_path}
    result = localize_text_files(project_root, mappings, suffixes, skip_dirs, skip_files=skip_files, dry_run=args.dry_run)

    residue_needles = [old for old, _new in mappings]
    if args.residue:
        residue_needles.extend(args.residue)
    residual_matches = find_text_occurrences(
        project_root,
        residue_needles,
        suffixes,
        skip_dirs,
        max_matches=args.max_residual_matches,
        skip_files=skip_files,
    )
    review_index = resolve_existing_path(manifest.get("artifacts", {}).get("review_index"), project_root)
    if not review_index:
        review_index = project_root / manifest.get("simulator_assets_dir", "simulator_assets") / "review" / "index.html"
    review_check = check_review_html_references(review_index)

    report = {
        "schema_version": DEFAULT_SCHEMA_VERSION,
        "project_root": str(project_root),
        "scene_id": manifest.get("scene_id"),
        "dry_run": bool(args.dry_run),
        "mappings": path_mapping_report(mappings, include_values=args.include_path_map_in_report),
        "explicit_mapping_count": len(explicit_mappings),
        "infer_common_remote_roots": bool(args.infer_common_remote_roots),
        "suffixes": sorted(suffixes),
        "skip_dirs": sorted(skip_dirs),
        "localization": result,
        "residual_count": len(residual_matches),
        "residual_matches": residual_matches,
        "review_html": review_check,
    }
    if not args.dry_run:
        write_json(output_path, report)
        manifest = load_manifest(project_root)
        manifest.setdefault("artifacts", {})["localize_export_paths_report"] = str(output_path)
        manifest["project_root"] = str((args.local_root or project_root).resolve())
        save_manifest(project_root, manifest)
    elif args.output:
        write_json(output_path, report)

    if args.json:
        print(json.dumps(report, indent=2, ensure_ascii=False))
    else:
        print(f"Localized export paths: {project_root}")
        print(f"Mappings: {len(mappings)}; changed_files={result['changed_file_count']}; replacements={result['replacement_count']}")
        print(f"Residual matches: {len(residual_matches)}")
        print(
            f"Review HTML refs: {review_check['reference_count']}; "
            f"missing={review_check['missing_count']}; index={review_check['review_index']}"
        )
        if not args.dry_run:
            print(f"Report: {output_path}")
    return 1 if (args.fail_on_residual and residual_matches) or (args.fail_on_missing_review_refs and review_check["missing_count"]) else 0


def ply_property_names(path: Path | None) -> list[str]:
    if path is None or not path.exists():
        return []
    try:
        header = parse_ply_vertex_header(path)
    except Exception:
        return []
    return [name for name, _prop_type in header.get("properties", [])]


def resolve_existing_artifact_or_default(project_root: Path, path_value: str | None, default_path: Path) -> Path:
    path = resolve_existing_path(path_value, project_root)
    if path and path.exists():
        return path
    return default_path


def summarize_ply_contract(path: Path | None, required_properties: set[str], forbidden_properties: set[str] | None = None) -> dict[str, Any]:
    forbidden_properties = forbidden_properties or set()
    summary: dict[str, Any] = {
        "path": str(path) if path else "",
        "exists": bool(path and path.exists()),
        "format": None,
        "valid_format": False,
        "vertex_count": None,
        "properties": [],
        "missing_properties": sorted(required_properties),
        "forbidden_properties_present": [],
    }
    if not path or not path.exists():
        return summary
    try:
        header = parse_ply_vertex_header(path)
        properties = [name for name, _prop_type in header.get("properties", [])]
        property_set = set(properties)
        summary.update(
            {
                "format": header.get("format"),
                "valid_format": header.get("format") in {"ascii", "binary_little_endian", "binary_big_endian"},
                "vertex_count": header.get("vertex_count"),
                "properties": properties,
                "missing_properties": sorted(required_properties - property_set),
                "forbidden_properties_present": sorted(forbidden_properties & property_set),
            }
        )
    except Exception as exc:
        summary["error"] = str(exc)
    return summary


def count_preview_images(root: Path, filename: str) -> int:
    if not root.exists():
        return 0
    return len([path for path in root.rglob(filename) if path.is_file()])


def find_review_tar(project_root: Path, scene_id: str | None, explicit_path: Path | None = None) -> Path | None:
    candidates: list[Path] = []
    if explicit_path:
        candidates.append(explicit_path if explicit_path.is_absolute() else project_root / explicit_path)
    if scene_id:
        candidates.append(project_root / f"{scene_id}_review_pack.tar.gz")
    candidates.extend(sorted(project_root.glob("*_review_pack.tar.gz")))
    for path in candidates:
        if path.exists():
            return path
    return candidates[0] if candidates else None


def report_status_summary(data: Any) -> tuple[str, Any]:
    if not isinstance(data, dict):
        return "missing", None
    status = data.get("status")
    if not status and isinstance(data.get("summary"), dict):
        status = data["summary"].get("headline")
    if not status and "ok" in data:
        status = "ok" if data.get("ok") else "not_ok"
    return str(status or "available"), data.get("summary")


def report_summary_item(name: str, path: Path, data: Any) -> dict[str, Any]:
    status, summary = report_status_summary(data)
    return {
        "name": name,
        "path": str(path),
        "exists": bool(path.exists()),
        "readable": isinstance(data, dict),
        "status": status,
        "ok": data.get("ok") if isinstance(data, dict) else None,
        "summary": summary,
    }


def object_merge_suggestions_summary_from_report(path: Path | None) -> dict[str, Any]:
    data = safe_read_json(path)
    summary: dict[str, Any] = {
        "path": str(path) if path else "",
        "exists": bool(path and path.exists()),
        "readable": isinstance(data, dict),
        "status": data.get("status") if isinstance(data, dict) else None,
        "foreground_object_count": 0,
        "suggestion_count": 0,
        "component_count": 0,
        "review_component_count": 0,
        "executable_component_count": 0,
        "executable_pair_command_count": 0,
        "review_only_source_count": 0,
        "parameters": {},
    }
    if not isinstance(data, dict):
        return summary

    components = data.get("components") if isinstance(data.get("components"), list) else []
    review_components = data.get("review_components") if isinstance(data.get("review_components"), list) else []
    suggestions = data.get("suggestions") if isinstance(data.get("suggestions"), list) else []
    review_sources: set[str] = set()
    for item in review_components:
        if isinstance(item, dict):
            review_sources.update(str(source) for source in item.get("sources") or [] if source)
    summary.update(
        {
            "status": data.get("status"),
            "foreground_object_count": int(data.get("foreground_object_count") or 0),
            "suggestion_count": int(data.get("suggestion_count") or len(suggestions)),
            "component_count": int(data.get("component_count") or len(components)),
            "review_component_count": int(data.get("review_component_count") or len(review_components)),
            "executable_component_count": len([item for item in components if isinstance(item, dict) and item.get("merge_command")]),
            "executable_pair_command_count": len([item for item in suggestions if isinstance(item, dict) and item.get("merge_command")]),
            "review_only_source_count": len(review_sources),
            "parameters": data.get("parameters") if isinstance(data.get("parameters"), dict) else {},
        }
    )
    return summary


def artifact_summary_item(
    name: str,
    path: Path | None,
    artifact_type: str,
    audience_use: str,
    priority: str,
    detail: str = "",
) -> dict[str, Any]:
    return {
        "name": name,
        "type": artifact_type,
        "path": str(path) if path else "",
        "exists": bool(path and path.exists()),
        "priority": priority,
        "audience_use": audience_use,
        "detail": detail,
    }


def path_from_artifact_or_default(project_root: Path, artifacts: dict[str, Any], key: str, default_path: Path | None = None) -> Path | None:
    path = resolve_existing_path(artifacts.get(key), project_root)
    if path and path.exists():
        return path
    return default_path


def summarize_demo_ply(project_root: Path, artifacts: dict[str, Any], key: str, required: set[str], forbidden: set[str]) -> dict[str, Any]:
    path = resolve_existing_path(artifacts.get(key), project_root)
    summary = summarize_ply_contract(path, required, forbidden)
    return {
        "artifact_key": key,
        "path": summary.get("path"),
        "exists": summary.get("exists"),
        "valid_format": summary.get("valid_format"),
        "vertex_count": summary.get("vertex_count"),
        "missing_properties": summary.get("missing_properties"),
        "forbidden_properties_present": summary.get("forbidden_properties_present"),
    }


def compact_gate(gate: Any) -> dict[str, Any] | None:
    if not isinstance(gate, dict):
        return None
    evidence = gate.get("evidence") if isinstance(gate.get("evidence"), dict) else {}
    compact_evidence = {}
    for key in [
        "provider",
        "stage_status",
        "path",
        "gaussian_count",
        "mask_count",
        "semantic_id_count",
        "foreground_objects",
        "meshes",
        "external_meshes",
        "background_structures",
        "instance_count",
        "qa_ok",
        "required_issue_count",
    ]:
        if key in evidence:
            compact_evidence[key] = evidence.get(key)
    return {
        "name": gate.get("name"),
        "status": gate.get("status"),
        "detail": gate.get("detail"),
        "next_step": gate.get("next_step"),
        "evidence": compact_evidence,
    }


def md_cell(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, bool):
        text = "yes" if value else "no"
    elif isinstance(value, (dict, list)):
        text = json.dumps(value, ensure_ascii=False)
    else:
        text = str(value)
    return text.replace("\n", " ").replace("|", "\\|")


def markdown_table(headers: list[str], rows: list[list[Any]]) -> str:
    lines = [
        "| " + " | ".join(md_cell(header) for header in headers) + " |",
        "| " + " | ".join("---" for _header in headers) + " |",
    ]
    for row in rows:
        lines.append("| " + " | ".join(md_cell(value) for value in row) + " |")
    return "\n".join(lines)


def write_advisor_demo_summary_markdown(report: dict[str, Any], output_path: Path) -> None:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    counts = report.get("counts") if isinstance(report.get("counts"), dict) else {}
    lines = [
        f"# Video2Mesh Advisor Demo Summary: {report.get('scene_id') or 'scene'}",
        "",
        "## Overall",
        "",
        markdown_table(
            ["Field", "Value"],
            [
                ["headline", summary.get("headline")],
                ["demo_ready", summary.get("demo_ready")],
                ["production_ready", summary.get("production_ready")],
                ["showable_artifacts", summary.get("showable_artifact_count")],
                ["missing_showcase_artifacts", summary.get("missing_showcase_artifact_count")],
                ["foreground_objects", counts.get("foreground_objects")],
                ["background_structures", counts.get("background_structures")],
                ["object_meshes", counts.get("object_meshes")],
                ["object_mask_clouds", counts.get("object_mask_clouds")],
                ["semantic_ids", counts.get("semantic_ids")],
            ],
        ),
        "",
        "## Showable Artifacts",
        "",
        markdown_table(
            ["Priority", "Artifact", "Type", "Exists", "Use", "Path", "Detail"],
            [
                [
                    item.get("priority"),
                    item.get("name"),
                    item.get("type"),
                    item.get("exists"),
                    item.get("audience_use"),
                    item.get("path"),
                    item.get("detail"),
                ]
                for item in report.get("showable_artifacts", [])
            ],
        ),
        "",
        "## Quality Reports",
        "",
        markdown_table(
            ["Report", "Exists", "Status", "OK", "Path"],
            [
                [item.get("name"), item.get("exists"), item.get("status"), item.get("ok"), item.get("path")]
                for item in report.get("quality_reports", [])
            ],
        ),
        "",
        "## Production Gates",
        "",
        markdown_table(
            ["Gate", "Status", "Detail", "Next Step"],
            [
                [item.get("name"), item.get("status"), item.get("detail"), item.get("next_step")]
                for item in report.get("production_gates", [])
            ],
        ),
        "",
        "## Recommended Demo Narrative",
        "",
    ]
    for item in report.get("recommended_demo_narrative", []):
        lines.append(f"- {md_cell(item)}")
    lines.extend(["", "## Remaining Gaps", ""])
    gaps = report.get("production_gaps", [])
    if gaps:
        for item in gaps:
            lines.append(f"- `{md_cell(item.get('name'))}`: {md_cell(item.get('status'))} - {md_cell(item.get('detail'))}")
    else:
        lines.append("- No baseline or blocking production gaps reported.")
    lines.extend(
        [
            "",
            "## SVLGaussian Interface Note",
            "",
            "SVLGaussian-style support in this project means pixel/object probabilities can be back-projected onto Gaussian vertices with ray-to-Gaussian association. It is a probability transfer interface, not a replacement for high-quality 3DGS training or production video segmentation.",
            "",
        ]
    )
    ensure_dir(output_path.parent)
    output_path.write_text("\n".join(lines), encoding="utf-8")


